UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/505/mod_label/intro/7_Employee%20Ethics.mp4">https://goalvow.com/upskilling/pluginfile.php/505/mod_label/intro/7_Employee%20Ethics.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-employee-ethics-lesson-7-appropriate-use-of-company-assets';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Every case is different.</strong>&nbsp;There isn’t one set way to solve an ethical dilemma. Use your judgment and consider your values to determine the best choice in a given situation.</li></ul><p></p><ul><li><strong>Embrace challenges.</strong>&nbsp;We avoid ethical decision-making because it’s hard. Try conditioning your brain to welcome challenges by seeing them as opportunities to grow, just as you’d condition your muscles to lift heavier weights at the gym. The more we practice overcoming difficulties, the easier it gets.</li></ul><p></p><ul><li><strong>Don\'t feed the fire.&nbsp;</strong>Negative gossip is like a fire—the more fuel you add, the bigger it gets. Instead of fuel, gossip survives on attention. Withdraw that, and negative gossip will fizzle out.</li></ul><p></p><ul><li><strong>When in doubt, cite your source.&nbsp;</strong>Protect yourself from the consequences of plagiarism by giving credit if you\'re unsure. It’s better to be safe than sorry.</li></ul><p></p><ul><li><strong>When in doubt, dig deeper.&nbsp;</strong>It’s easy to fall into motivated ignorance. All it takes is doing nothing. Instead, find out what’s really going on and tackle the problem directly.</li></ul><p></p><ul><li><strong>Follow company protocols.&nbsp;</strong>Most companies have a code of conduct as well as an issue escalation policy. Check and follow these company protocols.</li></ul><p></p><p></p><ul><li><strong>If in doubt—ask.&nbsp;</strong>Are you unsure whether you can use the company photocopier for a personal document? Or, do you have questions about what items you can and can’t expense on a work trip? If in doubt, ask your manager or human resources department.</li></ul><p></p><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-3-employee-ethics-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong><br></p><ul><li><strong>Understand </strong>business ethics</li><li><strong>Know-what </strong>is workplace integrity</li><li><strong>Know-how </strong>to maintain your integrity at work</li><li><strong>Know-how </strong>to be an ethical employee</li><li><strong>Avoid </strong>unethical behavior in the workplace</li></ul><br><p></p></div>' WHERE slug = 'module-1-business-ethics-fundamentals-learning-outcome';
