UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/509/mod_label/intro/4_Business%20Ethics%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/509/mod_label/intro/4_Business%20Ethics%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-business-ethics-fundamentals-lesson-4-how-to-be-an-ethical-employee';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/510/mod_label/intro/5_Business%20Ethics%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/510/mod_label/intro/5_Business%20Ethics%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-business-ethics-fundamentals-lesson-5-ethical-warning-signs-in-the-workplace';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Are you making excuses?</strong>&nbsp;If you’re struggling to determine whether or not something is ethical, ask yourself:&nbsp;<em>“Am I making excuses?”</em>&nbsp;and&nbsp;<em>“Am I trying to justify this?”</em>&nbsp;Excuses are a red flag that your conscience doesn’t agree with your behavior. Listen to that inner voice—it reveals a lot about what’s right and wrong.&nbsp;</li></ul><p></p><ul><li><strong>Integrity requires consistency.&nbsp;</strong>If there’s one thing to take away from this lesson, remember: Integrity requires consistency. You cannot be a person of integrity if you waver on your values. You must do the right thing even when it’s hard and inconvenient. You must continue to make the right choices over and over again.</li></ul><p></p><ul><li><strong>Focus on the future.</strong>&nbsp;While it’s important to reflect on past patterns, don’t get stuck in a loop of regret. If you’ve done things you’re not proud of, recognize those tendencies, and then move forward. Evaluate each new decision and—before stepping forward—ask yourself,&nbsp;<em>“Is this the next right move?”</em></li></ul><p></p><ul><li><span><strong style="font-style: italic;">When in doubt—ask for help.&nbsp;</strong>I</span>f you’re ever unsure whether a work behavior is ethical or not, then ask for help. Approach your manager, mentor, or even an HR professional for advice. Don’t be afraid to talk openly about ethical dilemmas and seek clarification as needed.</li></ul><p></p><p></p><ul><li><span>Just like it’s a red flag when you hide your activities from others, it’s also a red flag when others hide their activities from you. Take notice if team members or employees are acting secretive or hiding situations or information from you.</span></li></ul><p></p><p><em><br></em></p><p><em><br></em></p><p></p><p></p><p></p></div>' WHERE slug = 'module-1-business-ethics-fundamentals-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Understand </strong>ethical leadership and why its important in the workplace</li><li><span>Have the </span><strong>capability </strong>to create an employee code of conduct</li><li><strong>Know-how </strong>to develop ethical employees</li><li><strong>Make </strong>ethics part of your company culture</li><li><strong>Evaluate </strong>employees performance fairly</li><li><strong>Make </strong>ethical decisions as a leader</li></ul><p></p></div>' WHERE slug = 'module-2-leadership-on-ethics-learning-outcome';
