UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/517/mod_label/intro/7_Leadership%20on%20Ethics.mp4">https://goalvow.com/upskilling/pluginfile.php/517/mod_label/intro/7_Leadership%20on%20Ethics.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-leadership-on-ethics-lesson-7-managing-conflicts-of-interest-in-the-workplace';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Reflect on your personal role models.&nbsp;</strong>Who do you look up to? What traits or aspects do you admire about them? Consider cultivating and incorporating those qualities in your personal practices and values.</li></ul><p></p><ul><li><strong>Review and update your code of conduct regularly.&nbsp;</strong>Establish a regular cadence for reviewing and updating your employee code of conduct. That way, it will always stay relevant.</li></ul><p></p><p></p><ul><li><strong>Have the right expectations.&nbsp;</strong>It’s not possible to predict every challenge your employees will face, so don’t get caught up trying to anticipate every potential issue. Instead, focus on informing, educating, and motivating your team to be mindful of the choices they’re making.</li></ul><p></p><ul><li><strong>Details matter.&nbsp;</strong>Ethical behavior doesn’t have to involve grand gestures. Helping out a customer or voicing concern about a policy that seems contrary to a company’s values are small-scale ways to “do the right thing.” We can all integrate ethics into our daily life by taking these kinds of actions.&nbsp; &nbsp;</li><li><strong>Be direct but professional.&nbsp;</strong>Adopt a calm and neutral tone when delivering performance evaluations. Raising your voice or using disrespectful language is not only unsettling for the employee but also ineffective in motivating them to improve. An employee who feels personally attacked is not likely to perform well—and would be justified in reporting a manager’s poor behavior.</li></ul><p></p><ul><li><strong>What’s your code of ethics?</strong>&nbsp;To speed up the decision-making process, spend some time considering your personal beliefs. What are your values? And do you have a mantra you live by? Create a personal code of ethics and use it as a guide when making future ethical decisions.</li></ul><p><ul><li><strong>Remember that conflicts of interest are complicated.</strong>&nbsp;No two cases look the same, so the response will depend on the organization, the employee, and the conflict itself. Be sure to continually update and enforce your guidelines, even when it may seem easier to ignore potential conflicts.</li></ul></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-2-leadership-on-ethics-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong><br></p><ul><li><strong>Understand </strong>OSH Act for construction hazard</li><li><strong>Implement</strong>&nbsp;ergonomics, safe lifting, pushing and pulling safety measures</li><li><strong>Reduce&nbsp;</strong>slips, trips and falls</li><li><strong>Know-how </strong>to implement ergonomics measures at the office and at home</li><li><strong>Understand&nbsp;</strong>&nbsp;eye safety fundamentals in the workplace</li><li><strong>Understand </strong>ladder safety fundamentals</li></ul><br><p></p></div>' WHERE slug = 'module-1-workplace-health-amp-safety-learning-outcome';
