UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/523/mod_label/intro/6_Workplace%20Health%20and%20Safety.mp4">https://goalvow.com/upskilling/pluginfile.php/523/mod_label/intro/6_Workplace%20Health%20and%20Safety.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-workplace-health-amp-safety-lesson-6-ladder-safety-fundamentals';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Don’t cut corners.&nbsp;</strong>It’s easy to let safety slide. But cutting corners isn’t worth potentially fatal consequences. The next time you’re at a site tempted to “Just get the job done,” force yourself to pause. Slow down, assess the situation, and consider what you must do to stay safe. Your future self will thank you.</li></ul><p></p><ul><li><strong>Ask the experts.&nbsp;</strong>The front-line team knows better than anyone where risks lie. Get their input for improving workplace safety. Their knowledge and creative solutions make it a win-win for everyone.</li></ul><p></p><p></p><ul><li><strong>Report hazards to your manager.&nbsp;</strong>If you can’t remove a hazard yourself, report it promptly to your manager or human resources.</li></ul><p></p><ul><li><strong>Consult the pros.</strong>&nbsp;Always follow the manufacturer’s directions for storage, cleaning, and care of your personal protective eyewear. Visit&nbsp;<a href="https://www.osha.gov/" rel="noopener noreferrer" target="_blank">OSHA.gov</a>&nbsp;and&nbsp;<a href="https://www.ansi.org/" rel="noopener noreferrer" target="_blank">ANSI.org</a>&nbsp;to ensure you are following the correct safety protocols. &nbsp;</li></ul><p><ul><li><strong>Practice basic ladder maintenance.&nbsp;</strong>Help keep ladders in good condition with proper cleaning, care, and storage.</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-1-workplace-health-amp-safety-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong><br></p><ul><li><strong>Understand </strong>workplace violence and its impact</li><li><strong>Know-how</strong> to identify and report early warning sings of workplace violence</li><li><strong>Recognize </strong>and neutralize workplace bullying</li><li><strong>Understand </strong>levels of workplace bullying and how to respond to them</li><li><strong>Know-how </strong>to respond to active shooter threat</li><li><span>Have the </span><strong>capability </strong>to respond to a first aid for life-threatening bleeding</li></ul><br><br><p></p></div>' WHERE slug = 'module-2-workplace-violence-learning-outcome';
