UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><b>Summary</b></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Stay vigilant.</strong>&nbsp;Be aware of your surroundings at all times. Speak to a supervisor or HR rep immediately if you believe there is a threat to anyone’s safety.&nbsp;</li></ul><p></p><ul><li><strong><em>Disclaimer:</em>&nbsp;</strong>This lesson was designed to overview potential risk factors for violence. It should not be used as a diagnostic tool.</li></ul><p></p><ul><li><strong>Workplace bullying happens in remote offices too.</strong>&nbsp;The privacy of instant messages and emails makes it easy for people to bully others online. The effects are devastating, even if those involved work remotely. Be aware of cyberbullying—it’s just as harmful as bullying in an in-person workspace.</li></ul><p></p><p></p><ul><li><strong>Refer to an EAP.&nbsp;</strong>An employee assistance program (EAP) can support employees dealing with aggressive tendencies and those affected by it. Mental health assistance provides meaningful intervention and skill-building to improve the likelihood of positive outcomes.</li></ul><p></p><p></p><ul><li><strong>Take care of yourself.&nbsp;</strong>Simply going through a training like this can sometimes bring up feelings of anxiety and trauma, particularly if you or someone you know has experienced violence. Many companies have short- and long-term support through an employee assistance program (EAP) to help you work through complicated or difficult emotions.</li></ul><p></p><p><ul><li><strong>“Good Samaritan” laws offer some protection.&nbsp;</strong>These codes exist to protect bystanders who intervene in emergencies. They vary by country and state. It’s wise to understand your area’s laws about personal responsibility and liability just in case.</li></ul></p><p></p><p></p></div>' WHERE slug = 'module-2-workplace-violence-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong><br></p><ul><li><strong>Know-how</strong> to have inclusive conversations</li><li>&nbsp;<strong>Know-how</strong>&nbsp;to handle offensive comments at work</li><li>have the <strong>capability</strong>&nbsp;to recover when your impact does not match your intent</li><li><strong>Understand </strong>and amplify employee voice</li><li><strong>Know-when </strong>and how to apologize at work</li><li><strong>Create </strong>and use shared agreements</li><li><strong>Replace </strong>harmful phrases with inclusive language</li><li><strong>Use </strong>gender inclusive language</li><li><strong>Use </strong>inclusive language around orientation</li><li><strong>Use </strong>racially and ethnically inclusive language</li><li><strong>Use </strong>disability inclusive language</li><li><strong>Challenge </strong>assumptions for better workplace relationship</li><li><strong>Enable </strong>a quick guide to accessible writing</li></ul><br><br><p></p></div>' WHERE slug = 'module-2-inclusive-communication-learning-outcome';
