UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2987/mod_label/intro/6_Culture%20Competence.mp4">https://goalvow.com/upskilling/pluginfile.php/2987/mod_label/intro/6_Culture%20Competence.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-culture-competence-lesson-6-accommodating-religion-spirituality-and-beliefs-in-the-workplace';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2988/mod_label/intro/7_Culture%20Competence.mp4">https://goalvow.com/upskilling/pluginfile.php/2988/mod_label/intro/7_Culture%20Competence.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-culture-competence-lesson-7-politics-at-work-guidelines-for-discussing-hot-bottom-issues';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Cultural competence is a moral and ethical obligation.</strong>&nbsp;Research shows that diversity and multiculturalism are good for business, but organizations must think beyond the bottom line to create a workplace that celebrates all individuals and provides a safe and supportive place where all employees can flourish, personally and professionally.&nbsp;</li></ul><p></p><ul><li><strong>Focus on similarities.</strong>&nbsp;It’s easy to get overwhelmed by cultural differences and everything that could go wrong. But by emphasizing shared values, traditions, and insights, you’ll bridge the gap rather than widen it. Doing so will broaden your organization’s global appeal.&nbsp;</li></ul><p></p><ul><li><strong>Note: Recognize power and privilege.&nbsp;</strong>Class, race, nationality, language, gender identity, sexual orientation, and even marital status can all play a role in your relative privilege and power in a given situation. A culturally sensitive person is aware of that dynamic.</li></ul><p></p><ul><li><strong><em>Note:&nbsp;</em></strong>In a business setting, the best way to avoid committing cultural appropriation is by ensuring all voices are represented through diverse hiring practices and consulting with relevant advocacy groups before borrowing from other cultures.</li></ul><p></p><ul><li><strong>&nbsp;Listen first.&nbsp;</strong>We’re used to defining our spiritual practices by what’s different. By engaging with others’ beliefs with curiosity and careful listening, we’re more likely to find what we have in common.</li></ul><p><ul><li><strong>Avoid political television programming.&nbsp;</strong>Many 24-hour news stations feature pundits with clear agendas, sometimes including vitriolic and exaggerated statements about opposing viewpoints. Steer clear of broadcasting these stations in the office. Not only can it make people uncomfortable, but it also invites caustic discourse into the work environment.</li></ul></p><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-3-culture-competence-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong><br></p><ul><li><strong>Know-how </strong>to foster psychological safety in the workplace</li><li><span>Have the </span><strong>capability</strong>&nbsp;to create an inclusive remote environment</li><li><strong>Understand </strong>the gender spectrum</li><li><strong>Fight </strong>gender bias at work</li></ul><br><p></p></div>' WHERE slug = 'module-1-inclusion-and-respect-learning-outcome';
