UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2976/mod_label/intro/4_Inclusion%20and%20Respect.mp4">https://goalvow.com/upskilling/pluginfile.php/2976/mod_label/intro/4_Inclusion%20and%20Respect.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-inclusion-and-respect-lesson-4-fighting-gender-bias-at-work';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Actions speak louder than words.</strong>&nbsp;Psychological safety in the workplace starts with individuals, then teams, and spreads throughout the organization. Checking in on colleagues, sharing your personal stories, and asking for and offering help are a few ways to build trust and practice what you preach.</li></ul><p></p><ul><li><strong>Inclusion depends on both systemic and individual efforts.&nbsp;</strong>It’s a manager’s job to ensure employees have the support they need to be consciously inclusive at work.</li></ul><ul><li><strong>Note: You don’t have to understand everything to be respectful.</strong>&nbsp;Fully understanding the gender spectrum can be difficult, especially for those who need to unlearn old norms before accepting new ones. But regardless of any individual’s knowledge level, they should strive to see, hear, and respect others.</li></ul><ul><li><strong>Speak up.</strong>&nbsp;If you notice instances of gender bias at work, voice your concerns. Go to your manager or human resources representative to begin a dialogue. Biases take root because of complacency and inaction. Raising awareness is the first step toward meaningful change.&nbsp;&nbsp;</li></ul><p></p><p></p><p></p></div>' WHERE slug = 'module-1-inclusion-and-respect-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>the fundamental causes of stress</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to manage your body reaction to stress</li><li><strong>Know-how&nbsp;</strong>to identify and manage your stress triggers</li><li><strong>Differentiate </strong>between good stress and bad stress</li></ul><br><br><p></p></div>' WHERE slug = 'module-1-stress-fundamentals-learning-outcome';
