UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/1004/mod_label/intro/2_Stress%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/1004/mod_label/intro/2_Stress%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-stress-fundamentals-lesson-2-understanding-your-body-reaction-to-stress';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/1005/mod_label/intro/3_Stress%20Fundamentals.mp4?time=1710075210289">https://goalvow.com/upskilling/pluginfile.php/1005/mod_label/intro/3_Stress%20Fundamentals.mp4?time=1710075210289</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-stress-fundamentals-lesson-3-identifying-and-managing-your-stress-triggers';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/1006/mod_label/intro/4_Stress%20Fundamentals.mp4?time=1710075255011">https://goalvow.com/upskilling/pluginfile.php/1006/mod_label/intro/4_Stress%20Fundamentals.mp4?time=1710075255011</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-stress-fundamentals-lesson-4-good-stress-vs-bad-stress';
UPDATE lessons SET content = '<div class="no-overflow"><span><strong>Summary</strong><br><strong><br></strong><ul><li><strong>Tame your stress with laughter.</strong> When stress gets the better of us, it can be hard to let loose and laugh. But there’s a reason why people say, “Laughter is the best medicine.” Laughter can reduce your stress hormones, soothe tension, improve your immune system, and relieve pain. Even a single hearty laugh can leave your muscles relaxed for up to 45 minutes afterward. To create more moments for laughter, watch a funny movie, read and share a joke, play a board game, and surround yourself with fun-loving people.</li></ul><ul><li><strong>Don’t avoid stress completely.</strong> While it’s important to keep your stress level low, in some cases, stress can be helpful. In manageable doses, it can motivate us to perform better and achieve success. For example, moderate stress strengthens the connections between your brain neurons, helping you work faster under pressure. So, as long as stress isn’t chronic, it can be a positive force in your life.</li></ul><p></p><ul><li><strong>Keep a daily list. This lesson is only the beginning.</strong> You’ll likely experience several other triggers throughout your life. So, rather than ignoring them, write them down. Get in the habit of recording those moments—and asking yourself, “Why?” and, “What’s causing this?” Ultimately, the more you know about your triggers, the easier it will be to manage them.&nbsp;</li></ul><p></p><ul><li><strong>Remind yourself that a little bit of stress is a good thing.</strong> Eustress is still a form of stress. You may not feel 100% comfortable or confident, and it’s not always going to be easy. That’s okay. Remind yourself that a healthy level of stress means that you’re invested, and you’re challenging yourself. Eustress is an opportunity for growth, development, and discovery.</li></ul><p></p></span></div>' WHERE slug = 'module-1-stress-fundamentals-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>the relationship between pressure and performance</li><li><strong>Know-how </strong>to manage your stress and increase mental focus</li><li><strong>Know-how&nbsp;</strong>to perform well under pressure</li><li><strong>Know-how </strong>to recover from burnout</li></ul><br><br><p></p></div>' WHERE slug = 'module-2-stress-and-work-performance-learning-outcome';
