UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/1009/mod_label/intro/3_Stress%20and%20Work%20Performance.mp4?time=1710075464734">https://goalvow.com/upskilling/pluginfile.php/1009/mod_label/intro/3_Stress%20and%20Work%20Performance.mp4?time=1710075464734</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-stress-and-work-performance-lesson-3-how-to-perform-well-under-pressure';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/1010/mod_label/intro/4_Stress%20and%20Work%20Performance.mp4?time=1710075512912">https://goalvow.com/upskilling/pluginfile.php/1010/mod_label/intro/4_Stress%20and%20Work%20Performance.mp4?time=1710075512912</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-stress-and-work-performance-lesson-4-what-is-burnout';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/1011/mod_label/intro/5_Stress%20and%20Work%20Performance.mp4?time=1710075550752">https://goalvow.com/upskilling/pluginfile.php/1011/mod_label/intro/5_Stress%20and%20Work%20Performance.mp4?time=1710075550752</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-stress-and-work-performance-lesson-5-recovering-from-burnout';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Strive for excellence, not perfection.</strong>&nbsp;If perfection is often your goal, you’re putting unnecessary pressure on yourself. Perfection is more about the result, while excellence has to do with the process. When we strive for excellence, we aim to do our best—but understand that mistakes are part of the growth process. So, the next time you find yourself triple-checking your work or getting hung up on minor errors,&nbsp;<em>breathe</em>&nbsp;and let it go. You might not see an immediate shift in your approach and attitude, but you’ll eventually feel less pressure if you keep at it.</li></ul><p></p><ul><li><strong>Caution: Not all stress is bad.</strong>&nbsp;The stress that comes from challenging yourself or learning something new is actually beneficial. It can energize you and help you grow beyond your current capabilities. If you avoid all stress, you may find yourself feeling bored, disengaged, and stagnant. Strive for a balance in which you push yourself—but don’t overextend your emotional and physical resources.</li></ul><p></p><ul><li><strong>Pressure is a mental game.</strong>&nbsp;Regardless of the stakes, it’s your interpretation that determines how you respond to pressure. In that way, pressure is a choice. If you can change your mindset, you can release the pressure. So, the next time you feel your heart pounding, check in with your thoughts, and remind yourself that this is a mental game—and&nbsp;<em>you</em>&nbsp;are in control.</li></ul><p></p><ul><li><strong>Watch out for the signs.&nbsp;</strong>Burnout creeps up slowly. And if you’re not careful, day-to-day stress can morph into long-term burnout. So, watch out for the signs and learn to recognize the symptoms early so that you can change directions before the condition escalates.</li></ul><p></p><ul><li><strong>Rest is a necessity—not a luxury.&nbsp;</strong>&nbsp;There’s a lot of social pressure to always be&nbsp;<em>“on.”</em>&nbsp;We admire&nbsp;<em>“grind culture”</em>&nbsp;and often equate busyness with success. But everyone needs rest—even you. If you’re&nbsp;<em>always</em>&nbsp;working, you won’t be as successful as the person who takes breaks. So, don’t see rest as a weakness. Instead, recognize it as a necessary task on the to-do list.&nbsp;</li></ul><p></p><p><br></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-2-stress-and-work-performance-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Implement </strong>strategies for coping with stress</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to guide others to meditation for stress management</li><li><strong>Know-how&nbsp;</strong>to exercise for stress relief</li><li><strong>Know-how&nbsp;</strong>to reduce stress by changing your thinking</li><li><strong>Journal</strong>&nbsp;for stress relief</li><li><strong>Implement </strong>relaxation techniques for stress relief</li><li><strong>Cultivate </strong>an internal locus of control</li><li><strong>Implement </strong>sensory based strategies for reducing stress quickly</li></ul><br><br><p></p></div>' WHERE slug = 'module-3-strategies-to-relieve-stress-learning-outcome';
