UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2992/mod_label/intro/4_Online%20Security%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2992/mod_label/intro/4_Online%20Security%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-online-security-fundamentals-lesson-4-safe-use-of-social-media';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2993/mod_label/intro/5_Online%20Security%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2993/mod_label/intro/5_Online%20Security%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-online-security-fundamentals-lesson-5-dealing-with-a-security-incident';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Small steps can make a world of difference.&nbsp;</strong>It may seem daunting to address hacking and security breaches, but these small steps can often save you from big trouble down the road. In most cases, thieves will target a house with a single, easy-to-break lock rather than a home with multiple levels of security.</li></ul><p></p><ul><li><strong>Convenience vs. consequence.&nbsp;</strong>Our propensity for comfort can often lead to unforeseen consequences. When surfing the internet, take a moment to question whether a convenient function is really worth the potential security risk.</li></ul><p></p><ul><li><strong>Keep your guard up.&nbsp;</strong>A thoughtful pause to evaluate your surroundings before connecting to a public network can help you avoid getting hacked. Use common sense when you’re working away from home or the office. If something feels unsafe, trust your gut.</li></ul><p></p><ul><li><strong>Watch your webcam.&nbsp;</strong>Many social platforms enable users to share live or pre-recorded videos—or they allow you to video chat with friends. Be careful when using these functions. Hackers can hijack webcams and turn them on remotely to spy on you. There’s also a risk of user error if you forget to turn your video off after using it—or you accidentally press “record.”</li></ul><p></p><p><ul><li><strong>Staying alert is your greatest protection from security incidents.&nbsp;</strong>Carefully examine email addresses, web URLs, and invitations before clicking them. If something looks off, check with the sender to verify it’s legitimate.&nbsp;</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-1-online-security-fundamentals-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:<br></strong><br></p><ul><li><strong>Understand </strong>the importance of confidentiality in the workplace</li><li>Have the <strong>capability </strong>to create and manage strong passwords</li><li><strong>Implement </strong>multifactor authentication</li><li><strong>Know-how </strong>to use physical security to keep facilities and assets safe</li><li><strong>Protect </strong>portable devices and removable media data</li></ul><br><br><p></p></div>' WHERE slug = 'module-2-how-to-protect-your-data-learning-outcome';
