UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2998/mod_label/intro/5_How%20to%20Protect%20your%20Data.mp4">https://goalvow.com/upskilling/pluginfile.php/2998/mod_label/intro/5_How%20to%20Protect%20your%20Data.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-how-to-protect-your-data-lesson-5-portable-devices-and-removable-media-security';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>When in doubt, default to confidentiality.&nbsp;</strong>Not sure if something’s supposed to be a secret? Err on the side of caution, and assume it is. That way, you can avoid accidentally disclosing something that shouldn’t be public.</li></ul><p></p><ul><li><strong><em>Tip:&nbsp;</em></strong>You may have heard people say that writing down your passwords is a bad idea, but some security experts say this process can be safer than using a password manager. There are a few caveats. Don’t write down your passwords at work; just at home. And always keep passwords you’ve written down in a secure location that only you know about.</li></ul><p></p><ul><li><strong>A note on two-factor authentication.&nbsp;</strong>You may have heard of&nbsp;<strong>two-factor authentication</strong>, also known as 2FA, which is a&nbsp;<em>subset</em>&nbsp;of multifactor authentication. A website with 2FA has limited verification to two identifying factors, whereas a multifactor approach can encompass more variables. Remember, when it comes to authentication, more means safer.</li></ul><p></p><ul><li><strong><em>Tip:</em>&nbsp;</strong>All employees should be prepared to respond to both intentional and unintentional threats. From evacuation routes to how to protect company-issued equipment, physical security efforts depend on training and education. If you’re unsure of your company’s protocols, contact the IT team and request information so you’re ready for anything.</li></ul><p><ul><li><strong><em>Tip</em>:&nbsp;</strong>Many portable devices are GPS-enabled and come with “find my device” technology. Using this feature can help you pinpoint the location of a rogue phone or tablet. However, if you suspect the device was stolen, don’t try to track down and confront the thief. Instead, call local law enforcement and ask for their assistance in recovering your property.</li></ul></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-2-how-to-protect-your-data-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:<br></strong><br></p><ul><li><strong>Understand </strong>social engineering</li><li><strong>Avoid </strong>phishing by implementing best practices to internet surfing</li><li><strong>Prevent </strong>phone scams and phishing attacks</li><li><strong>Protect </strong>your data against malware</li></ul><br><br><p></p></div>' WHERE slug = 'module-3-social-engineering-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2153/mod_resource/content/2/Social%20Engineering%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Social Engineering Course Material.pdf</a></p>' WHERE slug = 'module-3-social-engineering-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2999/mod_label/intro/1_Social%20Engineering.mp4">https://goalvow.com/upskilling/pluginfile.php/2999/mod_label/intro/1_Social%20Engineering.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-social-engineering-lesson-1-what-is-social-engineering';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/3000/mod_label/intro/2_Social%20Engineering.mp4">https://goalvow.com/upskilling/pluginfile.php/3000/mod_label/intro/2_Social%20Engineering.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-social-engineering-lesson-2-phishing-101';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/3001/mod_label/intro/3_Social%20Engineering.mp4">https://goalvow.com/upskilling/pluginfile.php/3001/mod_label/intro/3_Social%20Engineering.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-social-engineering-lesson-3-safeguarding-against-business-email-compromise';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/3002/mod_label/intro/4_Social%20Engineering.mp4">https://goalvow.com/upskilling/pluginfile.php/3002/mod_label/intro/4_Social%20Engineering.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-social-engineering-lesson-4-preventing-phone-scams-and-vishing-attacks';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/3003/mod_label/intro/5_Social%20Engineering.mp4">https://goalvow.com/upskilling/pluginfile.php/3003/mod_label/intro/5_Social%20Engineering.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-social-engineering-lesson-5-protecting-against-malware';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>A healthy dose of distrust can be a good thing.</strong>&nbsp;Do you ever feel obligated to be friendly to strangers? Many of us readily give away details about our lives to people we don’t know. Unfortunately, this can make us vulnerable to social engineering and other scams. While being friendly is fine, know where to draw the line. Ask yourself the questions we covered in this lesson, and don’t be afraid to say&nbsp;<em>no</em>&nbsp;or withdraw from a situation if you feel uncomfortable.</li></ul><p></p><ul><li><strong>Phishing isn’t isolated to email.&nbsp;</strong>Scammers use schemes via telephone calls (referred to as vishing, a combination of voice and phishing) and through text messages (referred to as smishing, a combination of SMS and phishing) to perpetrate attacks. No matter the medium, always be wary of unsolicited communications that feature phishing red flags.</li></ul><p></p><ul><li><strong>Report BEC attacks.&nbsp;</strong>Tell your boss and IT department about attempted or successful cyberattacks immediately. They will help you determine the next best steps to minimize the damage. If you’ve wired money to an attacker, contact your financial institution. Finally, report all cybercrimes to the appropriate government agencies to help protect others.&nbsp;</li></ul><p></p><p></p><ul><li><strong>Be wary of anyone asking for personal information over the phone.&nbsp;</strong>Even pressing buttons or answering “Yes” or “No” questions can help a scammer. A legitimate company will understand if you need to verify information and call back—and won’t be aggressive in seeking information from you.</li></ul><p><ul><li>If you do inadvertently download malware, don’t panic. Follow the steps provided, and contact your IT department or a trusted professional to help you secure your device.</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-3-social-engineering-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>your brain on uncertainty</li><li><strong>Know-how </strong>to handle big emotions</li><li><strong>Know-how&nbsp;</strong>to grieve the death of a co-worker</li><li><strong>Know-how&nbsp;</strong>to find a good therapist</li><li><strong>Understand </strong>the anger cycle and how to interrupt it</li><li><strong>Know-how</strong> to get out of a mental rut</li></ul><br><br><p></p></div>' WHERE slug = 'module-6-dealing-with-emotions-learning-outcome';
