UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/571/mod_label/intro/3_Dealing%20with%20Emotions.mp4">https://goalvow.com/upskilling/pluginfile.php/571/mod_label/intro/3_Dealing%20with%20Emotions.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-dealing-with-emotions-lesson-3-grieving-the-death-of-a-co-worker';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/572/mod_label/intro/4_Dealing%20with%20Emotions.mp4">https://goalvow.com/upskilling/pluginfile.php/572/mod_label/intro/4_Dealing%20with%20Emotions.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-dealing-with-emotions-lesson-4-how-to-find-a-good-therapist';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/573/mod_label/intro/5_Dealing%20with%20Emotions.mp4">https://goalvow.com/upskilling/pluginfile.php/573/mod_label/intro/5_Dealing%20with%20Emotions.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-dealing-with-emotions-lesson-5-understanding-the-anger-cycle-and-how-to-interrupt-it';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/574/mod_label/intro/6_Dealing%20with%20Emotions.mp4">https://goalvow.com/upskilling/pluginfile.php/574/mod_label/intro/6_Dealing%20with%20Emotions.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-dealing-with-emotions-lesson-6-how-to-get-out-of-a-mental-rut';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Is your worry out of control?&nbsp;</strong>If you are overwhelmed by uncertainty or believe your worry and anxiety are out of control, it might be time to get help. Excessive worry and fear that danger is always around the corner might indicate generalized anxiety disorder. This disorder can be diagnosed, treated, and monitored by a qualified medical professional.</li></ul><p></p><ul><li><strong>Build your EQ score.&nbsp;</strong>EQ stands for Emotional Quotient or Emotional Intelligence. Slowing down and thinking through your feelings, motivations, and responses will make you more self-aware and able to help others, too.</li></ul><p></p><ul><li><strong>Reserve judgement on grief.&nbsp;</strong>People grieve differently, so give yourself—and everyone else—permission to do it however it feels healthy and productive. Scrutinizing your or someone else’s relationship to the deceased or questioning feelings of grief is unproductive and hurtful.</li></ul><p></p><ul><li><strong>Check if your company offers mental health benefits.</strong>&nbsp;Some employers offer free counseling or therapy sessions through employee assistance programs outside of health insurance. Contact your HR department to confirm what benefits your company offers.&nbsp;</li></ul><p></p><ul><li><strong>Sometimes, professional help is needed.&nbsp;</strong>Excessive anger or the inability to control anger can sometimes signal other issues. If you or someone you know struggles to express anger in healthy ways, there are options for help. A mental health professional or employee assistance program can offer suggestions.</li></ul><p><ul><li><strong>Don’t be afraid to ask for help.&nbsp;</strong>Isolating yourself during a rut makes things worse. Reach out to people with whom you feel comfortable sharing experiences. Open communication helps you process emotions and strengthens connections with others. If problems persist or worsen, contact a therapist or professional counselor, as it may indicate a more serious mental health disorder.&nbsp;</li></ul><p><br></p></p><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-6-dealing-with-emotions-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Master </strong>a beginners exercise</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to build a sustainable workout habit</li><li><strong>Know-how&nbsp;</strong>to apply the FITT principle to your workouts</li><li><strong>Overcome </strong>reasons of not exercising&nbsp;</li><li><strong>Implement</strong>&nbsp;easy desk stretches&nbsp;</li></ul><br><br><p></p></div>' WHERE slug = 'module-4-exercise-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2137/mod_resource/content/1/Exercise%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Exercise Course Material.pdf</a></p>' WHERE slug = 'module-4-exercise-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp; &nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/575/mod_label/intro/1_Exercise.mp4">https://goalvow.com/upskilling/pluginfile.php/575/mod_label/intro/1_Exercise.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-exercise-lesson-1-a-beginner-s-guide-to-exercise';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/576/mod_label/intro/2_Exercise.mp4">https://goalvow.com/upskilling/pluginfile.php/576/mod_label/intro/2_Exercise.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-exercise-lesson-2-building-a-sustainable-workout-habit';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/577/mod_label/intro/3_Exercise.mp4">https://goalvow.com/upskilling/pluginfile.php/577/mod_label/intro/3_Exercise.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-exercise-lesson-3-applying-the-fitt-principle-to-your-workouts';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/578/mod_label/intro/4_Exercise.mp4">https://goalvow.com/upskilling/pluginfile.php/578/mod_label/intro/4_Exercise.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-exercise-lesson-4-six-reasons-people-don-t-exercise-and-how-to-overcome-them';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/579/mod_label/intro/5_Exercise.mp4">https://goalvow.com/upskilling/pluginfile.php/579/mod_label/intro/5_Exercise.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-exercise-lesson-5-easy-desk-stretches';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Take time for rest and recovery.&nbsp;</strong>Pushing yourself beyond your physical limits—or failing to take time to rest and recover after intense exercise sessions—can harm your health and make maintaining your plan difficult. Rest and recovery are essential to a well-rounded workout routine, so build them into your plan.</li></ul><p></p><ul><li><strong>Reward yourself.&nbsp;</strong>Reinforce your small successes with small treats. Maybe it\'s a coffee after a tough workout or a massage at the end of the first month of achieving mini-goals. These little celebrations will keep you motivated on the way to the bigger target.</li></ul><p></p><p></p><ul><li><strong>Continue modifying your FITT plan.&nbsp;</strong>Remember that you’ll need to adjust your exercise plan over time. Avoid pushing yourself too hard, and monitor your progress. If things become too easy or boring, change the FITT components to keep you healthy and interested in your routine.</li></ul><p></p><ul><li><strong>Get out of your comfort zone.</strong>&nbsp;Exercise can be challenging, in more ways than one. But the fulfillment and gratification of testing your limits and developing your mental and physical strength are worth the time and effort. The result is a healthy new dimension to your life. &nbsp;</li></ul><p><ul><li><strong>Take a walk.&nbsp;</strong>A 3-minute movement break every hour is a great way to get your blood flowing and stretch your limbs. Consider grabbing a coffee, pacing on a call, or taking a lap around the office while discussing a question with a colleague.&nbsp;</li></ul></p><p></p><p><br></p><p></p><p></p></div>' WHERE slug = 'module-4-exercise-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Know-how </strong>habits form and how to break them</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to start new habits and make them stick</li><li><strong>Build </strong>a healthy morning routine</li><li><strong>Build </strong>a healthy evening routine</li><li><strong>Practice </strong>gratitude, tips and prompts</li><li><strong>Implement</strong> breathwork techniques</li></ul><br><br><p></p></div>' WHERE slug = 'module-2-forming-healthy-habits-learning-outcome';
