UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/584/mod_label/intro/5_Forming%20Healthy%20Habits.mp4?time=1710074734253">https://goalvow.com/upskilling/pluginfile.php/584/mod_label/intro/5_Forming%20Healthy%20Habits.mp4?time=1710074734253</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-forming-healthy-habits-lesson-5-practicing-gratitude-tips-and-prompts';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp; &nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/585/mod_label/intro/6_Forming%20Healthy%20Habits.mp4?time=1710074783535">https://goalvow.com/upskilling/pluginfile.php/585/mod_label/intro/6_Forming%20Healthy%20Habits.mp4?time=1710074783535</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-forming-healthy-habits-lesson-6-breathwork-techniques-for-beginners';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Embrace significant life changes.&nbsp;</strong>Switching jobs? Moving to a new house or city? Becoming a parent? Big life transitions change your environment and context, making it a prime time to break old habits.&nbsp;</li></ul><p></p><ul><li><strong>Change isn’t “one and done.”</strong>&nbsp;For changes to last, we must actively work at them. Barriers to change don’t simply disappear; we have to continue to work around them to maintain new habits. Remember, everyone slips up, so don’t feel bad about stops and starts. The key is not giving up.</li></ul><p></p><ul><li><strong>Fortify your morning routine with your nighttime routine.&nbsp;</strong>Streamline your mornings by laying out clothes, prepping food, or looking to the next day’s tasks the night before. Feeling prepared for the next day may also help you get better sleep. Your morning routine will thank you!</li></ul><p></p><ul><li><strong>If you’re having consistent trouble sleeping, consider talking to a doctor.&nbsp;</strong>Sometimes a lack of quality sleep can be associated with more serious health concerns. If adding an evening routine isn’t working, consult with a medical professional.</li></ul><p></p><ul><li><strong><em>Note:&nbsp;</em>Gratitude is not a “lesser of two evils” comparison.</strong>&nbsp;Gratitude doesn’t sound like this:&nbsp;<em>“I haven\'t had a raise in five years, and my schedule is erratic, but some people don’t have a job at all.”</em>&nbsp;Or,&nbsp;<em>“My partner is verbally abusive, but at least he’s not physically abusive like some.”</em></li></ul><p></p><p>Being a grateful person means making an intentional effort to focus on the blessings in your life. Using gratitude to invalidate legitimate feelings and emotions or downplay unacceptable treatment ultimately harms your well-being.</p><p><ul><li><strong>Did you know?&nbsp;</strong>Deep breathing can switch on the parasympathetic nervous system—the network in your body that relaxes you to a state of calm and safety after stress or danger has passed.&nbsp;</li></ul></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-2-forming-healthy-habits-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Know-how </strong>to support your team\'s mental health</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to raise awareness, supporting co-workers with mental health</li><li><strong>Know-how&nbsp;</strong>to combat stigma and misconceptions about mental health</li><li><strong>Know-how&nbsp;</strong>to recognize the signs of employee substance abuse at work</li><li><strong>Guide</strong>&nbsp;support to grieving employees</li><li><strong>Know-how </strong>to support a grieving co-worker</li></ul><br><br><p></p></div>' WHERE slug = 'module-5-mental-health-awareness-learning-outcome';
