UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/995/mod_label/intro/6_Mental%20Health.mp4">https://goalvow.com/upskilling/pluginfile.php/995/mod_label/intro/6_Mental%20Health.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-mental-health-awareness-lesson-6-how-to-support-a-grieving-co-worker';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Use your position to cultivate safety.&nbsp;</strong>Employees will keep their thoughts, needs, and emotions to themselves if they feel they will be exploited, ignored, or bullied. If you want your team to be open with you, you have to create a workplace where they feel safe to do so.</li></ul><p></p><ul><li><strong>You are not alone.&nbsp;</strong>Raising awareness at work reduces the stigma of mental health that prevents so many people from getting help. It starts by being vocal about your own struggles but also advocating for effective policies that make a difference. When you support your co-workers, you support yourself and pave the way for greater progress.&nbsp;</li></ul><p></p><ul><li>The Substance Abuse and Mental Health Services Administration (SAMHSA) in the United States operates a hotline for people struggling with substance abuse or addiction. Call 1-800-662-HELP for assistance, information, and referrals 24/7. SAMHSA also provides free resources and guidance for employers on their website at samsha.gov.</li></ul><p><ul><li>If your organization lacks a clear policy about bereavement or resources to help the grieving, consider asking leadership or HR to make it a priority. Death is a part of life that will eventually impact your organization. Being prepared to support employees dealing with grief and loss at work is the mark of a caring and compassionate employer.</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-5-mental-health-awareness-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>the science of happiness and well-being</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to improve your wellbeing through social connections</li><li><strong>Challenge</strong>&nbsp;core beliefs</li><li><strong>Avoid </strong>cognitive distortions that undermine your happiness</li><li><strong>Adopt </strong>physical habits for happiness and well-being</li><li><strong>Find </strong>purpose and meaning in life</li><li><strong>Know-how </strong>to connect with nature and improve health</li><li><strong>Boost </strong>your happiness</li></ul><br><br><p></p></div>' WHERE slug = 'module-1-positive-psychology-fundamentals-learning-outcome';
