UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/595/mod_label/intro/7_Positive%20Psychology%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/595/mod_label/intro/7_Positive%20Psychology%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-positive-psychology-fundamentals-lesson-7-easy-ways-to-connect-with-nature-and-improve-health';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/597/mod_label/intro/8_Positive%20Psychology%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/597/mod_label/intro/8_Positive%20Psychology%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-positive-psychology-fundamentals-lesson-8-ten-tech-tips-to-boost-happiness';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong><em>Note:&nbsp;</em></strong>If you find yourself unable to cultivate happiness or struggle with consistent feelings of hopelessness or despair, it may be time to consult a professional to help you find ways to address issues preventing you from achieving overall well-being.</li></ul><p></p><ul><li><strong>What’s one thing you can do?&nbsp;</strong>Think back on what you learned in this lesson. We covered a lot of tips, but you don’t need to take them on board all at once. Ask yourself,&nbsp;<em>“What’s one thing I can do today?”</em>&nbsp;Take small, deliberate steps to build fulfilling connections gradually.</li></ul><p></p><ul><li><strong>Give yourself (and others) a break.</strong>&nbsp;When you fall into negative patterns, take a moment to think of one thing that makes you grateful for yourself, others, or the world. Moments of gratitude can lift your mood and counterbalance the negative emotion or belief.&nbsp;</li></ul><p></p><ul><li><strong>Seek help from a trained professional.</strong>&nbsp;While this lesson’s tips are a helpful starting point, they shouldn’t replace a trained professional. If you relate to the cognitive distortions in this lesson, you may benefit from a professional who can diagnose and help treat harmful thinking patterns.&nbsp;</li></ul><p></p><ul><li><strong>Do what you love.&nbsp;</strong>It’s better to choose a habit you enjoy than to force yourself to do something you hate. Multiply your chance of success by choosing something intriguing or fun to try. A new routine is easier to stick with when it doesn’t feel like a punishment.&nbsp;</li></ul><p></p><ul><li><strong>Note: Your purpose may change.&nbsp;</strong>Your life purpose is born out of experiences, so it makes sense that as you experience more things, learn new information, and meet new people, your passions and interests may change. Your purpose should align with your current values and beliefs — not what some former version of yourself believed. That means sometimes your purpose will change. And that’s OK.</li></ul><p></p><ul><li><strong>Don’t forget the sense of smell.&nbsp;</strong>Botanical scents aren’t just for the spa—they have proven health benefits! Citrus, for example, is energizing, while lavender is a relaxing stress-buster. Try a few essential oils and note how they make you feel. Keep a few at your desk that create a positive response, or carry a roll-on in your bag or purse.</li></ul><p><ul><li><strong><em>Note:&nbsp;</em>Used wisely, technology can actually be good for your mental health</strong>. Many online spaces offer help, advice, and community support if you’re struggling. You can connect with experts who can help, find people experiencing similar feelings, and access support tools—creating a healthier, happier you without even leaving the comforts of home.</li></ul></p><p></p><p></p><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-1-positive-psychology-fundamentals-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><span><strong>Know-what </strong>makes people feel happy and fulfilled at work</span></li><li><strong>Know-how </strong>to find meaning and purpose in your work</li><li><strong>Build </strong>a healthy social life at work</li><li><strong>Boost </strong>your wellness with healthy workplace habits&nbsp;</li><li><strong>Find </strong>flow and engagement in your work</li><li><strong>Foster </strong>positive emotions at work</li><li><strong>Know-how </strong>to combat workplace perfectionism</li></ul><br><br><p></p></div>' WHERE slug = 'module-3-positive-psychology-in-the-workplace-learning-outcome';
