UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/610/mod_label/intro/6_HR_Ways%20to%20Reduce%20Interviewer%20Bias.mp4">https://goalvow.com/upskilling/pluginfile.php/610/mod_label/intro/6_HR_Ways%20to%20Reduce%20Interviewer%20Bias.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-interviewing-lesson-6-ways-to-reduce-interviewer-bias';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/611/mod_label/intro/7_HR_Why%20and%20How%20to%20Follow-Up%20After%20an%20Interview.mp4?time=1708866929057">https://goalvow.com/upskilling/pluginfile.php/611/mod_label/intro/7_HR_Why%20and%20How%20to%20Follow-Up%20After%20an%20Interview.mp4?time=1708866929057</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-interviewing-lesson-7-why-and-how-to-follow-up-after-an-interview';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><span>Plan for potential interruptions. Schedule a 15-minute buffer before and after each interview to protect&nbsp;</span>your interview time from meetings that run late and to avoid having to cut your interview short if it&nbsp;goes long. Also, if you’re conducting a video interview, be sure to test your technology beforehand so&nbsp;that everything runs smoothly when you need it.</li></ul><ul><li>Don’t hesitate to keep phone interviews short. If it’s the very first interview and you still have a large pool of candidates to narrow down, you might schedule 20-30-minute calls to make the first cut. Don’t let technical issues interrupt your video interviews. Choose and test your video conferencing software well before reaching out to candidates. Provide candidates with details about how to use the program and what to expect. Also, ask candidates to test their tech in advance so that you can both be present for the entirety of your scheduled time together.</li></ul><ul><li>Try to make a capability test as relevant and accurate as possible. What are the primary duties or skills required for the position? How can you create a practice assessment, exercise, or assignment that is relevant to those duties or that truly applies those skills?<br></li></ul><p></p><ul><li>Keep interviewer bias at the forefront of your considerations. Consider how different types of interviews might leave more or less room for unconscious bias, or accidental discrimination, and take steps to minimize it.</li></ul><p></p><ul><li>Take notes. Take notes during or immediately after an interview depending on whether you conduct it over the phone or in person. Interviewing a lot of candidates can make your interviews feel like a blur and cause you to confuse candidates or forget important information. Notes can help you remember your initial impressions and identify information to circle back to in follow-up interviews.</li></ul><p></p><ul><li>Write a list of interview questions beforehand. Structured interviews are known to be more effective, and more legally defensible, than unstructured interviews. Write your interview questions down beforehand. You can use this list to stay organized and double check for illegal questions. Stick to this list during the interview to avoid making a mistake.</li></ul><p></p><ul><li>Be slow and deliberate in your decision-making. Interviewers often jump to conclusions or make their minds up about a candidate early in the interview. Slow down. Resolve to set aside judgments until the very end of the interview—after you consult your notes and the job criteria.</li></ul><p><ul><li>Double check a job offer before you send it. Ask colleagues or consult a lawyer if you have questions. Once a job offer is sent and signed, the candidate will expect that you’re able to uphold it.</li></ul></p><p></p><p><br></p><p></p><p></p><p></p></div>' WHERE slug = 'module-3-interviewing-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>retirement planning and why it is crucial</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;a retirement plan that will work for you</li><li><strong>Know-how</strong>&nbsp;to avoid retirement planning mistakes.</li></ul><br><p></p></div>' WHERE slug = 'module-8-retirement-planning-learning-outcome';
