UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/614/mod_label/intro/3_HR_Retirement%20Planning.mp4">https://goalvow.com/upskilling/pluginfile.php/614/mod_label/intro/3_HR_Retirement%20Planning.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-8-retirement-planning-lesson-3-age-milestones-for-your-retirement-planning';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/615/mod_label/intro/4_HR_Retirement%20Planning.mp4">https://goalvow.com/upskilling/pluginfile.php/615/mod_label/intro/4_HR_Retirement%20Planning.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-8-retirement-planning-lesson-4-catching-up-when-you-re-behind-on-retirement-saving';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/962/mod_label/intro/5_HR_Retirement%20Planning.mp4">https://goalvow.com/upskilling/pluginfile.php/962/mod_label/intro/5_HR_Retirement%20Planning.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-8-retirement-planning-lesson-5-five-retirement-planning-mistakes-to-avoid';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr"><strong>Summary</strong></p><p dir="ltr"></p><ul><li>Take control of what you can. There are many unknowns in life. You don’t know what the job market will be like when you’re older, nor do you know what your health will be like or what government programs will or won’t exist. But there is something that you can guarantee, and that’s saving for your retirement. So, do your future self a favor and commit to taking control of what you can—starting today.</li></ul><p></p><ul><li>You can choose more than one plan. Are you having trouble deciding? Keep in mind that you don’t have to limit yourself to only one retirement plan. Depending on your situation, you may be able to choose more than one option. And you may turn to different plans at different stages of your life. What matters most is that you pick the plan or plans that will work best for your current and anticipated future needs.<br></li></ul><p></p><ul><li>Don’t compare yourself to others. While each retirement-planning milestone represents a worthy goal, don’t get caught up in the comparisons. We’re all running our own race and have our own roadblocks. What matters most is that you have a plan and that you stick to it.</li></ul><p></p><ul><li>Focus on what you can change. You might feel tempted to obsess over what you “should have done” years ago, but you can’t change the past. Living with regret isn’t only unhealthy; it’s also unhelpful. So, focus on the future. Focus on the things that you can change, and commit to taking those small, steady steps toward a more secure financial future.</li></ul><p><ul><li>You can roll accounts over into an IRA. If you simply want to move funds from one retirement plan to another, you can roll that money over into a traditional IRA. With this option, you won’t face any fees or miss out on future compounding interest.</li></ul></p><p></p><p></p></div>' WHERE slug = 'module-8-retirement-planning-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand&nbsp;</strong>the workplace Anti-Discrimination laws</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to build a respectful workplace</li><li><strong>Understand</strong>&nbsp;Harassment and Discrimination.&nbsp;</li><li><strong>Know-how&nbsp;</strong>to differential to types of Sexual Harassment</li><li><strong>Implement</strong>&nbsp;processes that will deal with Sexual Harassment.</li></ul>,<br><p></p></div>' WHERE slug = 'module-7-anti-harassment-and-discrimination-learning-outcome';
