UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/1068/mod_label/intro/3_HR_Talent%20Management.mp4">https://goalvow.com/upskilling/pluginfile.php/1068/mod_label/intro/3_HR_Talent%20Management.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-talent-management-lesson-3-attracting-and-sourcing-top-talent';
