UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/632/mod_label/intro/3_HR_How%20to%20Overcome%20Your%20Unconscious%20Biases.mp4">https://goalvow.com/upskilling/pluginfile.php/632/mod_label/intro/3_HR_How%20to%20Overcome%20Your%20Unconscious%20Biases.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-unconscious-bias-lesson-3-how-to-overcome-your-unconscious-biases';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/633/mod_label/intro/4_HR_Tips%20for%20Avoiding%20Bias%20While%20Recruiting%20and%20Retaining%20Talent.mp4">https://goalvow.com/upskilling/pluginfile.php/633/mod_label/intro/4_HR_Tips%20for%20Avoiding%20Bias%20While%20Recruiting%20and%20Retaining%20Talent.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-unconscious-bias-lesson-4-tips-for-avoiding-bias-while-recruiting-and-retaining-talent';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr"></p><ul><li>What are your biases? When evaluating unconscious bias, the question is not, <em>“Do I have them?”</em> but rather, <em>“What are they?”</em> Remember, unconscious biases are unintentional, so maintain self-awareness. Notice when you’re making judgments too quickly and focus on re-evaluating your thought process.</li></ul><p></p><ul><li>Ask why. Think about past decisions that you’ve made at work—even those that are seemingly inconsequential. Ask yourself: <em>Why did I make that decision? What assumptions was I operating within at that time?</em></li></ul><p></p><ul><li><span>Check your assumptions. The next time you jump to conclusions, ask yourself why. Why do you think&nbsp;</span><span>this? Is this decision based on an irrational bias? Keep your assumptions in check, and you’ll build&nbsp;awareness of your biases, which is the first step to overcoming them.</span></li></ul><p><ul><li>Increase the diversity of your hiring panel. Increase the diversity of your hiring or interview panel as well as your talent management staff . Having a diverse set of perspectives represented will help you combat bias in your hiring decisions.</li></ul></p></div>' WHERE slug = 'module-4-unconscious-bias-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><ul><li><strong>Understand </strong>the benefits of health and well-being to businesses.</li><li><strong>Develop </strong>and employee wellness program.</li><li><strong>Capable </strong>of assessing employee interest on Wellness.</li><li><strong>Implement</strong>&nbsp;a diversified wellness program.</li><li><strong>Know-how</strong>&nbsp;to boost employee participation on wellness programs.</li></ul><br><p></p></div>' WHERE slug = 'module-6-workplace-well-being-learning-outcome';
