UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/637/mod_label/intro/4_HR_Workplace%20Well-Being.mp4">https://goalvow.com/upskilling/pluginfile.php/637/mod_label/intro/4_HR_Workplace%20Well-Being.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-workplace-well-being-lesson-4-diversifying-your-wellness-programs';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/638/mod_label/intro/5_HR_Workplace%20Well-Being.mp4">https://goalvow.com/upskilling/pluginfile.php/638/mod_label/intro/5_HR_Workplace%20Well-Being.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-workplace-well-being-lesson-5-increasing-awareness-of-employee-wellness-programs';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/639/mod_label/intro/6_HR_Workplace%20Well-Being.mp4">https://goalvow.com/upskilling/pluginfile.php/639/mod_label/intro/6_HR_Workplace%20Well-Being.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-workplace-well-being-lesson-6-how-to-boost-participation-for-your-employee-wellness-program';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr"><strong>Summary</strong></p><p dir="ltr"></p><ul><li>Get buy-in from leaders. Company leadership has an immense impact on the workplace culture and can make or break the success of a wellness initiative. Get your organization’s leaders on board before launching a wellness program, so they can serve as role models and spearhead the movement toward better health.</li></ul><p></p><ul><li>Ask for help. A successful wellness program is employee-led. Ask for help from employees in shaping and running the program.</li></ul><p></p><p dir="ltr"></p><p></p><ul><li>Send a company-wide calendar invite to take the survey. Encourage employees to complete the survey by scheduling it on their calendars. Consider sending a company-wide calendar invite that blocks out 15 minutes for completing the survey during the workday. Set a reminder notification of the appointment and don’t forget to include the link to the survey!</li></ul><p></p><p></p><ul><li>Ask your team. Feeling stuck? Unsure which ideas your employees would like best? You don’t have to develop a wellness program alone. Get your team involved. Send out an employee interest survey or host a creative brainstorming session and ask for their ideas. A diversity of perspectives can generate more dynamic and diverse ideas for wellness activities.</li></ul><p></p><ul><li>Avoid rigid health ideals. Avoid setting a rigid health ideal or wellness goal. Instead, leave it up to the individual to define their own goals. For example, rather than encouraging employees to get at least 150 minutes of moderate exercise a week, encourage them to set incremental and attainable goals that fit their lifestyle.</li></ul><p></p><ul><li>Consider your audience. Always consider your employees in your communication decisions. Who will be most difficult to reach? What channels of communication do they use most? What are their biggest priorities and motivations for better health? Meet your employees where they are.</li></ul><p><ul><li>Ask for regular feedback. As you apply these strategies to your program, don’t forget to regularly ask for employees’ feedback, input, and suggestions. Ask them what works, what doesn’t work, and what they need to start participating in an employee wellness program.</li></ul></p><p></p></div>' WHERE slug = 'module-6-workplace-well-being-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand</strong>&nbsp;the importance of branding</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to develop your brand personality</li><li><strong>Know-how&nbsp;</strong>to use visual brand design essentials</li><li><strong>Know-how&nbsp;</strong>to position and send a compelling message for your brand</li><li><strong>Know-how </strong>to tell a compelling brand story</li><li><strong>Implement </strong>a strategy for rebranding</li></ul><br><br><p></p></div>' WHERE slug = 'module-2-brand-identity-and-strategy-learning-outcome';
