UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/653/mod_label/intro/8_Content%20Marketing.mp4?time=1709436236306">https://goalvow.com/upskilling/pluginfile.php/653/mod_label/intro/8_Content%20Marketing.mp4?time=1709436236306</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-content-marketing-lesson-8-business-blogging-101';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr"></p><ul><li><strong>Pretend you’re the customer.</strong> Think about your own spending habits and the brands you’ve personally bonded with over the years. How did those companies win your loyalty, and what keeps you coming back? Challenge yourself to create the type of content that you would like to see if you were in the market searching out opportunities.</li></ul><p></p><ul><li><strong>Don’t squander great content by taking a passive approach.</strong> Be bold, and trust that once you get it in front of the right audience, you’ll see real results.</li></ul><p></p><ul><li><strong>Experiment and iterate.</strong> Monitor the popularity and effectiveness of your content. What content attracts the most traffic? And which campaigns have the highest conversion rates? Experiment, identify trends, and adjust your content strategy to find what works best with your audience.</li></ul><p></p><ul><li><strong>Stop and ask yourself:</strong> <em>“What is my message, who is it for, and what’s the lasting impression I want to leave with them?”</em></li></ul><p></p><ul><li><em><strong>Tip 1:</strong> </em>Most distribution channels offer tools and resources to measure various KPIs. Familiarize yourself&nbsp;<span>with the tools available to track your success.&nbsp;</span></li></ul><ul><li><strong><em>Tip 2:</em></strong> Managing your content strategy may require investment in time, resources, and personnel.</li></ul><p></p><ul><li><strong>Don’t be a lone wolf.</strong> Developing a content strategy isn’t a one-person job. Involve your team members in each stage of the process, and delegate tasks as necessary. Getting multiple perspectives ensures that you’re creating a comprehensive strategy that will guide your content through its lifecycle.</li></ul><p></p><ul><li><strong>Find the best content for you.</strong> The content we covered in this lesson is only the beginning. Every industry and company is different, and you may find that some strategies work better than others. Keep creating, testing, and experimenting. As long as you remember your overall TOFU, MOFU, and BOFU goals, you will develop the best content for your brand and consumers.</li></ul><p></p><ul><li><strong>Remember the person behind the reader.</strong> Don’t bore them with tired cliches and corporate lingo. Be friendly, and don’t be afraid to show your personality. Treat them like real people, and they’re more likely to respond and engage.</li></ul><p><ul><li><strong>Don’t forget to market the blog. </strong>Link to new posts in your email, newsletter, and social platforms to boost traffic.</li></ul></p><p></p></div>' WHERE slug = 'module-4-content-marketing-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>the different types of customer research available</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to identify your target market</li><li><strong>Know-how&nbsp;</strong>to create and use buyer personas</li><li><strong>Know-how&nbsp;</strong>to create a customer journey map</li><li><strong>Know-how </strong>to conduct a competitive landscape analysis</li><li><strong>Implement </strong>a strategy to segment your target market</li></ul><br><br><p></p></div>' WHERE slug = 'module-5-customer-and-marketing-research-learning-outcome';
