UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/672/mod_label/intro/8_Marketing%20Fundamentals.mp4?time=1709433574893">https://goalvow.com/upskilling/pluginfile.php/672/mod_label/intro/8_Marketing%20Fundamentals.mp4?time=1709433574893</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-marketing-fundamentals-lesson-8-introduction-to-marketing-analytics';
UPDATE lessons SET content = '<div class="no-overflow"><p><strong>Summary</strong></p><p></p><ul><li><strong>Successful marketing connects the right customers to your offering.</strong> This is accomplished not by finding the customers to suit the offering but by creating an offering that fits the target customers’ wants and needs.</li></ul><p></p><ul><li>The examples of traditional and digital marketing methods in this lesson aren’t meant to be an exhaustive list. Marketing has a rich history of innovation and features a spectrum of methods and strategies to engage customers. The key is finding the right tools for your business.</li></ul><p></p><ul><li><strong>Expanding the 4 Ps.</strong> Some marketing professionals use the “7 Ps,” which include additional elements like people, process, and physical evidence. As you consider your offering, you may want to incorporate more Ps to test your marketing strategy further.</li></ul><p></p><ul><li><strong>Winners sometimes quit.</strong> Remember, marketing plans are fluid documents for a reason. Don’t be afraid to pivot when necessary. The faster you move on from tactics that don’t work, the sooner you’ll discover those that will help you achieve your goals.</li></ul><p></p><ul><li><strong>Get creative.</strong> A USP is about individuality. As you seek inspiration, you might look at other companies for examples. But ultimately, your USP shouldn’t sound like anyone else’s. So, have fun brainstorming with your team, and permit yourself to flex those creativity muscles. Think outside of the box, and you’ll find an untouched marketplace niche where your company can shine.</li></ul><p></p><ul><li><strong>Customize your funnel.</strong> As you review the marketing funnel, keep in mind that you can customize the step labels to suit your business. While the overall flow will look similar for every company, the individual steps may differ. So, explore your buyers’ experience, and don’t hesitate to rename, combine, or separate the steps so that they fit your company best.</li></ul><p></p><ul><li><strong>Company beware. </strong>The old saying “Buyer beware” is rapidly being replaced by a new warning: “Company beware.” Disgruntled customers can take to social media to fight back against unethical marketing practices—and their voices could be heard by millions. Don’t resort to manipulation. Instead, strive for transparency and authenticity in your marketing.</li></ul><p><ul><li>Incorporate analytics as an ongoing part of your marketing strategy and decision-making process. Make a habit of regularly reviewing the data throughout the month—not just at the end of a campaign or reporting period.</li></ul></p></div>' WHERE slug = 'module-1-marketing-fundamentals-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>what is marketing analytics and how you can use it to your advantage</li><li><strong>Choose </strong>marketing key performance indicators from your marketing campaign</li><li><strong>Capable</strong>&nbsp;of measuring the effectiveness of your marketing campaign</li><li><strong>Know-how&nbsp;</strong>to interpret and analyze the marketing data</li><li><strong>Use </strong>storytelling to communicate data</li></ul><br><br><p></p></div>' WHERE slug = 'module-11-marketing-analytics-learning-outcome';
