UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/674/mod_label/intro/2_Marketing%20Analytics.mp4?time=1709475175424">https://goalvow.com/upskilling/pluginfile.php/674/mod_label/intro/2_Marketing%20Analytics.mp4?time=1709475175424</video>&nbsp;<br></p></div>' WHERE slug = 'module-11-marketing-analytics-lesson-2-choosing-marketing-key-performance-indicators';
UPDATE lessons SET content = '<div class="no-overflow">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/675/mod_label/intro/3_Marketing%20Analytics.mp4?time=1709475246011">https://goalvow.com/upskilling/pluginfile.php/675/mod_label/intro/3_Marketing%20Analytics.mp4?time=1709475246011</video>&nbsp;</div>' WHERE slug = 'module-11-marketing-analytics-lesson-3-measuring-the-effectiveness-of-marketing-campaigns';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp; &nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/676/mod_label/intro/4_Marketing%20Analytics.mp4?time=1709475527970">https://goalvow.com/upskilling/pluginfile.php/676/mod_label/intro/4_Marketing%20Analytics.mp4?time=1709475527970</video>&nbsp;<br></p></div>' WHERE slug = 'module-11-marketing-analytics-lesson-4-tips-for-interpreting-and-analyzing-marketing-data';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/677/mod_label/intro/5_Marketing%20Analytics.mp4?time=1709475584474">https://goalvow.com/upskilling/pluginfile.php/677/mod_label/intro/5_Marketing%20Analytics.mp4?time=1709475584474</video>&nbsp;<br></p></div>' WHERE slug = 'module-11-marketing-analytics-lesson-5-using-storytelling-to-communicate-data';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr"></p><ul><li><strong>Incorporate analytics as an ongoing part of your marketing strategy and decision-making process.</strong> Make a habit of regularly reviewing the data throughout the month—not just at the end of a campaign or reporting period.</li></ul><p></p><ul><li><strong>You may want to hire an expert. </strong>Marketing analytics can be overwhelming, and specialists have the knowledge and experience to develop a unique plan for your organization. Instead of going forward alone, consider bringing someone onto your team.</li></ul><p></p><ul><li><strong>Share your findings with other teams.</strong> Never place blame on anyone. Instead, keep communication open and work together to improve numbers.</li></ul><p></p><ul><li><strong>There are many advanced methods and models for analyzing campaign effectiveness.</strong> We’ve just scratched the surface of what’s possible for you and your marketing plans. Models such as multi-touch attribution, marketing mix modeling, and economic modeling provide deeper insight into different types of campaigns and definitions of success. For an analysis plan unique to your organization, consider consulting an expert or hiring a marketing agency.</li></ul><p></p><ul><li><strong>Don’t forget: Interpretation is subjective.</strong> Success will mean different things across different campaigns. Establish what success means for you, your team, and your organization, and stay open to varying interpretations of your data.</li></ul><p><ul><li><strong>Be a ruthless editor.</strong> What you leave out is just as important as what you leave in. Effective data presentation requires tough editorial decisions. Time, space, medium, and audience should all influence the type and amount of content you include and how you convey it. If you boil the data down to its most essential ideas, managers will be more likely to listen to your suggestions and take bold action.</li></ul></p></div>' WHERE slug = 'module-11-marketing-analytics-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>how to use Search Engine Marketing (SEM) to your advantage</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to implement your paid search and paid per click advertising</li><li><strong>Implement</strong> out-of-home advertising</li><li><strong>Implement</strong> display advertising</li><li><strong>Know-how </strong>to create eye-catching display ads</li><li><strong>Recapture </strong>audience attention through remarketing</li></ul><br><br><p></p></div>' WHERE slug = 'module-10-paid-advertising-learning-outcome';
