UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr"></p><ul><li><strong>Keep reviewing your strategy. </strong>Search engine advertisers change parameters from time to time without fanfare. Review them regularly to stay on top of changes.</li></ul><p dir="ltr"></p><ul><li><span><strong>Track your paid ad performance.</strong> Experiment with different ad messages, formats, links, timing, and&nbsp;</span><span>other variables to explore how they affect your ad performance and search engine ranking.</span></li></ul><p></p><ul><li><strong>Get inspired and explore examples from your favorite brands.</strong> Research online to find creative and award-winning examples of OOH from other companies.</li></ul><p></p><ul><li><strong>Pinching your pennies? </strong>Because of their low cost, display ads are particularly useful for those on a budget. Or, if you’re looking to strategically spend down some leftover advertising dollars, display ads also provide good value for money.</li></ul><p><ul><li><strong>When in doubt, go for the simpler option.</strong> The more complex an ad becomes, the more likely the message will get lost. The job of a display ad is to guide visitors to their destination, like an appetizer before the main course. So, draw just enough attention to make people want to learn more.</li></ul><p><br></p></p></div>' WHERE slug = 'module-10-paid-advertising-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand&nbsp;</strong>the market your product or service will operate into.</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to find and measure your Product-Market-Fit</li><li><strong>Know-how</strong>&nbsp;to develop your Pricing Strategy</li><li><strong>Know-how&nbsp;</strong>to craft an effective Go-to-Market Strategy.</li><li><strong>Know-what </strong>steps to take for a successful product launch</li><li><strong>Implement</strong>&nbsp;strategies that will increase your sales.</li></ul><br><br><p></p></div>' WHERE slug = 'module-3-product-marketing-learning-outcome';
