UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp; &nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/705/mod_label/intro/11_Social%20Media%20Marketing.mp4?time=1709444180125">https://goalvow.com/upskilling/pluginfile.php/705/mod_label/intro/11_Social%20Media%20Marketing.mp4?time=1709444180125</video>&nbsp;<br></p></div>' WHERE slug = 'module-8-social-media-marketing-lesson-11-eight-social-media-metrics-to-monitor';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr"><strong>Summary</strong></p><p dir="ltr"></p><ul><li><strong>Social media constantly changes. </strong>New social media sites and apps pop up every year. Stay up to date with new features, trends, and apps.</li></ul><p></p><p dir="ltr"></p><ul><li><span><strong>Test your theories.</strong> A/B testing pits version A and version B against each other to see which performs&nbsp;</span>best. Use A/B testing to determine the best times of day to post, what content types are popular, or even which platforms attract the most audience interactions.</li></ul><p></p><ul><li><strong>Simplify social practice.</strong> If you decide to use multiple platforms, try a social media management tool to access all your channels with one login and dashboard. Use it to plan and understand posts and interactions at a glance.</li></ul><p></p><ul><li><strong>Ro</strong><strong>tate between buckets.</strong> Avoid overfilling one content bucket while leaving another bucket empty. Instead, rotate between buckets to ensure you’re giving each topic equal attention.</li></ul><p></p><ul><li><strong>There is more to learn.</strong> This lesson features a sampling of social media marketing best practices, but it isn’t an exhaustive list. Peruse reputable online sources to learn more ways to improve customer reach and engagement on social media. Guides from individual platforms and third parties can help you improve.</li></ul><p></p><ul><li><strong>Take action.</strong> While “listening” might sound passive, social listening is very much about action. Monitoring conversations and analyzing themes are just the first steps. To reap the full benefits, you’ll need to move tactically in response to any collected data. With each piece of information you collect, ask yourself: What can we do with this? How can we take action?</li></ul><p></p><ul><li><strong>Change is inevitable.</strong> The nature of social media is ever-evolving. New trends can emerge tomorrow, only to vanish the next day. Keep an open mind and go with the flow.</li></ul><p></p><ul><li><strong>Start an inspiration folder.</strong> Schedule regular time to explore the social web and get inspired by creative brands, influencers, or followers.</li></ul><p></p><ul><li><strong>Be mindful of space.</strong> It may sound odd to think of taking up space in a virtual environment, but social media operates like a public park. So, just like in a physical park, be courteous, don’t be too noisy, and respect the space.</li></ul><p></p><ul><li><strong>Don’t skip research! Knowing what your audience likes,</strong> what they’re doing, and what interests them helps you meaningfully tailor messages. While a tongue-in-cheek midnight tweet from Taco Bell might reach the college crowd, Sesame Street would have better luck with a playful tweet in the afternoon to reach parents of young children.</li></ul><p><ul><li><strong>Don’t be afraid to invest in additional tools and resources.</strong> Many social media platforms provide analytics that measure various metrics. But web apps and third-party tools available for purchase can take it to the next level. When identifying your most critical social media metrics, factor in the cost required to measure them effectively. It’ll be money well spent.</li></ul></p><p></p></div>' WHERE slug = 'module-8-social-media-marketing-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li>Have the&nbsp;<strong>capability</strong>&nbsp;to use your website as a marketing tool to attract traffic<br></li><li><strong>Know-how&nbsp;</strong>to design great landing pages</li><li><strong>Know-how&nbsp;</strong>to reduce friction on your website and your website conversion rate</li></ul><br><br><p></p></div>' WHERE slug = 'module-6-website-marketing-learning-outcome';
