UPDATE lessons SET content = '<div class="no-overflow">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/960/mod_label/intro/1_Website%20Marketing.mp4?time=1709440801853">https://goalvow.com/upskilling/pluginfile.php/960/mod_label/intro/1_Website%20Marketing.mp4?time=1709440801853</video>&nbsp;</div>' WHERE slug = 'module-6-website-marketing-lesson-1-using-your-website-as-a-marketing-tool';
UPDATE lessons SET content = '<div class="no-overflow">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/707/mod_label/intro/2_Website%20Marketing.mp4?time=1709440948629">https://goalvow.com/upskilling/pluginfile.php/707/mod_label/intro/2_Website%20Marketing.mp4?time=1709440948629</video>&nbsp;</div>' WHERE slug = 'module-6-website-marketing-lesson-2-how-to-design-great-landing-pages';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/972/mod_label/intro/3_Website%20Marketing.mp4?time=1709441011368">https://goalvow.com/upskilling/pluginfile.php/972/mod_label/intro/3_Website%20Marketing.mp4?time=1709441011368</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-website-marketing-lesson-3-how-to-reduce-friction-and-increase-website-conversions';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr"></p><ul><li><strong>Promote your website on emails and social media platforms.</strong> Link to your website in email campaigns or signatures—and social media profiles or posts.</li></ul><p></p><ul><li><strong>There are many subcategories of landing pages.</strong> Certain lead generation pages focus exclusively on capturing email addresses (“squeeze pages”), while others outline pricing or subscription options. Some landing pages are used for purely informational purposes, such as “About Us” or “Thank You” pages, or to promote upcoming events. Long-form landing pages (“explainer pages”) go into much greater detail about the product or service they’re offering. Consider your campaign-specific goal when tailoring your landing page.</li></ul><p></p><ul><li><strong>Boost your page loading speed.</strong> Nobody wants to wait endlessly for a page to load. Users have been conditioned to expect instant results, so any lag at all can easily turn site visitors away. The landing page should already be free of clutter and other elements that may cause drag, but you will want to take additional measures to ensure a rapid loading time. And don’t forget to test it regularly.</li></ul><p></p><ul><li><strong>Challenge your assumptions.</strong> Because the internet plays a central part in our personal and professional lives, we often assume that we just have an intuitive sense of how a website operates and how we can use it to our advantage. Challenge those assumptions and be willing to incorporate techniques that are proven to get results, even if it contradicts beliefs you’ve held about the topic. That willingness could result in a new level of success for your business.</li></ul><p><ul><li><strong>Configure a “persistent shopping cart.”</strong> A persistent shopping cart automatically saves items in visitors’ shopping carts when they leave your website. That way, customers can pick up where they left off upon return.</li></ul></p><p></p></div>' WHERE slug = 'module-6-website-marketing-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>After completing this module</strong><strong>, you will be able to:&nbsp;</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Master</strong> sales negotiations</li><li><strong>Understand </strong>essential techniques for negotiating a sale</li><li><strong>Countering</strong> common buyer negotiation tactics</li><li><strong>Know-how</strong> to close sales</li><li><strong>Know-how </strong>to transition to customer success</li></ul><p></p></div>' WHERE slug = 'module-6-closing-the-deal-learning-outcome';
