UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/710/mod_label/intro/3_Closing%20the%20Deal.mp4?time=1709819054838">https://goalvow.com/upskilling/pluginfile.php/710/mod_label/intro/3_Closing%20the%20Deal.mp4?time=1709819054838</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-closing-the-deal-lesson-3-countering-common-buyer-negotiation-tactics';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/711/mod_label/intro/4_Closing%20the%20Deal.mp4?time=1709819097881">https://goalvow.com/upskilling/pluginfile.php/711/mod_label/intro/4_Closing%20the%20Deal.mp4?time=1709819097881</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-closing-the-deal-lesson-4-closing-the-sale';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/712/mod_label/intro/5_Closing%20the%20Deal.mp4?time=1709819151888">https://goalvow.com/upskilling/pluginfile.php/712/mod_label/intro/5_Closing%20the%20Deal.mp4?time=1709819151888</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-closing-the-deal-lesson-5-transitioning-to-customer-success';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Give and take.&nbsp;</strong>A negotiation can only end successfully when both sides benefit in some way. Empathize with your buyer’s position for a smoother road to agreement.</li></ul><p></p><ul><li><strong>Take notes on your negotiations.</strong>&nbsp;Learn from your experiences by jotting down what you observe during negotiations. By identifying what soars—and what flops—you’ll develop a powerful toolbox of techniques.</li></ul><p></p><ul><li><strong>Don’t take things personally.&nbsp;</strong>These tactics exist to throw you off your game. Simply accept them—and the heightened emotions that can ensue—as part of the process. Take a deep breath and get down to business.</li></ul><p></p><ul><li><strong>Making a deal is a journey, not a destination.&nbsp;</strong>The stereotypical refrain of the sales world is: “Always be closing.” But that doesn’t mean you should push aggressively from the start. Think of each step as a bridge that connects you to your final goal.</li></ul><p></p><ul><li><strong>Solicit feedback.&nbsp;</strong>Improve the transition process today by asking Customer Success what they need from Sales. That will also give you an indication of what questions to ask the customer in the selling process.</li></ul><strong><br></strong><p></p><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-6-closing-the-deal-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>After completing this module you will be able to:</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Know-how </strong>to analyse your sales pipeline</li><li>Be <strong>capable </strong>of using sales tools for more successful sales transactions</li><li><strong>Integrate </strong>your sales and marketing efforts</li><li><strong>Align </strong>the sales with the buyers journey</li></ul><p></p></div>' WHERE slug = 'module-1-sales-fundamentals-learning-outcome';
