UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/720/mod_label/intro/8_Sales%20Fundamentals.mp4?time=1709803142700">https://goalvow.com/upskilling/pluginfile.php/720/mod_label/intro/8_Sales%20Fundamentals.mp4?time=1709803142700</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-sales-fundamentals-lesson-8-basic-sales-communication-skills';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><b>Summary</b></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Self-care is essential for salespeople.</strong>&nbsp;The field is fun and exciting, but long hours, the pressure to meet goals, and the prevalence of rejection can lead to burnout. Make sure that as you take care of your customers, you also take care of yourself.</li></ul><p></p><ul><li><strong>Let your pipeline be a helpful tool rather than a rigid structure.&nbsp;</strong>Every customer is different, and every solution is unique. So, it’s vital to see contacts as people rather than as figures on a chart. Remember—sales is about building relationships, not tracking stages.</li></ul><p></p><ul><li><strong>A CRM system is only as good as the data a salesperson enters into it.&nbsp;</strong>Every member of a sales team needs appropriate training to maintain records within the CRM system.</li></ul><ul><li><strong>It’s easy to get overwhelmed by all the tools available.</strong>&nbsp;Remember that sales tools are only meant to enhance your sales process, not overtake it. Ultimately, sales continues to be about building positive relationships, which good tools can make easier for your team.</li></ul><p></p><ul><li><strong>Alignment between sales and marketing isn’t a one-time event.&nbsp;</strong>Plan for regular meetings and create ways for the teams to collaborate. Give each team a voice at every stage of your process.</li></ul><p></p><ul><li>As you guide a contact through the buyer’s journey, you might occasionally determine that the best solution isn’t yours. That’s fine! You still have the opportunity to build a positive relationship. If done well, the customer might come back to you when they realize your solution&nbsp;<em>is</em>&nbsp;the right fit for them.</li></ul><p></p><ul><li>A great sale won’t feel like a business transaction—it will feel like a partnership based on mutual trust and respect. Making ethical choices will win your customers’ trust and uphold your reputation.</li></ul><p><ul><li><strong>Being nervous about having sales conversations is normal.</strong>&nbsp;Remember that you’re there to help another person solve a problem with a solution that you already have.&nbsp;</li></ul></p><p></p><p></p><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-1-sales-fundamentals-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Know-how</strong> to handle sales objections</li><li><strong>Overcome</strong> common sales objections</li><li><strong>Implement</strong> winning techniques for handling sales objections</li><li><strong>Understand </strong>common mistakes when handling sales objections</li></ul><p></p></div>' WHERE slug = 'module-7-handling-objections-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2071/mod_resource/content/2/Handling%20Objections%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Handling Objections Course Material.pdf</a></p>' WHERE slug = 'module-7-handling-objections-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/721/mod_label/intro/1_Handling%20Objections.mp4">https://goalvow.com/upskilling/pluginfile.php/721/mod_label/intro/1_Handling%20Objections.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-handling-objections-lesson-1-introduction-to-handling-sales-objections';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/722/mod_label/intro/2_Handling%20Objections.mp4">https://goalvow.com/upskilling/pluginfile.php/722/mod_label/intro/2_Handling%20Objections.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-handling-objections-lesson-2-five-common-sales-objections-and-how-to-overcome-them';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/723/mod_label/intro/3_Handling%20Objections.mp4">https://goalvow.com/upskilling/pluginfile.php/723/mod_label/intro/3_Handling%20Objections.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-handling-objections-lesson-3-winning-techniques-for-handling-sales-objections';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/724/mod_label/intro/4_Handling%20Objections.mp4">https://goalvow.com/upskilling/pluginfile.php/724/mod_label/intro/4_Handling%20Objections.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-handling-objections-lesson-4-common-mistakes-when-handling-sales-objections';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Listen closely when customers ask, “<em>Why</em>.”&nbsp;</strong>Questions that begin with&nbsp;<em>“why”</em>&nbsp;are often sales objections in disguise. For example, a customer who asks,&nbsp;<em>“Why is this option so much more expensive?”&nbsp;</em>may be expressing an objection to the product’s price. Pay attention—and treat disguised sales objections accordingly.&nbsp;</li></ul><p></p><ul><li><strong>Be selfless.&nbsp;</strong>At the core of each objection strategy is selflessness. A naysaying prospect has their guard up. So, if you want to move past that barrier, you must prove that your motives are genuine. Regardless of the objection, be selfless. Communicate to your prospect that you’re not just trying to land the sale—you’re trying to help them with the best solution.</li></ul><p></p><ul><li><strong>Aim for a mixed approach.&nbsp;</strong>We covered a lot of techniques in this lesson. And, while you might already have a favorite, never rely on just one. Every prospect is different, which means there’s no one way to solve every problem. So, concentrate on combining the techniques and aiming for a mixed approach—as that will lead to the best turnaround.</li></ul><p><ul><li><strong>Treat every mistake as a learning opportunity.</strong>&nbsp;If a customer raises a sales objection that you’re not sure how to handle or are unsuccessful at addressing, think about what you can learn from the experience. How could you address that sales objection better next time? And what could you have done differently this time?</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-7-handling-objections-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li>Have the&nbsp;<strong>capability</strong>&nbsp;to transition from salesperson to sales manager</li><li><strong>Know-how </strong>to manage a sales team effectively</li><li><strong>Understand </strong>common sales methodologies and how they work&nbsp;<br></li><li><strong>Understand</strong>&nbsp;sales best practices that can empower your sales team</li><li><strong>Build</strong> and effective sales process for your team</li><li><strong>Know-how </strong>to automate your sales process</li><li><strong>Know-how </strong>to structure your sales team for better sales results</li><li><strong>Track and Improve </strong>your sales team performance</li><li><strong>Set </strong>realistic sales quotas for your team</li><li><strong>Create </strong>battle cards to empower and enable your sales team</li><li><strong>Understand </strong>the basics of creating a sales forecast</li></ul><br><br><p></p></div>' WHERE slug = 'module-2-sales-leadership-and-management-learning-outcome';
