UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/748/mod_label/intro/5_Prospecting.mp4?time=1709819603941">https://goalvow.com/upskilling/pluginfile.php/748/mod_label/intro/5_Prospecting.mp4?time=1709819603941</video>&nbsp;<br></p></div>' WHERE slug = 'module-8-prospecting-lesson-5-effective-warm-calling-in-sales';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/749/mod_label/intro/6_Prospecting.mp4?time=1709819635050">https://goalvow.com/upskilling/pluginfile.php/749/mod_label/intro/6_Prospecting.mp4?time=1709819635050</video>&nbsp;<br></p></div>' WHERE slug = 'module-8-prospecting-lesson-6-connecting-with-prospects-through-social-selling';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Create a consistent schedule.&nbsp;</strong>Successful prospecting takes consistency and perseverance. To stay on track, develop a weekly plan that allows time for refining your target list, researching potential buyers, and reaching out regularly.</li></ul><p></p><ul><li><strong>Track your progress.&nbsp;</strong>Success is about trial and error, so get in the habit of recording your results. How many times did you contact prospect A before they answered? What outreach methods did you use? What about prospect B, C, and D? Record your results, and you can create the perfect outreach plan for you.&nbsp;</li></ul><p></p><p></p><ul><li><strong>Never stop analyzing.&nbsp;</strong>Studying your competition isn’t a one-time event. New competitors will continue to pop up—and minor threats may adjust their positioning and become significant contenders. Don’t get sideswiped by market changes. Reevaluate your competition regularly and continue refining your sales strategy, so you stand out in the crowd.&nbsp;</li></ul><p></p><ul><li><strong>Practice, practice, practice.&nbsp;</strong>Perfecting the cold call process takes time. Don’t get discouraged if you stumble over your words or hear more than a few “no thanks” responses. The more you practice, the better you’ll get. So, practice in front of a mirror, ask a friend to answer a few fake calls, and keep dialing potential customers.</li></ul><p></p><ul><li><strong>Pretend that you’re calling a friend.&nbsp;</strong>Since sales is about building relationships, one of the best ways to connect is to use a personable, casual tone. Pretend that you’re reaching out to a friend in your next call. Smile when you talk, establish reliability, and—if you feel comfortable—reveal a sense of humor.</li></ul><p><ul><li><strong>Take small steps every day.&nbsp;</strong>Relationships don’t form overnight. Trust takes time—and you won’t become a reliable expert instantly. So, take small steps in your social selling journey. Focus on little wins and forge genuine connections. Once you get going, you’ll start seeing results over time.</li></ul></p><p></p></div>' WHERE slug = 'module-8-prospecting-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Understand </strong>why people buy</li><li><strong>Know-how </strong>to succeed in sales as an Introvert</li><li><strong>Know-how </strong>to deal with rejection</li><li><strong>Know-how </strong>to use body language to win more sales</li><li><strong>Master</strong> the capability of selling to different personality types</li><li><strong>Manage </strong>stress as a salesperson</li></ul><p></p></div>' WHERE slug = 'module-3-sales-psychology-learning-outcome';
