UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/753/mod_label/intro/6_Sales%20Psychology.mp4?time=1709818111517">https://goalvow.com/upskilling/pluginfile.php/753/mod_label/intro/6_Sales%20Psychology.mp4?time=1709818111517</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-sales-psychology-lesson-6-managing-stress-as-a-salesperson';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>No matter what, don’t stretch the truth just to make a sale.&nbsp;</strong>Understanding buyer psychology is useful when your product or service fits a customer’s needs. But it’s irrelevant if what you’re selling wouldn’t meet the buyer’s real need.&nbsp;</li></ul><p></p><ul><li><strong>Get out of your comfort zone occasionally.&nbsp;</strong>That doesn’t mean forcing yourself to become someone you’re not. However, there’s value in expanding your horizons by practicing skills that don’t come naturally to you.</li></ul><p></p><ul><li><strong>Think like a champion.</strong>&nbsp;Is there a sports figure you admire? Or someone else you respect who embodies resilience? When champions fall, they brush it off and get back up. So, the next time someone rejects you, do the same—get back in the game.</li></ul><p></p><ul><li><strong>Get comfortable.&nbsp;</strong>Communicating nonverbally may not come easily at first. Practice until it feels natural to use open hand gestures, nod frequently, and close wide physical gaps when speaking to others. You’ll be an expert in body language before you know it.</li></ul><p></p><ul><li><strong>Which style is the most challenging?&nbsp;</strong>Certain styles are more likely to clash than others. Identify the style that is the most difficult for you to mirror. Give extra attention to that style and practice until it feels comfortable.</li></ul><p><ul><li><strong>Don’t wait until the breaking point.&nbsp;</strong>Even if you don’t feel super stressed right now, take stock of your daily routine. What are some ways you can reduce some pressures? Take steps now to avoid a critical mass that can become unmanageable down the road.</li></ul></p><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-3-sales-psychology-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>After completing this module, you will be able to:&nbsp;</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Know-how </strong>to qualify sales leads using BANT framework</li><li><strong>Understand </strong>potential buyer\'s needs</li><li><strong>Know-how </strong>to build trust with potential buyers</li><li><span>Have the </span><strong>capability</strong> implement consultative selling</li><li><strong>Leverage </strong>decision markers, influencers and gatekeepers</li><li><strong>Develop</strong>&nbsp;emotional intelligence in sales</li><li><strong>Implement </strong>transparency in building relationships and boost</li></ul><p></p></div>' WHERE slug = 'module-5-building-relationships-learning-outcome';
