UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>What do I do with unqualified leads?</strong>&nbsp;If a contact’s needs seem like they won’t ever align, you can refer them to another company or solution. But if the contact has the potential to<em>&nbsp;become qualified</em>&nbsp;over time, then feed them back into your lead nurturing cycle until the time is right.</li></ul><p></p><ul><li><strong>Ask why.</strong>&nbsp;Sometimes a potential buyer may struggle to communicate the root of their needs. For example, they might say they have a specific requirement (such as a five-star user rating)—which is actually the symptom of a deeper underlying need (dependability). In these cases, it helps to ask,&nbsp;<em>“Why?”&nbsp;</em>For example, “<em>Why is a five-star user rating important to you?”</em></li></ul><p></p><ul><li><span><strong style="">Prepare your questions.&nbsp;</strong>A handy list of common questions you can use to get to know prospective customers will help you remember what to ask when you’re talking with someone.</span></li></ul><p></p><ul><li><strong>Go above and beyond to help potential buyers</strong>. Extraordinary customer service can set your company apart and demonstrate your genuine desire to add value to their buyer’s journey.</li></ul><p></p><ul><li><strong>Be authentic.</strong>&nbsp;Express genuine curiosity about the prospective customer’s situation. Strike a conversational tone and beware of coming across as disingenuous or overeager to sell.</li></ul><p></p><ul><li><strong>Call early or late.&nbsp;</strong>Executives are often the first people to arrive at the office—and the last to leave. You might catch them answering phones directly if you call before or after standard working hours. &nbsp;</li></ul><p></p><ul><li><span><strong>Accept responsibility for your sales outcomes.&nbsp;</strong>Emotionally intelligent salespeople don’t blame poor outcomes on the prospective customer or situation. Instead, they look inward and brainstorm ways that&nbsp;they&nbsp;can do better.&nbsp;</span></li></ul><p></p><ul><li><strong style="">Ditch aggressive selling techniques.</strong>&nbsp;No one likes to feel like they’ve been swindled into a sale. Avoid scare tactics, manipulative phrasing, or bullying.</li></ul><p></p><p></p><p></p><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-5-building-relationships-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>what is Change Management</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to analyze the change impact</li><li><strong>Know-how&nbsp;</strong>to get sponsorship and buy-in for change</li><li><strong>Know-how&nbsp;</strong>to implement project changes</li></ul><br><p></p></div>' WHERE slug = 'module-8-project-change-management-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2080/mod_resource/content/2/Change%20Management%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Change Management Course Material.pdf</a></p>' WHERE slug = 'module-8-project-change-management-module-reading-material';
