UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/764/mod_label/intro/2_Change%20Management.mp4">https://goalvow.com/upskilling/pluginfile.php/764/mod_label/intro/2_Change%20Management.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-8-project-change-management-lesson-2-how-to-analyze-change-impact';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/765/mod_label/intro/3_Change%20Management.mp4">https://goalvow.com/upskilling/pluginfile.php/765/mod_label/intro/3_Change%20Management.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-8-project-change-management-lesson-3-getting-sponsorship-and-buy-in-for-change';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/766/mod_label/intro/4_Change%20Management.mp4">https://goalvow.com/upskilling/pluginfile.php/766/mod_label/intro/4_Change%20Management.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-8-project-change-management-lesson-4-how-to-implement-project-changes';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><b>Summary</b></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Don’t skip any steps.</strong>&nbsp;It’s tempting to jump ahead when implementing change. But if steps are skipped, and changes aren’t well-thought-out, you risk being worse off than when you originally started. Take the time to follow every process step, and you’ll improve your chances of success.</li></ul><p></p><ul><li><strong>Don’t skip the impact analysis.&nbsp;</strong>All these steps may seem time-consuming (especially when you’re busy), but they’re worth the extra attention. If you skip the impact analysis, you open the door to surprises that could disrupt your entire project. Invest the time today, and you’ll save even more time tomorrow.</li></ul><p></p><ul><li><strong>Maintain consistent communication.&nbsp;</strong>Communication is your most powerful tool. As a best practice, don’t want until there’s a change to start the dialogue. Maintain consistent communication throughout your project, and you’ll already have engaged stakeholders you can turn to for sponsorship and buy-in.</li></ul><p><ul><li><strong>Review. Revise. Improve.&nbsp;</strong>Change doesn’t stop once it’s approved. You must continue to review changes even after they’ve been implemented. Revise what’s not working. Make improvements. Drive your project toward it’s desired outcomes by continuing to evaluate what’s working and what isn’t.</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-8-project-change-management-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Know-why </strong>communication is important in project management</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to communicate successfully during in projects</li><li><strong>Know-how&nbsp;</strong>to choose communication methods and tools</li><li><strong>Put </strong>together a communication plan</li><li><strong>Organize and lead </strong>effectively in project meetings</li></ul><br><p></p></div>' WHERE slug = 'module-3-project-communication-learning-outcome';
