UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/769/mod_label/intro/3_Project%20Communication.mp4">https://goalvow.com/upskilling/pluginfile.php/769/mod_label/intro/3_Project%20Communication.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-project-communication-lesson-3-choosing-your-communication-methods-and-tools';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/770/mod_label/intro/4_Project%20Communication.mp4">https://goalvow.com/upskilling/pluginfile.php/770/mod_label/intro/4_Project%20Communication.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-project-communication-lesson-4-putting-together-a-communication-plan';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/771/mod_label/intro/5_Project%20Communication.mp4">https://goalvow.com/upskilling/pluginfile.php/771/mod_label/intro/5_Project%20Communication.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-project-communication-lesson-5-organizing-and-leading-effective-project-meetings';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Set yourself up for success.&nbsp;</strong>Before your next project, set yourself up for success by encouraging everyone to share their thoughts and ask questions. Make sure your team understands what you expect of them. Then, as the project progresses, don’t close anyone out. Keep communication constant. It’s the key to success.</li></ul><p></p><ul><li><strong>You set the tone.&nbsp;</strong>As the project manager, you set the tone. Lead by example by encouraging your team and stakeholders to share their thoughts, ideas, and concerns. Be the type of manager who sets the right environment of honesty, respect, and collaboration, and others will follow.</li></ul><p></p><ul><li><strong>How important is your message?&nbsp;</strong>When considering the best method and tool for your situation, ask yourself: How important is this message? If my receiver doesn’t read it, will that negatively impact the project? Only use the pull method when you can answer no to that question. Remember, even if you don’t need the person to take action, you might still need them to acknowledge the information.</li></ul><p></p><p></p><ul><li><strong>Different plans for different projects.&nbsp;</strong>Different projects, people, and tasks demand different types of communication. Larger projects may require more structure than smaller projects. Your plan can be as simple or as detailed as it needs to be. But no matter the scope of your next project, remember: a plan must be made.</li></ul><p><ul><li><strong>Always follow the agenda.&nbsp;</strong>Meetings aren’t always as productive as we’d like them to be. Discussions get off topic, team members rehash the same points, and time gets wasted. The best way to manage these negative dynamics is to follow your agenda. Every discussion should lead to action. If it doesn’t, it’s up to you to redirect the conversation toward the agenda.</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-3-project-communication-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>project management framework</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to choose correct framework foreach project<br></li><li><strong>Implement </strong>critical path and critical chain project management</li><li><strong>Differentiate </strong>between Kanban and Scrum</li><li><strong>Choose </strong>the right project management framework</li></ul><br><br><p></p></div>' WHERE slug = 'module-2-project-frameworks-learning-outcome';
