UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/775/mod_label/intro/4_Project%20Framework.mp4">https://goalvow.com/upskilling/pluginfile.php/775/mod_label/intro/4_Project%20Framework.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-project-frameworks-lesson-4-kanban-vs-scrum';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/776/mod_label/intro/5_Project%20Framework.mp4">https://goalvow.com/upskilling/pluginfile.php/776/mod_label/intro/5_Project%20Framework.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-project-frameworks-lesson-5-choosing-the-right-project-management-framework';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Give it time.&nbsp;</strong>Some project management frameworks require more time to learn than others. Give yourself time to learn a framework, and then train your team. You will likely experience some level of trial and error along the way. Learn from your mistakes, and look for new ways to refine your process on every project. The framework will eventually become second nature.</li></ul><p></p><ul><li><strong>Consider your project needs.&nbsp;</strong>Consider the unique nature and requirements of your project to help decide if Waterfall, Agile, or Lean are for you. If none of these frameworks fit the bill, then head online and research the many alternative frameworks out there.</li></ul><p></p><p></p><ul><li><strong>Work backward.&nbsp;</strong>Even though it makes sense to start from the beginning when defining project tasks, it’s actually more helpful to start from the end of a project when developing your schedule. Start with the project’s deadline and work backward from there.&nbsp;</li></ul><p></p><ul><li><strong>Make your board visible.</strong>&nbsp;Whether you’re using a Kanban board or a Scrum task board, make it highly visible for your team. Tack it on a whiteboard or wall in the center of the office. Or, make it a virtual board if your team is more likely to see and use it online. Choose a place for your board that is most likely to be seen and used on a daily basis.&nbsp;</li></ul><p></p><p><ul><li><strong>Revisit your choice periodically.&nbsp;</strong>Projects change. Organizational goals, structure, and environmental factors may shift from time to time. It’s a good idea to also revisit your project management framework choices from time to time to make sure you still have the right fit.</li></ul><p><br></p></p><p></p><p></p></div>' WHERE slug = 'module-2-project-frameworks-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>fundamentals of project management</li><li><strong>Execute </strong>each of the four phases of project management effectively</li><li><strong>Know-how&nbsp;</strong>to write a business case for the project</li><li><span>Have the </span><strong>capability</strong> to create a project plan</li><li><strong>Implement </strong>strategies to increase team effectiveness</li><li><strong>Know-how </strong>to close a project</li></ul><br><p></p></div>' WHERE slug = 'module-1-project-management-fundamentals-learning-outcome';
