UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/780/mod_label/intro/4_Project%20Management%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/780/mod_label/intro/4_Project%20Management%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-project-management-fundamentals-lesson-4-how-to-create-a-project-plan';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/781/mod_label/intro/5_Project%20Management%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/781/mod_label/intro/5_Project%20Management%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-project-management-fundamentals-lesson-5-strategies-for-increasing-team-effectiveness';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/782/mod_label/intro/6_Project%20Management%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/782/mod_label/intro/6_Project%20Management%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-project-management-fundamentals-lesson-6-closing-a-project';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Research project management frameworks.&nbsp;</strong>You do not need to reinvent the wheel when it comes to project management. There are various project management frameworks and methodologies that have been tested and standardized by project managers across industries. Research and study the different approaches to project management. Choose the best fit for your team and project.</li></ul><p></p><ul><li><strong>Set yourself up for success.&nbsp;</strong>Allot more time in the project planning phase to save time and prevent headaches in the execution and monitoring phase. The more clarity you have on the project details, priorities, and risks up front, the better defense you’ll have against surprises and setbacks down the line.</li></ul><p></p><ul><li><strong>Use it as a reference.&nbsp;</strong>A business case does not become obsolete after a project is approved. Refer back to the business case anytime changes are made to a project. Update the business case with any agreed-upon changes for your records. Or, you may use a business case to argue against changes that don’t align with the project’s original purpose.</li></ul><p></p><ul><li><strong>What’s missing?&nbsp;</strong>When reviewing your project plan, always ask yourself and your team: What’s missing? Are there any deliverables that have not been defined? Are there gaps in the plan or tasks missing to complete the project? What resources haven’t you accounted for? And what risks haven’t you considered?</li></ul><p></p><ul><li><strong>Track your team’s rime.&nbsp;</strong>Track your team’s time on a project and use the data to help you predict your next project schedule more accurately. Just make sure to communicate to team members that the purpose of time-tracking is to make better time estimations—not scrutinize their working speed!&nbsp;</li></ul><p><ul><li><strong>Celebrate!&nbsp;</strong>As you close a project, don’t forget to acknowledge your project team and reward them for a job well done. Recognizing and celebrating your team’s success is integral to building team morale and retention.</li></ul></p><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-1-project-management-fundamentals-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>mistakes to avoid in project management</li><li><strong>Know-how</strong>&nbsp;seek client feedback</li><li><strong>Know-how&nbsp;</strong>to conduct a post-implementation review</li><li><strong>Implement </strong>a continuous project management improvement</li></ul><br><p></p></div>' WHERE slug = 'module-7-project-improvement-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2079/mod_resource/content/2/Project%20Improvement%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Project Improvement Course Material.pdf</a></p>' WHERE slug = 'module-7-project-improvement-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/783/mod_label/intro/1_Project%20Improvement.mp4">https://goalvow.com/upskilling/pluginfile.php/783/mod_label/intro/1_Project%20Improvement.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-project-improvement-lesson-1-five-project-management-mistakes-to-avoid';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/784/mod_label/intro/2_Project%20Improvement.mp4">https://goalvow.com/upskilling/pluginfile.php/784/mod_label/intro/2_Project%20Improvement.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-project-improvement-lesson-2-seeking-client-feedback';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/785/mod_label/intro/3_Project%20Improvement.mp4">https://goalvow.com/upskilling/pluginfile.php/785/mod_label/intro/3_Project%20Improvement.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-project-improvement-lesson-3-how-to-conduct-a-post-implementation-review';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/786/mod_label/intro/4_Project%20Improvement.mp4">https://goalvow.com/upskilling/pluginfile.php/786/mod_label/intro/4_Project%20Improvement.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-project-improvement-lesson-4-continuous-project-management-improvement';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Resolving issues.&nbsp;</strong>While it’s best to avoid these mistakes altogether, don’t panic if you’ve already made one or two of them. Instead, go back. See if there’s an implementation step you missed. Remember the tools and techniques you have at your disposal and focus on resolving the issue as quickly as possible.</li></ul><p></p><ul><li><strong>Focus on what you can do, not what you can’t.&nbsp;</strong>Another strategy for challenging client requests is to focus on what you can do instead of what you can’t. Offer a better or alternative option that still addresses the client’s problem.</li></ul><p></p><ul><li><strong>Send your client a post-project feedback survey.&nbsp;</strong>Consider sending your client a survey or questionnaire after the project is over with a few simple questions such as,&nbsp;<em>“In what areas did we meet or exceed your expectations?”&nbsp;</em>and&nbsp;<em>“In what areas could we improve?”</em>&nbsp;A post-project survey will help you improve how you handle projects in the future.</li></ul><p></p><ul><li><strong>Put it into practice.&nbsp;</strong>A PIR is only meaningful if you implement the recommendations and lessons that you learned. So, put it into practice. Review your findings before the next project and make the relevant changes. &nbsp;</li></ul><p><ul><li><strong>Create a culture of continuous improvement.&nbsp;</strong>Continuous improvement can breathe life, energy, and excitement into your team. It opens the door to new ideas and innovation. Embrace this practice in your project team culture. Encourage them to share pain points and brainstorm new approaches. You might even try challenging your project team to identify one change or tweak they can make at the end of every week.</li></ul></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-7-project-improvement-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>project scheduling</li><li><strong>Define</strong> deliverables and activities</li><li><strong>Know-how&nbsp;</strong>to estimate time accurately&nbsp;&nbsp;</li><li><strong>Differentiate </strong>task dependencies</li><li><span>Have the </span><strong>capability&nbsp;</strong>to create a resource plan</li><li><strong>Implement </strong>project scheduling techniques&nbsp;</li></ul><br><br><p></p></div>' WHERE slug = 'module-4-project-scheduling-learning-outcome';
