UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/789/mod_label/intro/3_Project%20Scheduling.mp4">https://goalvow.com/upskilling/pluginfile.php/789/mod_label/intro/3_Project%20Scheduling.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-project-scheduling-lesson-3-how-to-estimate-time-accurately';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/790/mod_label/intro/4_Project%20Scheduling.mp4">https://goalvow.com/upskilling/pluginfile.php/790/mod_label/intro/4_Project%20Scheduling.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-project-scheduling-lesson-4-four-types-of-task-dependencies';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/791/mod_label/intro/5_Project%20Scheduling.mp4">https://goalvow.com/upskilling/pluginfile.php/791/mod_label/intro/5_Project%20Scheduling.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-project-scheduling-lesson-5-how-to-create-a-resource-plan';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/792/mod_label/intro/6_Project%20Scheduling.mp4">https://goalvow.com/upskilling/pluginfile.php/792/mod_label/intro/6_Project%20Scheduling.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-project-scheduling-lesson-6-project-scheduling-techniques';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><ul><li><strong>Hold a scheduling team meeting.&nbsp;</strong>One of the most challenging steps in developing your project schedule is estimating task durations, especially when you don’t have any experience with the tasks yourself. Schedule a meeting with your project team and ask for their input. You’ll likely get a more realistic idea of how long a task will take. You can also account for timing conflicts like vacation days or competing deadlines for other projects.</li></ul><p></p><ul><li><strong>Use verbs for activities and nouns for deliverables.&nbsp;</strong>Project activities are action items, whereas project deliverables are outcomes. So, use verbs when listing project activities and nouns for listing tangible project deliverables.</li></ul><p></p><ul><li><strong>Create a time log.&nbsp;</strong>No matter which time estimation technique you use, you can empower your team to make more accurate time estimates by creating a time log. Set up a system or live timer to have team members track how long tasks take to complete. Start building a history of the actual hours it takes to complete a project, and use that information as a forecasting tool for future projects.</li></ul><p></p><ul><li><strong>Communicate task dependencies to your team.&nbsp;</strong>Identify who is responsible for completing each task and make sure to communicate any critical task dependencies to them. Knowledge is power. By telling your team how tasks interact and impact the work that others are doing, you encourage them to take a deadline seriously and bring up project threats early.</li></ul><p></p><ul><li><strong>Encourage time blocking.&nbsp;</strong>Encourage your team members to share calendars, block out unavailable time, and block out the hours they’re working on a project. That will help you avoid scheduling team members while they’re in meetings or out of the office, and it will help them protect their time and get their project hours in.</li></ul><p></p><p></p><p><ul><li><strong>Review and update your project schedule as often as possible.&nbsp;</strong>The best way to keep your project on track is to closely monitor a project’s progress and keep your project schedule updated. Check in with project team members often and address scheduling issues immediately.</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-4-project-scheduling-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand</strong>&nbsp;project reporting</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to write a project status report</li><li>Have the <strong>capability </strong>to control costs through budgeting, tracking and reporting</li><li><strong>Know-how&nbsp;</strong>to manage and report risk</li><li><strong>Know-how </strong>to use quality management techniques</li><li><strong>Apply </strong>best practices for choosing key performance indicators</li></ul><br><br><p></p></div>' WHERE slug = 'module-6-project-reporting-learning-outcome';
