UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/794/mod_label/intro/2_Project%20Reporting.mp4">https://goalvow.com/upskilling/pluginfile.php/794/mod_label/intro/2_Project%20Reporting.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-project-reporting-lesson-2-writing-a-project-status-report';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/980/mod_label/intro/3_Project%20Reporting.mp4">https://goalvow.com/upskilling/pluginfile.php/980/mod_label/intro/3_Project%20Reporting.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-project-reporting-lesson-3-controlling-costs-through-budgeting-tracking-and-reporting';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/795/mod_label/intro/4_Project%20Reporting.mp4">https://goalvow.com/upskilling/pluginfile.php/795/mod_label/intro/4_Project%20Reporting.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-project-reporting-lesson-4-managing-and-reporting-risks';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/796/mod_label/intro/5_Project%20Reporting.mp4">https://goalvow.com/upskilling/pluginfile.php/796/mod_label/intro/5_Project%20Reporting.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-project-reporting-lesson-5-quality-management-tools-and-techniques';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/797/mod_label/intro/6_Project%20Reporting.mp4">https://goalvow.com/upskilling/pluginfile.php/797/mod_label/intro/6_Project%20Reporting.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-project-reporting-lesson-6-best-practices-for-choosing-key-performance-indicators';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Get familiar with different reports.&nbsp;</strong>There are several types of project reports, and the best project managers will familiarize themselves with all of them. That way, you can effectively monitor progress and make informed, fact-based decisions.&nbsp;</li></ul><p></p><ul><li><strong>Keep it short and simple.&nbsp;</strong>There’s a lot of information that goes into a status report, but do your best to avoid long narratives. By limiting your report to four sections and keeping the text concise, it’s less likely that crucial information will be missed. Remember, a status report is a snapshot, not an essay.</li></ul><p></p><ul><li><strong>Be wary of positive cost variances.&nbsp;</strong>Often, project managers worry about being over budget when identifying deviations. But remember to consider all variances—both positive and negative. While being under budget might be the result of a savvy cost-saving measure, it could also mean that you’re the victim of schedule lag or ineffective estimates.</li></ul><p></p><ul><li><strong>Always stick to the plan.&nbsp;</strong>Creating a consistent risk management plan saves you time and effort down the road. Don’t break the wheel. Each time you start a new project, follow the seven-step process, and you’ll be more likely to address risks properly and prevent issues.</li></ul><p></p><p></p><ul><li><strong>Simple. Clear. Straightforward.&nbsp;</strong>Charts and graphs should be as simple and clear as possible. Too much detail can get confusing. Keep it straightforward. Your tools should speak for themselves. If you have to explain what’s happening, the tool isn’t doing its job.</li></ul><p><ul><li><strong>KPIs aren’t rigid.&nbsp;</strong>As projects change, so too do KPIs. If you find that certain KPIs hold less significance as your project moves along, don’t hesitate to remove them and add new ones. Continue to develop SMART KPIs that provide a deeper understanding of your project.</li></ul></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-6-project-reporting-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>scope management</li><li><strong>Know-what </strong>project requirements are and how to collect them</li><li><strong>Know-how&nbsp;</strong>to define and document scope</li><li><strong>Know-how&nbsp;</strong>to create a Work Breakdown Structure (WBS)</li><li><strong>Address </strong>scope creep</li><li><strong>Implement</strong>&nbsp;best practices for effective scope management</li></ul><br><br><p></p></div>' WHERE slug = 'module-5-project-scope-management-learning-outcome';
