UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/800/mod_label/intro/3_Project%20Scope%20Management.mp4">https://goalvow.com/upskilling/pluginfile.php/800/mod_label/intro/3_Project%20Scope%20Management.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-project-scope-management-lesson-3-defining-and-documenting-project-scope';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/801/mod_label/intro/4_Project%20Scope%20Management.mp4">https://goalvow.com/upskilling/pluginfile.php/801/mod_label/intro/4_Project%20Scope%20Management.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-project-scope-management-lesson-4-how-to-create-a-work-breakdown-structure';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/802/mod_label/intro/5_Project%20Scope%20Management.mp4">https://goalvow.com/upskilling/pluginfile.php/802/mod_label/intro/5_Project%20Scope%20Management.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-project-scope-management-lesson-5-addressing-scope-creep';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/803/mod_label/intro/6_Project%20Scope%20Management.mp4">https://goalvow.com/upskilling/pluginfile.php/803/mod_label/intro/6_Project%20Scope%20Management.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-project-scope-management-lesson-6-tips-for-effective-scope-management';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Communicate how costs often increase with time.&nbsp;</strong>Adding new features or implementing changes to project scope often become more difficult and costly the later they’re submitted. Communicate this relationship to your client. The earlier you can catch scope changes, the easier they are to implement. The later you submit a change during a project’s execution, the more complex and expensive the changes—and your project—may become.</li></ul><p></p><ul><li><strong>Create a prototype.&nbsp;</strong>For some projects, it may be helpful to create a prototype or sample of the project to gather your client’s or customer’s initial thoughts, feedback, and requirements.</li></ul><p></p><ul><li><strong>Start by asking the right questions.&nbsp;</strong>If you find yourself struggling to articulate the project scope, then you might not have taken enough time to talk to your client and deeply understand their needs, goals, and expectations for the project. Set up a meeting to explore together what a project does and doesn’t include. Ask targeted questions to find out how your client defines the success or failure of a project.</li></ul><p></p><ul><li><strong>Organize a brainstorming session.&nbsp;</strong>Set up a brainstorming session with your project team or key stakeholders to make sure you break down all of the deliverables required to complete your project.</li></ul><p></p><ul><li><strong>If you can’t beat it, expect it.&nbsp;</strong>Scope creep is common. If you find that many of your projects suffer from scope creep, expect it and embrace it in your project plans. Increase your costs or add a buffer to your timeline to leave room for scope creep.</li></ul><p><ul><li><strong>Add a buffer.&nbsp;</strong>Changes to project scope are often inevitable. But that doesn’t mean you have to let change ruin your project plans. Add a buffer to your project budget, timeline, or other resources from the start. That way, you can say “yes” to more project changes without hurting your team, project, or profits in the process.</li></ul></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-5-project-scope-management-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>types of customer service channels</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to write outstanding customer emails</li><li><strong>Know-how&nbsp;</strong>to talk to customers on live chat</li><li><strong>Know-how&nbsp;</strong>to support customers on social media</li><li><strong>Master </strong>customer service phone calls</li><li><strong>Implement </strong>channel switching in customer service</li></ul><br><br><p></p></div>' WHERE slug = 'module-4-customer-communication-channels-learning-outcome';
