UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/810/mod_label/intro/7_Customer%20Communicatiom%20Channels.mp4">https://goalvow.com/upskilling/pluginfile.php/810/mod_label/intro/7_Customer%20Communicatiom%20Channels.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-customer-communication-channels-lesson-7-successful-channel-switching-in-customer-service';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Practice consistency. </strong>Regardless of which channel you use to interact with customers, remember to\r\nprovide consistent service across all platforms. Your email service quality should be just as stellar as the\r\nservice you provide over the phone, on-site, or via chat.</li></ul><p></p><ul><li><strong>Don’t forget to follow up.</strong> Whether the customer responds or not, send a follow-up email to show that\r\nyou’re still available to answer questions. Prompting customers this way can leave a positive impression\r\neven if you don’t hear back.</li></ul><p></p><ul><li><strong>Shortcuts are your best friend.</strong> Create keyboard shortcuts for common responses to save yourself some\r\ntime. You can always add small variations to the auto-filled text to customize interactions.</li></ul><p></p><ul><li><strong>Beware of trolls.</strong> Not every complaint will be genuine. “Trolls” seek to sow chaos and discord online. To\r\ndetermine if someone might be a troll, scroll through their comment history. If everything they post is&nbsp;negative, chances are they’re a troll.</li></ul><p></p><ul><li><strong>Create a dedicated social media account for customer service.</strong> To facilitate ticket management or\r\ndelegation of responsibilities between different departments, consider creating a separate social media\r\naccount dedicated solely to customer service, alongside your brand’s main account.</li></ul><p></p><p></p><ul><li><strong>Practice makes perfect.</strong> It’s normal to struggle with certain aspects of speaking with customers over the\r\nphone. Practicing will help you identify the skills you need to build and refine. Take time to rehearse&nbsp;your phone skills to prepare for when you do speak to a customer.</li></ul><p></p><ul><li><strong>Self-service is essential to omnichannel customer service.</strong> Creating self-service options like blog posts\r\nand video tutorials is an effective way to provide immediate service to customers. If possible, consider\r\ndeveloping an array of self-service solutions for your customers.</li></ul><p><ul><li><strong>Examine the customer journey.</strong> Refer to your conversations with customers to gain deeper insight into\r\nyour channel switching strategies. Are some channels more effective than others? Do your customers\r\nprefer one channel over another? Use this information to find and fix gaps in the customer journey.</li></ul></p><p></p><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-4-customer-communication-channels-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Know-how </strong>to communicate effectively with customers</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to personalize customer interactions to build rapport</li><li><strong>Know-how&nbsp;</strong>to have active listening in customer service</li><li><strong>Respond </strong>to customer feedback&nbsp;</li><li><strong>Express</strong>&nbsp;empathy in customer service</li><li><strong>Know-when </strong>to end customer service conversations</li></ul><br><br><p></p></div>' WHERE slug = 'module-3-customer-communication-basics-learning-outcome';
