UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/817/mod_label/intro/7_Customer%20Communicatiom%20Basics.mp4">https://goalvow.com/upskilling/pluginfile.php/817/mod_label/intro/7_Customer%20Communicatiom%20Basics.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-customer-communication-basics-lesson-7-ending-customer-service-conversations';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Respect goes both ways.</strong> Remember that respect applies to you as well. Some people simply will not\r\naccept your answers, and you have no obligation to put up with mistreatment or abuse. Ask for help,\r\nand take care of yourself!</li></ul><p></p><ul><li><strong>Customer service is within your control.</strong> You can’t manage your customers’ experience with other\r\nbrands, but you can control how they see you and your business. A friendly, thoughtful experience will\r\nencourage your customers to keep coming back for more.</li></ul><p></p><ul><li><strong>Reflect on your conversations.</strong> Self-reflection is a great tool for improving your active listening. The\r\nnext time you work with a customer, reflect on the interaction when you’ve finished. Did anything\r\ndistract you? Did you jump to any conclusions? Get to know your disrupting patterns, and you’ll take\r\nthe first step toward breaking them.</li></ul><p></p><ul><li><strong>What if the customer doesn’t want help?</strong> Even the best greetings won’t work all the time. If a customer\r\nsays, “I’m fine,” or “No thanks,” offer a courteous reply, and then give them their space. Some polite\r\nresponses include: “You got it! Let me know if you change your mind,” or “Absolutely! Just flag me down if you\r\nneed anything.”</li></ul><p></p><ul><li><strong>Imagine you’re greeting a friend. </strong>How would you say “hello” to a close friend? Would you speak formally,\r\nor would you be more personable? Treat customers the same way. Speak naturally and be attentive. That\r\napproach will go a long way toward improving a customer’s experience.</li></ul><p></p><ul><li><strong>Sometimes, parting ways makes sense.</strong> No solution works for everyone. Your goal is to make a customer’s\r\nexperience the best it can be. So, if a customer believes your product or solution isn’t for them, let them\r\ngo. You did your part in listening and responding with empathy.</li></ul><p></p><ul><li><strong>Is it empathy?</strong> If you’re unsure whether you’re showing empathy or sympathy, ask yourself: “Am I relating\r\nto this emotion or experience? Do I understand the feeling?” If you can experience the moment alongside them,\r\nthen you’re demonstrating empathy.</li></ul><p><ul><li><strong>Maintain a positive tone.</strong> A customer might forget your conversation’s details, but they won’t forget the\r\nimpression you made. So, maintain a positive, caring tone as you follow the above steps. You want\r\ncustomers to have memorable experiences that keep them coming back.</li></ul></p><p></p><p></p><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-3-customer-communication-basics-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>why cultural sensitivity matters in customer service</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to deliver exceptional customer service across cultures</li><li><strong>Know-how&nbsp;</strong>to communicate with cross-cultural customers</li><li><strong>Know-how&nbsp;</strong>to confront cultural bias in customer service</li></ul><br><p></p></div>' WHERE slug = 'module-6-culture-sensitivity-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2063/mod_resource/content/2/Cultural%20Sensitivity%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Cultural Sensitivity Course Material.pdf</a></p>' WHERE slug = 'module-6-culture-sensitivity-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/818/mod_label/intro/1_Culture%20Sensitivity.mp4">https://goalvow.com/upskilling/pluginfile.php/818/mod_label/intro/1_Culture%20Sensitivity.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-culture-sensitivity-lesson-1-why-cultural-sensitivity-matters-in-customer-service';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/819/mod_label/intro/2_Culture%20Sensitivity.mp4">https://goalvow.com/upskilling/pluginfile.php/819/mod_label/intro/2_Culture%20Sensitivity.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-culture-sensitivity-lesson-2-delivering-exceptional-customer-service-across-cultures';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/820/mod_label/intro/3_Culture%20Sensitivity.mp4">https://goalvow.com/upskilling/pluginfile.php/820/mod_label/intro/3_Culture%20Sensitivity.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-culture-sensitivity-lesson-3-communicating-with-cross-cultural-customers';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/821/mod_label/intro/4_Culture%20Sensitivity.mp4?time=1709800248293">https://goalvow.com/upskilling/pluginfile.php/821/mod_label/intro/4_Culture%20Sensitivity.mp4?time=1709800248293</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-culture-sensitivity-lesson-4-confronting-cultural-bias-in-customer-service';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Developing cultural sensitivity is an ongoing effort. </strong>It’s not a one-time event. Treat this lesson as a\r\nstarting point for ongoing research, learning, self-evaluation, and conversation.</li></ul><p></p><ul><li><strong>Observe and follow the customer’s lead.</strong> Simply knowing about and celebrating cultural differences will\r\nboost your competence as a customer service professional. So, don’t stress if you’re unsure of a customer’s\r\ncultural norms or preferences. Take your cues from the customer on communication style, body\r\nlanguage, and behaviors, then follow their lead</li></ul><p></p><ul><li><strong>Be supportive. </strong>Cross-cultural communication seeks to make all parties feel comfortable. Approach cross cultural communications with an attitude of encouragement, patience, and sensitivity. Always treat&nbsp;customers with respect.</li></ul><p><ul><li><strong>Check your affinity bias.</strong> We tend to associate more with people who are similar to us—from the same\r\nculture, age group, or social class, for example. Notice when you feel more comfortable with certain\r\ngroups of people over others, and challenge yourself to get out of your comfort zone once in a while.</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-6-culture-sensitivity-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>why customer get upset</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to respond to an upset or abusive customer</li><li><strong>Know-how&nbsp;</strong>to give an effective customer apology</li><li><strong>Know-how&nbsp;</strong>to handle refund or cancellation requests</li><li><strong>Retain </strong>customers during times of crisis</li><li><strong>Know-how </strong>to say no to customers</li><li><strong>Master </strong>strategies for gaining control of customer conversations</li></ul><br><br><p></p></div>' WHERE slug = 'module-7-difficult-situations-learning-outcome';
