UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/984/mod_label/intro/6_Difficult%20Situations%20of%20Customer%20Service.mp4">https://goalvow.com/upskilling/pluginfile.php/984/mod_label/intro/6_Difficult%20Situations%20of%20Customer%20Service.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-difficult-situations-lesson-6-a-guide-to-saying-no-to-customers';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/985/mod_label/intro/7_Difficult%20Situations%20of%20Customer%20Service.mp4">https://goalvow.com/upskilling/pluginfile.php/985/mod_label/intro/7_Difficult%20Situations%20of%20Customer%20Service.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-difficult-situations-lesson-7-seven-strategies-for-gaining-control-of-customer-conversations';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Pause before responding to upset customers.</strong> Whether you take a deep breath or count to three, pausing\r\ncan interrupt your body’s natural “fight or flight” response to stressful situations. That gives you time to&nbsp;collect your thoughts and avoid reacting emotionally.</li></ul><p></p><ul><li><strong>Always get help if you feel unsafe.</strong> The above steps are good general rules to follow. However, if you ever\r\nfeel unsafe, end the conversation immediately—and get help. And, if you’re interacting in person, call\r\nsecurity. Your safety matters most.</li></ul><p></p><ul><li><strong>It has nothing to do with you.</strong> If you find yourself getting upset while dealing with an emotional\r\ncustomer, remind yourself: “This has nothing to do with me.” An upset customer is not the result of your\r\nfailings. Numerous factors are working outside your control. So, take a deep breath and keep your\r\nattention on protecting yourself and moving forward.</li></ul><p></p><ul><li><strong>Learn from your mistakes. </strong>Treat every mistake as a learning opportunity. What can you do to avoid\r\nsimilar mistakes in the future? How might you improve the customer experience? Continue to identify\r\nand implement ways to provide better customer service.</li></ul><p></p><ul><li><strong>Never respond to customers in anger.</strong> If you find yourself frustrated by a customer’s request, pause and\r\ncreate some emotional distance from the situation before responding. If you’re writing an email, then\r\ncome back to it later. If you’re talking with the customer on the phone or in-person, try taking a deep\r\nbreath or asking a question to give yourself a moment to collect your thoughts.</li></ul><p></p><ul><li><strong>People over profits.</strong> Research shows that customers expect companies to demonstrate care and\r\ncompassion during times of crisis. Make sure you have a plan to show customers you care and that you’re\r\nwilling to go the extra mile to reduce their stress and discomfort.</li></ul><p></p><ul><li><strong>Maintain a confident tone.</strong> As challenging as it can be, stay confident and positive while delivering your\r\nmessage. A meek, “I don’t think so,” or “I’m not sure,” will only confuse customers. Speak confidently, and\r\ncustomers will trust the validity of your “no”—which opens the door to alternative solutions.</li></ul><p><ul><li><strong>Multitask when you can.</strong> If you’re taking care of administrative or behind-the-scenes tasks on a call with\r\na customer, and those tasks don’t require a high level of mental energy, then why not let the customer\r\nkeep talking while you do your work? You can then interject once you’re ready to move on to the next\r\nstep</li></ul></p><p></p><p></p><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-7-difficult-situations-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>the fundamentals of customer service</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to balance personal and professional customer service</li><li><strong>Know-how&nbsp;</strong>to meet and exceed customer expectation</li></ul><br><br><p></p></div>' WHERE slug = 'module-1-customer-service-fundamentals-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/1956/mod_resource/content/2/Customer%20Service%20Fundamentals%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Customer Service Fundamentals Course Material.pdf</a></p>' WHERE slug = 'module-1-customer-service-fundamentals-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp; &nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/986/mod_label/intro/1_Customer%20Service.mp4">https://goalvow.com/upskilling/pluginfile.php/986/mod_label/intro/1_Customer%20Service.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-customer-service-fundamentals-lesson-1-what-is-customer-service-and-why-does-it-matter';
UPDATE lessons SET content = '<div class="no-overflow">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/824/mod_label/intro/2_Customer%20Service.mp4">https://goalvow.com/upskilling/pluginfile.php/824/mod_label/intro/2_Customer%20Service.mp4</video>&nbsp;</div>' WHERE slug = 'module-1-customer-service-fundamentals-lesson-2-balancing-personable-and-professional-customer-service';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp; &nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/825/mod_label/intro/3_Customer%20Service.mp4">https://goalvow.com/upskilling/pluginfile.php/825/mod_label/intro/3_Customer%20Service.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-customer-service-fundamentals-lesson-3-meeting-and-exceeding-customer-expectations';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Define your “good.</strong>” We can all recall negative customer service interactions. But do you remember when\r\nyou were impressed by a positive experience? What made that event “good”? Identify the elements that,\r\nin your view, set the standard for good customer service.</li></ul><p></p><ul><li><strong>Keep track of past conversations.</strong> If you work with regular customers, try jotting down what you\r\ndiscussed in the last conversation. Perhaps the customer mentioned they were training for a half-marathon or getting a new pet. Asking how their running is going or what the new pet is doing can be\r\na great way to add a personal touch to your interaction.</li></ul><p></p><ul><li><strong>Needs, wants, and expectations.</strong> While you should always strive to meet your customers’ needs and exceed\r\ntheir expectations, you may not be able to cater to all their wants. Separate your must-haves from nice-to haves to help prioritize.</li></ul><p><ul><li><strong>Expectations will differ by customer. </strong>You won’t always know exactly what each customer expects from\r\nyou. So, keep the lines of communication open so you can learn enough to establish baseline\r\nexpectations. Use those as a guide to practice going above and beyond.</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-1-customer-service-fundamentals-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Improve </strong>your customer service skills</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to work with different customer personality types</li><li><strong>Know-how&nbsp;</strong>to overcome empathy fatigue in customer service</li><li><strong>Know-how&nbsp;</strong>to troubleshoot customer issues</li></ul><br><br><p></p></div>' WHERE slug = 'module-2-customer-service-skills-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2060/mod_resource/content/2/Customer%20Service%20Skills%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Customer Service Skills Course Material.pdf</a></p>' WHERE slug = 'module-2-customer-service-skills-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/826/mod_label/intro/1_Customer%20Skills.mp4">https://goalvow.com/upskilling/pluginfile.php/826/mod_label/intro/1_Customer%20Skills.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-customer-service-skills-lesson-1-improving-your-customer-service-skills';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/827/mod_label/intro/2_Customer%20Skills.mp4">https://goalvow.com/upskilling/pluginfile.php/827/mod_label/intro/2_Customer%20Skills.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-customer-service-skills-lesson-2-four-important-skills-you-need-in-customer-service';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/828/mod_label/intro/3_Customer%20Skills.mp4">https://goalvow.com/upskilling/pluginfile.php/828/mod_label/intro/3_Customer%20Skills.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-customer-service-skills-lesson-3-working-with-different-customer-personality-types';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/987/mod_label/intro/4_Customer%20Skills.mp4">https://goalvow.com/upskilling/pluginfile.php/987/mod_label/intro/4_Customer%20Skills.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-customer-service-skills-lesson-4-overcoming-empathy-fatigue-in-customer-service';
UPDATE lessons SET content = '<div class="no-overflow">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/829/mod_label/intro/5_Customer%20Skills.mp4">https://goalvow.com/upskilling/pluginfile.php/829/mod_label/intro/5_Customer%20Skills.mp4</video>&nbsp;</div>' WHERE slug = 'module-2-customer-service-skills-lesson-5-a-guide-to-troubleshooting-customer-issues';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Mistakes are bound to happen.</strong> As you work to improve your customer service skills, don’t be surprised\r\nif you make a few mistakes along the way. Mistakes are a natural part of the growth process, and\r\naccepting them frees you to stretch outside your comfort zone.</li></ul><p></p><ul><li><strong>Other skills to add to your toolkit.</strong> Once you’ve mastered active listening, empathy, asking questions,\r\nand creativity, don’t stop there. Other useful customer service skills to build and refine include\r\ncommunication, persuasion, collaboration, patience, positivity, time management, and more.</li></ul><p></p><ul><li><strong>Other personality assessments.</strong> Like Reid and Merrill, dozens of psychologists have come up with their\r\nown versions of the Social Styles Model. The Myers-Briggs Type Indicator (MBTI) personality inventory\r\nand the Disc assessment, for example, are other frameworks for categorizing people by personality\r\ntype. Each framework has its pros and cons, so spend time exploring several to find the one that works\r\nbest for you</li></ul><p></p><ul><li><strong>Seek professional help when needed.</strong> If you suspect that your emotional strain is more than you can\r\nhandle on your own, don’t hesitate to seek professional help. A certified mental health professional can\r\nequip you with effective strategies tailored to your situation and needs.</li></ul><p><ul><li><strong>Share what you’ve learned.</strong> Don’t treat customer service issues as one-time challenges that you solve and\r\nthen forget. Instead, share your insights across departments. That way, other teams can take steps to help\r\nensure the same problems don’t come up again in the future. And, if they do, they will be easier to solve.</li></ul></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-2-customer-service-skills-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand&nbsp;</strong>how to manage a customer contact center of your team</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to create a customer service strategy that works</li><li><strong>Know how&nbsp;</strong>to empower your team to deliver great customer service.</li><li><strong>Know-how&nbsp;</strong>to measure customer service performance</li><li><strong>Implement</strong>&nbsp;processes for customer support tickets</li></ul><br><p></p></div>' WHERE slug = 'module-5-team-management-learning-outcome';
