UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/835/mod_label/intro/6_Team%20Management.mp4">https://goalvow.com/upskilling/pluginfile.php/835/mod_label/intro/6_Team%20Management.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-team-management-lesson-6-how-to-measure-customer-service-performance';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/836/mod_label/intro/7_Team%20Management.mp4">https://goalvow.com/upskilling/pluginfile.php/836/mod_label/intro/7_Team%20Management.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-team-management-lesson-7-delivering-proactive-customer-service';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/837/mod_label/intro/8_Team%20Management.mp4">https://goalvow.com/upskilling/pluginfile.php/837/mod_label/intro/8_Team%20Management.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-team-management-lesson-8-managing-customer-support-tickets';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr"></p><ul><li><span>Contact center vs. call center. Many people use these terms interchangeably, but contact centers offer&nbsp;</span><span>customers various ways to reach out for support (known as multichannel customer service). Call centers,&nbsp;</span><span>on the other hand, field phone calls only.</span></li></ul><p></p><ul><li>Should you outsource your contact center instead? If you’re short on time and resources, outsourcing your contact center may be a better option than building and maintaining an in-house team. Outsourcing can be more affordable, and it allows you to scale easily. Keep in mind, however, that the quality of customer interactions can take a hit with outsourcing. So, be sure to weigh the pros and cons of each option before moving forward.</li></ul><p></p><ul><li>View your strategy as a work in progress. No matter how confident you feel in your finished customer service strategy, always view it as a work in progress. Changing consumer demands, new competitors, and other factors can influence how your team approaches customer interactions. Be ready to pivot when needed.</li></ul><p></p><ul><li>Be your reps’ greatest cheerleader. When you advocate for your team, you activate one of the most effective empowerment methods available. Knowing that someone has your back builds confidence. So, don’t hesitate to go to bat for your reps or sing their praises across departments when appropriate.</li></ul><p></p><ul><li>Determine your acceptable churn rate. Some level of churn is normal and to be expected. Even the most successful businesses can’t retain every customer. However, a high or increasing level of churn is a red flag. Look to your industry for guidance, and determine what’s considered an acceptable vs. abnormal churn rate for your business.</li></ul><p></p><ul><li>Focus on your most valuable customers. Not every customer brings in the same revenue. Identify your most valuable customers, and focus your retention efforts on them. For example, if you sell software, you can imagine that an individual subscription plan earns less revenue than a team or enterprise subscription plan. In this case, you should distribute more resources to retain the enterprise client.</li></ul><p></p><ul><li>Involve your team. Invite employees on the front line to help choose the right tool for their pain points and needs.</li></ul><p></p><ul><li>Share metrics with your team. Don’t keep the data you collect to yourself or only share it with your executives. Use it to show your team the progress they’re making and where they can improve. And don’t forget to celebrate wins together, too!</li></ul><p></p><ul><li>What can you fix permanently? Next time your team gets a support request, ask yourself: “Can we prevent others from experiencing this?” Some requests are reactive by nature—but others lend themselves well to proactive fixes. Work to implement as many of those solutions as you can, and you’ll drastically improve the customer experience.</li></ul><p></p><ul><li>Support ticket vs. conversation. While many companies opt for the term “support ticket,” some organizations and software tools are moving to the term “conversation” instead. As you look for the right solution for your team, keep in mind that these terms may be used interchangeably.</li></ul><p><ul><li>Cut down on your ticket queue with self-service options. If reps are still struggling to manage support tickets, slash your queue by creating a searchable knowledge base with common support questions and answers. That way, customers can find the information they need quickly and solve problems on their own.</li></ul></p></div>' WHERE slug = 'module-5-team-management-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand and Leverage </strong>you strengths</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to match your career to your interests</li><li><strong>Know-how&nbsp;</strong>to define your goals</li><li><strong>Know-how&nbsp;</strong>to seek and receive feedback</li><li><strong>Develop </strong>a growth mindset</li></ul><br><p></p></div>' WHERE slug = 'module-2-assessing-your-strengths-and-skills-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2101/mod_resource/content/2/Assessing%20your%20Strength%20%20Skills%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Assessing your Strength  Skills Course Material.pdf</a></p>' WHERE slug = 'module-2-assessing-your-strengths-and-skills-module-reading-materials';
