UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2700/mod_label/intro/6_Assessing%20your%20Skills.mp4">https://goalvow.com/upskilling/pluginfile.php/2700/mod_label/intro/6_Assessing%20your%20Skills.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-assessing-your-strengths-and-skills-lesson-6-developing-a-growth-mindset';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Development is a journey.</strong>&nbsp;Developing your strengths takes time. The process is a journey that requires ongoing work. So, make those daily reflections a habit. Continue to think about how you can better use your strengths and stay persistent—because practice makes perfect.</li></ul><p></p><ul><li><strong>Every matching career won’t be right.&nbsp;</strong>There’s a lot of variety when it comes to matching careers and interests. Some jobs will pique your interests immediately, while others will feel off-base. Trust your instincts. Remember, you’re exploring what you enjoy. So, if something doesn’t relate to your other interest areas, remove it from your list of options.</li></ul><p></p><p></p><ul><li><strong>Values change with time.</strong>&nbsp;Your values define who you are in your life today—and they may change as you move through different stages. So, continue to assess your values. And if you’re ever feeling unhappy with your job, do another self-assessment and ask yourself: “Is my job honoring my core values?” If not, commit to changing course.</li></ul><p></p><ul><li><strong>Are you a remote worker?&nbsp;</strong>If so, you’ll need to be even more proactive about seeking and asking for feedback. Remote teams have fewer opportunities to exchange quick, informal feedback face-to-face. Don’t hesitate to reach out through messaging apps or emails, or to ask to hop on a 10-minute phone call to debrief.</li></ul><p></p><ul><li>If you receive feedback that’s muddled or confusing, try summarizing what the other person said, and repeat it back to them in your own words. Then ask,&nbsp;<em>“Did I get that right?”&nbsp;</em>Or,&nbsp;<em>“Do I understand you correctly?”</em></li></ul><p></p><ul><li><span><strong style="">Clarification!&nbsp;</strong>A growth mindset doesn’t mean that you believe you’ll be the next Einstein. It also doesn’t mean that you ignore your or others’ strengths. It does mean that you believe you can improve at something if you want to and put in the necessary work.&nbsp;</span></li></ul><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-2-assessing-your-strengths-and-skills-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>career development and how to drive your career successfully</li><li><strong>Know-how </strong>to crate a career development plan</li><li><strong>Know-how&nbsp;</strong>to use your One-on-One meeting with your manager to support your development</li><li><span><strong>Know-how </strong>to<span> i</span></span><span><span style="">ncrease </span>y</span>our value at work</li><li><strong>Know-how</strong> to ask <span>for a raise</span></li><li><span>Have the </span><strong>capability </strong>to take control of your personal brand at work</li><li><strong>Prepare </strong>for your performance review</li><li><strong>Know-how </strong>to transfer jobs with your company</li><li><strong>Choose </strong>which career track is best for you between individual contributor or manager</li><li><br></li></ul><br><br><p></p></div>' WHERE slug = 'module-1-driving-your-career-learning-outcome';
