UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2694/mod_label/intro/9_Driving%20your%20Career.mp4">https://goalvow.com/upskilling/pluginfile.php/2694/mod_label/intro/9_Driving%20your%20Career.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-driving-your-career-lesson-9-choose-your-track-manager-or-individual-contributor';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Talk to a manager or mentor.&nbsp;</strong>While you should be the one driving your career, it can also be helpful to get another person’s perspective or have someone to help hold you accountable. Talk to your manager or a mentor about your professional goals and interests. Ask for a second opinion on what they see as your strengths. And get their input on opportunities to develop the skills or gain the experience you need to move forward.&nbsp;</li></ul><p></p><ul><li><strong>Review and update your career development plan regularly.</strong>&nbsp;Set up recurring meetings with your manager to report on your progress and revise your career development plan. That may mean you meet to review your plan every month, once a quarter, twice a year or annually. It’s up to you and your manager. Having regular meetings will ensure that you don’t go months without making progress toward your career goals—and that your manager is invested the process, too.</li></ul><p></p><ul><li><strong>Give examples.&nbsp;</strong>Give specific examples when sharing constructive feedback with your manager. Pinpoint a specific situation, project, interaction, or outcome to convey your point more effectively.&nbsp;</li></ul><p></p><ul><li><strong>Deepen or expand your skills.&nbsp;</strong>What are the top skills your role requires? Are there any skill gaps on your team? Work to deepen your existing skills—or even develop new skills to fulfill your team’s or company’s greatest needs.</li></ul><p></p><p></p><p></p><p></p><ul><li><strong>Remember that you’re not guaranteed a raise just because you ask for one.&nbsp;</strong>If there isn’t justification for a raise, then ask your manager to help you create a career development plan and identify what you can do to increase your value to the company.</li></ul><p></p><ul><li><strong>Let your passion shine through.&nbsp;</strong>A final tip for developing a personal brand that aligns with your career interests is to be transparent about your passions and professional intentions. Speak up about projects and initiatives that excite you, and volunteer to take on challenges that spark your curiosity.</li></ul><p></p><ul><li><strong>Take regular notes.&nbsp;</strong>It’s easy to forget about the small wins or lessons you’ve learned throughout the year. You can make preparing for your performance reviews easier by taking regular notes. Try setting aside 30-60 minutes at the end of each month to make a few notes about your accomplishments and progress, and keep track of your performance metrics.</li></ul><p></p><ul><li><strong>Get exposure to different parts of the organization.&nbsp;</strong>Understanding what other departments do, how they work, and what opportunities there might be may pique your curiosity and lead you to discover your next lateral move.</li></ul><p><ul><li><strong>One question to ask.</strong>&nbsp;If you’re on the fence between being a manager or an individual contributor, ask yourself this one question:&nbsp;<em>“Can I confidently make the switch from myself to others?”</em>&nbsp;If not, don’t force it. A fulfilling career means being honest with yourself. So, only move into management if you’re happy putting others’ needs above your own.</li></ul></p><p></p><p><br></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-1-driving-your-career-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Make sense </strong>of the signs that its time to find a new job</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to create a resume</li><li><strong>Write </strong>a cover letter</li><li><strong>Prepare </strong>for a job interview</li><li><strong>Know-how&nbsp;</strong>to respond to common interview questions</li><li><strong>Decide </strong>if remote work will work for you</li><li><strong>Know-how </strong>to look for a new job&nbsp;<br></li></ul><br><br><p></p></div>' WHERE slug = 'module-3-finding-a-new-job-learning-outcome';
