UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2724/mod_label/intro/4_Mentoring%20in%20the%20Workplace.mp4?time=1710003951978">https://goalvow.com/upskilling/pluginfile.php/2724/mod_label/intro/4_Mentoring%20in%20the%20Workplace.mp4?time=1710003951978</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-mentoring-in-the-workplace-lesson-4-common-mentoring-challenges-and-how-to-overcome-them';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Be a model mentee.&nbsp;</strong>To increase your chances of landing a mentor, make sure that you’re an enjoyable mentee. Be open, optimistic, and enthusiastic. Always demonstrate an exemplary work ethic, and don’t get defensive when receiving feedback. Express your appreciation of your mentor’s time by being flexible and accommodating their schedule.</li></ul><p></p><ul><li><strong>Add value.&nbsp;</strong>Your mentor has their own reasons for mentoring you. They may be hoping to hone their interpersonal skills, fill a business need, enhance their job satisfaction, or gain recognition from their peers. How can you make the mentoring relationship valuable for them? Whether it’s talking your mentor up to peers or offering respectful feedback on their mentoring techniques, look for ways that you can add value for your mentor, too.</li></ul><p></p><ul><li><strong>Are you ready to be a mentor?&nbsp;</strong>Determine if you’re prepared to be a mentor by answering the following questions: Do you have the time and energy to commit to regular mentoring sessions? Do you enjoy helping others? Do you have skills, knowledge, and experience that a less-experienced professional could benefit or learn from? If you answered yes to these questions, then you’re ready to consider becoming a mentor.</li></ul><p><ul><li><strong>How can you be a better mentee or mentor?&nbsp;</strong>Sometimes, it’s easy to place the blame on the other party when we face a challenge. Instead, take responsibility for the role you play in the problem and regularly ask yourself,&nbsp;<em>“How can I be a better mentee or mentor?”</em></li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-6-mentoring-in-the-workplace-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Know-what </strong>is networking and <strong>why </strong>it is important</li><li><strong>Navigate </strong>a business networking event</li><li><strong>Develop</strong>&nbsp;a winning elevator pitch</li><li><strong>Develop&nbsp;</strong>to develop a professional network</li><li><strong>Maintain </strong>your professional network</li></ul><br><p></p></div>' WHERE slug = 'module-5-networking-learning-outcome';
