UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2721/mod_label/intro/5_Networking.mp4?time=1710003659450">https://goalvow.com/upskilling/pluginfile.php/2721/mod_label/intro/5_Networking.mp4?time=1710003659450</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-networking-lesson-5-how-to-maintain-your-professional-network';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><b>Summary</b></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Start today.&nbsp;</strong>The worst networking mistake you can make is putting it off. Genuine connections take time to cultivate and maintain. So, if you wait for a crisis to kick-start your networking, you’ll be unlikely to reap rewards. Start growing your network today, and you can leverage those contacts when you need them.</li></ul><p></p><ul><li><strong>Treat connections like friendships.&nbsp;</strong>A networking event isn’t an interview. Your goal isn’t to sell yourself—it’s to create personal connections. So, ask yourself,&nbsp;<em>“If this person was a friend, What would I say?”&nbsp;</em>&nbsp;Remember, a great professional relationship is built on honesty and trust—just like friendship.</li></ul><p></p><ul><li><strong>You don’t need to share everything.&nbsp;</strong>It’s tempting to share your life story, but an elevator pitch should be brief. Time yourself, continue making revisions, and confirm that your speech is no more than 60 seconds long. Remember, It’s better to leave people wanting more than it is to overwhelm them with details. If they’re curious, they’ll ask questions.</li></ul><p></p><ul><li><strong>Start where you’re comfortable.&nbsp;</strong>When it comes to meeting new people, there are several strategies out there—and some may feel easier than others. So, start where you’re comfortable and work your way up. You don’t need to do everything at once, but you do need to start somewhere.</li></ul><p></p><p></p><p></p><p><ul><li><strong>It’s OK to let some connections go.&nbsp;</strong>If you regularly reach out to someone and never hear back, it’s OK to move on and let them go. Remember, networking is a two-way street. So, as much as you should give back to others, they should also give to you. Focus on maintaining mutually beneficial connections, and your network will continue to thrive.</li></ul></p><p></p></div>' WHERE slug = 'module-5-networking-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><span>Have the </span><strong>capability</strong> to create<span><span style=""> </span>a</span> 30/60/90 day plan</li><li><strong>Adopt a successful work attitude</strong></li><li><strong>Know-how </strong>to be an effective teammate</li><li><strong>Know-how&nbsp;</strong>to connect with coworkers</li><li><strong>Ask </strong>for help at work when you need it</li><li><strong>Know-how </strong>to build your confidence as a new professional</li><li><strong>Implement </strong>practices of successful new professionals</li><li><span>Have the capability to t</span><strong>rain </strong>new coworkers</li></ul><br><br><p></p></div>' WHERE slug = 'module-4-new-professional-learning-outcome';
