UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2715/mod_label/intro/9_New%20Professional.mp4?time=1710003314608">https://goalvow.com/upskilling/pluginfile.php/2715/mod_label/intro/9_New%20Professional.mp4?time=1710003314608</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-new-professional-lesson-9-six-tips-for-training-new-coworkers';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Nobody’s perfect.</strong>&nbsp;Everyone slips up—and that’s OK. You can’t be expected to know everything on day one. It takes time to settle into a new job. So approach this week as an exciting challenge and chance to demonstrate your best qualities.&nbsp;</li></ul><p></p><ul><li><strong>Don’t skip the plan</strong><strong>.</strong>&nbsp;A 30/60/90-day plan does take work to set up—but the focus and autonomy that will result from a well-developed plan make it well worth the effort. You already have great ideas from your reflections in this course—now, turn your notes into your recipe for success!</li></ul><p></p><ul><li>Harness the power of “yet.” Try adding the word “yet” to make any negative statement positive. “I don’t know how to do that” has potential when you say, “I don’t know how to do that, yet.”</li></ul><p></p><ul><li><strong>Pause and take a breath.</strong>&nbsp;Before you take credit, pause and ask yourself,&nbsp;<em>“Who else deserves credit?”</em>&nbsp;Before you say&nbsp;<em>“Yes,” &nbsp;</em>take a breath and ask yourself,&nbsp;<em>“What skills do I contribute to this project?”</em>&nbsp;If you don’t like an idea immediately, pause and ask yourself,&nbsp;<em>“Why don’t I like this idea? What parts of this idea can I be open to and build on?”&nbsp;</em>A pause and a breath help you remember good habits and to be a thoughtful, productive team member.&nbsp;</li></ul><p></p><ul><li><strong>Let yourself be uncomfortable.&nbsp;</strong>If you’re a big talker, get quiet and listen. If you’re introverted, force yourself to say hello to a group in the breakroom. Those who work through lunch—get up and stretch your legs instead. Join a new group or give a compliment.&nbsp;<em>Try something new</em>, even if it feels awkward at first.&nbsp;</li></ul><p></p><ul><li><strong>Be honest.&nbsp;</strong>Asking for help can be challenging, but your honesty will earn respect from your manager and coworkers—and get you moving forward faster.&nbsp;</li></ul><p></p><ul><li><strong>Books, blogs, and online courses are great teachers, too.&nbsp;</strong>Don’t limit your research to people and experiences at work. You can learn from many sources—self-confidence is a transferable resource!</li></ul><p></p><ul><li><strong>Be professional.</strong>&nbsp;Successful new professionals act the part. They use appropriate language, follow the company code of conduct, and treat others with courtesy and respect.&nbsp;</li></ul><p><ul><li><strong>Take breaks.&nbsp;</strong>Learning new things is mentally taxing. Don’t forget to schedule breaks throughout training to recharge.</li></ul></p><p></p><p></p><p></p><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-4-new-professional-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Know-what </strong>to do and what <strong>not to do </strong>after losing your job</li><li>Have the <strong>strength</strong> to come back from a big mistake</li><li><strong>Know-what </strong>to do when you\'re feeling unmotivated</li><li><strong>Cope </strong>with workplace challenges</li><li><strong>Overcome </strong>imposter syndrome</li><li><strong>Implement </strong>strategies for working remotely</li><li><strong>Overcome </strong>the fear of failure</li><li><strong>Get </strong><strong>noticed</strong> at work</li></ul><br><br><p></p></div>' WHERE slug = 'module-9-overcoming-challenges-learning-outcome';
