UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2738/mod_label/intro/6_Overcoming%20Challenges%20as%20New%20Professional.mp4">https://goalvow.com/upskilling/pluginfile.php/2738/mod_label/intro/6_Overcoming%20Challenges%20as%20New%20Professional.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-9-overcoming-challenges-lesson-6-strategies-for-working-remotely';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2739/mod_label/intro/7_Overcoming%20Challenges%20as%20New%20Professional.mp4">https://goalvow.com/upskilling/pluginfile.php/2739/mod_label/intro/7_Overcoming%20Challenges%20as%20New%20Professional.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-9-overcoming-challenges-lesson-7-overcoming-the-fear-of-failure';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2740/mod_label/intro/8_Overcoming%20Challenges%20as%20New%20Professional.mp4">https://goalvow.com/upskilling/pluginfile.php/2740/mod_label/intro/8_Overcoming%20Challenges%20as%20New%20Professional.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-9-overcoming-challenges-lesson-8-getting-noticed-at-work';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>This is temporary.</strong>&nbsp;As you navigate these new waters, keep reminding yourself that this is all temporary. You won’t be unemployed forever, and you can pick yourself up. Losing your job is what you make of it. So, avoid falling into that “woe is me” mentality and, instead, keep your perspective looking forward.</li></ul><p></p><ul><li><strong>Find the positives.&nbsp;</strong>Often, we learn the most from our failures, not our successes. So, if you’re feeling down on yourself, consider the benefits of your mishap. How will this mistake help you grow and improve? Use mistakes as a form of personal development, and you can shift your perspective and start to see the silver lining.</li></ul><p></p><ul><li><strong>Don’t wait it out.&nbsp;</strong>Low motivation rarely solves itself. More often than not, it only escalates with time. So, if you’re in a motivation rut, don’t wait it out. Don’t hope things will get better. Instead, take action because you’re the only person in control of what happens next.</li></ul><p></p><ul><li><strong>Give it time.&nbsp;</strong>As the five reaction stages prove, accepting change takes time. So, don’t rush your emotions or get frustrated if you’re feeling stuck. Everyone moves at a different pace. What matters is not how quickly you progress, but that you do so in a healthy and productive way. So, continue to follow the coping strategies and give it time.</li></ul><p></p><ul><li><strong>Remember: It’s irrational.&nbsp;</strong>The next time you feel like impostor syndrome is taking over, remind yourself that—as real as it feels—it’s irrational. So, don’t get caught in the lie. Focus on factual truths and gain outside perspectives, and you’ll snap yourself out of the illusion.</li></ul><p></p><p></p><p></p><p></p><p></p><ul><li><strong>Find what works for you.&nbsp;</strong>Success as a remote employee requires some trial and error. For example, you might work best in the evenings, but if your friends and family are only around after 6 p.m., you might feel isolated with that schedule. So, experiment with the various strategies to determine your priorities. Then, find out what unique strategy combination works best for you.</li></ul><p></p><ul><li><strong>Practice self-compassion.&nbsp;</strong>Be kind to yourself when you experience failure. Nix negative self-talk and practice positive self-affirmations. You might even practice self-care such as watching a feel-good movie, reading a book, making comfort food, or seeking support from a partner, family, or friends.</li></ul><p><ul><li><strong>Speak up to your boss.&nbsp;</strong>Your boss isn’t a mind reader. Talk to them about your goals to increase your visibility at work. Ask for your boss’s help with developing an action plan. They’ll appreciate your initiative and drive—and be more likely to notice when you follow through with your goals.</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-9-overcoming-challenges-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Elevate </strong>your workplace professionalism</li><li><strong>Know-how </strong>to write effective business emails</li><li><strong>Adopt </strong>business phone etiquette</li><li><strong>Know-when </strong>and how to use formal/informal communication</li></ul><br><br><p></p></div>' WHERE slug = 'module-7-professional-etiquette-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2106/mod_resource/content/2/Professional%20Etiquette%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Professional Etiquette Course Material.pdf</a></p>' WHERE slug = 'module-7-professional-etiquette-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2725/mod_label/intro/1_Professional%20Etiquette.mp4?time=1710004049314">https://goalvow.com/upskilling/pluginfile.php/2725/mod_label/intro/1_Professional%20Etiquette.mp4?time=1710004049314</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-professional-etiquette-lesson-1-a-guide-to-workplace-professionalism';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2726/mod_label/intro/2_Professional%20Etiquette.mp4?time=1710004093421">https://goalvow.com/upskilling/pluginfile.php/2726/mod_label/intro/2_Professional%20Etiquette.mp4?time=1710004093421</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-professional-etiquette-lesson-2-how-to-write-effective-business-emails';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2727/mod_label/intro/3_Professional%20Etiquette.mp4?time=1710004147538">https://goalvow.com/upskilling/pluginfile.php/2727/mod_label/intro/3_Professional%20Etiquette.mp4?time=1710004147538</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-professional-etiquette-lesson-3-business-phone-etiquette';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2728/mod_label/intro/4_Professional%20Etiquette.mp4?time=1710004198231">https://goalvow.com/upskilling/pluginfile.php/2728/mod_label/intro/4_Professional%20Etiquette.mp4?time=1710004198231</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-professional-etiquette-lesson-4-formal-vs-informal-communication';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Review your company’s code of conduct.&nbsp;</strong>A code of conduct provides more tailored guidelines for professional behaviors in&nbsp;<em>your</em>&nbsp;workplace.</li></ul><p></p><ul><li><strong>Send a copy to yourself.</strong>&nbsp;Send a copy of important emails to yourself to file for future reference.</li></ul><p></p><ul><li><strong>Avoid using speakerphone when it’s not necessary.&nbsp;</strong>While it may&nbsp;<em>seem</em>&nbsp;tempting to have your hands free to type or sort papers while you talk, the quality of your call diminishes. Callers may have trouble hearing over speakerphone due to echo or background noise. Worse—they may wonder if you’re paying attention.</li></ul><p></p><ul><li><strong>When in doubt, err on the side of formality.&nbsp;</strong>Start formal, and take the other party’s lead from there. You can always change your tone to mirror the other person’s response.</li></ul><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-7-professional-etiquette-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Build </strong>strong work relationships with your coworkers</li><li><strong>Build </strong>strong work relationships with your boss&nbsp;</li><li><strong>Repair </strong>broken work relationships</li><li><strong>Work </strong>with people you don\'t like</li></ul><br>&nbsp;<br><p></p></div>' WHERE slug = 'module-8-working-relationships-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2107/mod_resource/content/2/Working%20Relationship%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Working Relationship Course Material.pdf</a></p>' WHERE slug = 'module-8-working-relationships-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2729/mod_label/intro/1_Working%20Relationship.mp4?time=1710004272169">https://goalvow.com/upskilling/pluginfile.php/2729/mod_label/intro/1_Working%20Relationship.mp4?time=1710004272169</video>&nbsp;<br></p></div>' WHERE slug = 'module-8-working-relationships-lesson-1-building-strong-work-relationships-with-your-coworkers';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2730/mod_label/intro/2_Working%20Relationship.mp4?time=1710004325188">https://goalvow.com/upskilling/pluginfile.php/2730/mod_label/intro/2_Working%20Relationship.mp4?time=1710004325188</video>&nbsp;<br></p></div>' WHERE slug = 'module-8-working-relationships-lesson-2-building-a-strong-working-relationship-with-your-boss';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2731/mod_label/intro/3_Working%20Relationship.mp4?time=1710004367818">https://goalvow.com/upskilling/pluginfile.php/2731/mod_label/intro/3_Working%20Relationship.mp4?time=1710004367818</video>&nbsp;<br></p></div>' WHERE slug = 'module-8-working-relationships-lesson-3-repairing-a-broken-work-relationship';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2732/mod_label/intro/4_Working%20Relationship.mp4?time=1710004419749">https://goalvow.com/upskilling/pluginfile.php/2732/mod_label/intro/4_Working%20Relationship.mp4?time=1710004419749</video>&nbsp;<br></p></div>' WHERE slug = 'module-8-working-relationships-lesson-4-working-with-people-you-don-t-like';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Make a habit of asking yourself,&nbsp;<em>“What do my coworkers need from me today?”</em>&nbsp;</strong>Whether they need a word of encouragement, a second set of eyes on a project, or someone who can take a task off their plate and run with it, do everything in your power to fulfill that need for them.</li></ul><p></p><ul><li><strong>Ask your boss for regular feedback.</strong>&nbsp;If you want to know how you could be a better employee, why not ask your boss directly? Your boss will appreciate your initiative, and you can glean some helpful tips to develop as an individual and improve your professional relationship.</li></ul><p></p><ul><li><strong>Don’t stop working on your professional relationship after you’ve repaired the damage.&nbsp;</strong>Continue to develop your interpersonal skills and be careful to maintain the trust and goodwill that you’ve worked so hard to restore. &nbsp;</li></ul><p><ul><li><strong>Talk to your manager if you’ve exhausted other options.&nbsp;</strong>If you’ve tried all of these tips, talked to your coworker about an issue directly, and still can’t find a way to work together effectively, then it may be time to talk to your manager. Just make sure that you go to your manager to brainstorm solutions—not to complain.</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-8-working-relationships-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>the fundamentals of change management</li><li>Have the <strong>capability </strong>to implement organizational change</li><li><strong>Understand </strong>the basics of change management models</li><li><strong>Implement </strong>best practices for change management</li><li><strong>Overcome </strong>common change management challenges</li></ul><br><br><p></p></div>' WHERE slug = 'module-1-change-management-fundamentals-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2109/mod_resource/content/2/Change%20Managmnt%20Fund%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Change Managmnt Fund Course Material.pdf</a></p>' WHERE slug = 'module-1-change-management-fundamentals-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2866/mod_label/intro/1_Change%20Management%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2866/mod_label/intro/1_Change%20Management%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-change-management-fundamentals-lesson-1-introduction-to-change-management';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2867/mod_label/intro/2_Change%20Management%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2867/mod_label/intro/2_Change%20Management%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-change-management-fundamentals-lesson-2-three-types-of-organizational-change';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2868/mod_label/intro/3_Change%20Management%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2868/mod_label/intro/3_Change%20Management%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-change-management-fundamentals-lesson-3-understanding-the-basics-of-change-management-models';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2869/mod_label/intro/4_Change%20Management%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2869/mod_label/intro/4_Change%20Management%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-change-management-fundamentals-lesson-4-best-practices-for-change-management';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2870/mod_label/intro/5_Change%20Management%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2870/mod_label/intro/5_Change%20Management%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-change-management-fundamentals-lesson-5-overcoming-common-change-management-challenges';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><b>Summary</b></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Pay attention to how individuals are handling change.&nbsp;</strong>Some employees may be excited about change, while others feel hesitant, fearful, or downright angry. When managing the people side of change, remember that there is no one-size-fits-all solution. A human-centered approach to change is rooted in equity and empathy—and that looks different for everyone.</li></ul><p></p><ul><li><strong>Check your bias.&nbsp;</strong>As you plan small or expansive changes, play devil’s advocate. What are you assuming about the change that may not be true? This line of questioning may free up ideas, resources, and innovations that otherwise might get overlooked.</li></ul><p></p><ul><li><strong>Don’t go it alone.&nbsp;</strong>Change is inevitable—which also means it’s been done countless times before. A proven model can guide you. Think about the support you need, assess the different models, and choose ones that’ll help you reach those goals.</li></ul><p></p><ul><li><strong>Always inform people to the extent possible.</strong>&nbsp;One of the pitfalls of change is the lack of clarity about why change is needed and how it will happen. If people are used to one way of working, shifting can be difficult. So, provide as much information as soon as you can. This helps dissipate the fear and anxiety of welcoming an uncertain or unfamiliar future.</li></ul><p><ul><li><strong>Recognition is a helpful motivator.&nbsp;</strong>As the initiative progresses, acknowledge team members modeling behaviors you want. Try a mix of rewards: Spotlight team members, offer financial bonuses, and award promotions or new responsibilities. This will encourage other employees to follow suit.&nbsp;</li></ul></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-1-change-management-fundamentals-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p>\r\n<p dir="ltr"><strong>After completing this module</strong><strong>, you will be able to:</strong></p>\r\n<p dir="ltr"></p>\r\n<ul>\r\n<li><strong>Understand </strong>and implement<strong> </strong>the McKinsey model</li>\r\n<li><strong>Implement</strong> Lewin\'s 3-step Change Management model</li>\r\n<li><strong>Implement </strong>Kotter\'s 8-step change model</li>\r\n<li><strong>Implement </strong>Kubler-Ross change management framework</li>\r\n<li><strong>Implement </strong>the Satir change management model</li>\r\n</ul>\r\n<p><br><br></p>\r\n<p></p></div>' WHERE slug = 'module-2-change-management-models-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2110/mod_resource/content/2/Change%20Mangmnt%20Models%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Change Mangmnt Models Course Material.pdf</a></p>' WHERE slug = 'module-2-change-management-models-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2871/mod_label/intro/1_Change%20Management%20Models.mp4">https://goalvow.com/upskilling/pluginfile.php/2871/mod_label/intro/1_Change%20Management%20Models.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-change-management-models-lesson-1-the-mckinsey-7-s-model';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2872/mod_label/intro/2_Change%20Management%20Models.mp4">https://goalvow.com/upskilling/pluginfile.php/2872/mod_label/intro/2_Change%20Management%20Models.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-change-management-models-lesson-2-lewin-s-3-step-change-management-model';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2873/mod_label/intro/3_Change%20Management%20Models.mp4">https://goalvow.com/upskilling/pluginfile.php/2873/mod_label/intro/3_Change%20Management%20Models.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-change-management-models-lesson-3-kotter-s-8-step-change-model';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2874/mod_label/intro/4_Change%20Management%20Models.mp4">https://goalvow.com/upskilling/pluginfile.php/2874/mod_label/intro/4_Change%20Management%20Models.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-change-management-models-lesson-4-kubler-ross-change-management-framework';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2875/mod_label/intro/5_Change%20Management%20Models.mp4">https://goalvow.com/upskilling/pluginfile.php/2875/mod_label/intro/5_Change%20Management%20Models.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-change-management-models-lesson-5-the-satir-change-management-model';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Recognition is a helpful motivator.&nbsp;</strong>As the initiative progresses, acknowledge team members modeling behaviors you want. Try a mix of rewards: Spotlight team members, offer financial bonuses, and award promotions or new responsibilities. This will encourage other employees to follow suit.&nbsp;</li></ul><p></p><ul><li><strong>Give it time.&nbsp;</strong>Lewin’s model follows a slow and steady pace. The framework only works if you give employees time to adjust. Remember, your team needs to become familiar with a change before initiation. And they need space to practice and make mistakes&nbsp;<em>before</em>&nbsp;refreezing operations. &nbsp;</li></ul><p></p><ul><li>Change management models typically simplify the change process by transforming it into a series of straightforward steps. In reality, change is more complex and messy than models show. The key is to tailor a model to your needs. Maybe your organization needs to invest more time in creating a sense of urgency, or perhaps employee resistance is a barrier requiring additional time to dismantle. The process won’t look the same for every organization. Apply the model in ways that work best for your team.</li></ul><p></p><ul><li><strong>It’s not one-size-fits-all.&nbsp;</strong>Though these emotions are universal, how people experience them is unique. What works for one person may not work for another. Stay patient, and keep trying until you find the right approach.</li></ul><p></p><p></p><p></p><p><ul><li><strong>Change is not always linear.&nbsp;</strong>Individuals move through change at different speeds. Managers often progress at a faster pace than staff, and individual employees may not advance through the stages in order. For instance, some employees may start at the Integration stage but regress to the Resistance stage when they encounter problems. The Satir Model offers the data and understanding necessary to support your staff and evolve your business into the best possible version of itself.</li></ul></p><p></p></div>' WHERE slug = 'module-2-change-management-models-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><ul><li>Have the&nbsp;<strong>capability</strong>&nbsp;to plan an effective change communication strategy</li><li><strong>Know-how&nbsp;</strong>to get employee buy-in during change</li><li><strong>Implement </strong>an effective change management communication</li></ul><br><br><p></p></div>' WHERE slug = 'module-4-communicating-change-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2112/mod_resource/content/2/Communicating%20Change%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Communicating Change Course Material.pdf</a></p>' WHERE slug = 'module-4-communicating-change-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2881/mod_label/intro/1_Communicating%20Change.mp4">https://goalvow.com/upskilling/pluginfile.php/2881/mod_label/intro/1_Communicating%20Change.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-communicating-change-lesson-1-planning-an-effective-change-communication-strategy';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2882/mod_label/intro/2_Communicating%20Change.mp4">https://goalvow.com/upskilling/pluginfile.php/2882/mod_label/intro/2_Communicating%20Change.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-communicating-change-lesson-2-getting-employee-buy-in-during-change';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2883/mod_label/intro/3_Communicating%20Change.mp4">https://goalvow.com/upskilling/pluginfile.php/2883/mod_label/intro/3_Communicating%20Change.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-communicating-change-lesson-3-effective-change-management-communication';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Cultivate healthy communication strategies early.&nbsp;</strong>Don’t wait until you get hit with an unexpected change! Start talking about change in consistent, clear ways to prepare your organization for the next transition.</li></ul><p></p><ul><li>When it comes to change leadership, a “we’re all in this together” approach will have better results than an “us versus them” mentality. Focus on teamwork and collaboration, and make sure all employees know they are playing a valued role in the change—and, subsequently, in the organization’s ongoing success.</li></ul><p><ul><li><strong>How’s everyone feeling?&nbsp;</strong>Nothing scuppers a great plan faster than a mass refusal to adopt it. Implement methods to keep tabs on the team’s emotional temperature. Is it moving in the right direction? If not, consider adjusting tactics.</li></ul></p><p></p><p></p></div>' WHERE slug = 'module-4-communicating-change-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"></p><p dir="ltr"><strong>After completing this module</strong><strong>, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>the fundamentals of leading through change</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to lead teams through change</li><li><strong>Know-how&nbsp;</strong>to empower employees to successfully navigate change</li></ul><br><br><p></p></div>' WHERE slug = 'module-5-leading-through-change-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2113/mod_resource/content/2/Leading%20through%20Change%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Leading through Change Course Material.pdf</a></p>' WHERE slug = 'module-5-leading-through-change-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2884/mod_label/intro/1_Leading%20Through%20Change.mp4">https://goalvow.com/upskilling/pluginfile.php/2884/mod_label/intro/1_Leading%20Through%20Change.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-leading-through-change-lesson-1-the-fundamentals-of-leading-through-change';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2885/mod_label/intro/2_Leading%20Through%20Change.mp4">https://goalvow.com/upskilling/pluginfile.php/2885/mod_label/intro/2_Leading%20Through%20Change.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-leading-through-change-lesson-2-five-tips-for-leading-teams-through-change';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2886/mod_label/intro/3_Leading%20Through%20Change.mp4">https://goalvow.com/upskilling/pluginfile.php/2886/mod_label/intro/3_Leading%20Through%20Change.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-leading-through-change-lesson-3-empowering-employees-to-successfully-navigate-change';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Research change leadership models.&nbsp;</strong>There are many different methods and perspectives for leaders regarding change. Explore what’s available and choose the models that best fit your leadership style and team.</li></ul><p></p><ul><li><strong>Don’t forget to celebrate!&nbsp;</strong>When you’re focused on overall success, it’s easy to gloss over wins and milestones. But don’t forget that all victories, even small ones, are worth celebrating.</li></ul><p><ul><li><strong>Leave space for every voice.</strong>&nbsp;Carve out time to hear from every team member. Let them share concerns, and be sure to acknowledge them. It’s OK to respond and gently nudge them in a better direction. Have them repeat your positive interpretation in their own words to be sure they understand it.&nbsp;</li></ul></p><p></p><p><br></p><p></p></div>' WHERE slug = 'module-5-leading-through-change-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Lead</strong> during an unexpected change</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to build adaptability for your team&nbsp;</li><li><strong>Know-how&nbsp;</strong>to support your employees in a crisis</li><li><strong>Know-how&nbsp;</strong>to turn a crisis situation into an opportunity for positive change</li></ul><br><br><p></p></div>' WHERE slug = 'module-6-managing-change-in-time-of-crisis-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2114/mod_resource/content/2/Managing%20Change%20in%20Crisis%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Managing Change in Crisis Course Material.pdf</a></p>' WHERE slug = 'module-6-managing-change-in-time-of-crisis-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2887/mod_label/intro/1_Managing%20Change%20in%20Time%20of%20Crisis.mp4">https://goalvow.com/upskilling/pluginfile.php/2887/mod_label/intro/1_Managing%20Change%20in%20Time%20of%20Crisis.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-managing-change-in-time-of-crisis-lesson-1-leading-during-an-unexpected-change';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2888/mod_label/intro/2_Managing%20Change%20in%20Time%20of%20Crisis.mp4">https://goalvow.com/upskilling/pluginfile.php/2888/mod_label/intro/2_Managing%20Change%20in%20Time%20of%20Crisis.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-managing-change-in-time-of-crisis-lesson-2-building-adaptability-for-your-team';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2889/mod_label/intro/3_Managing%20Change%20in%20Time%20of%20Crisis.mp4">https://goalvow.com/upskilling/pluginfile.php/2889/mod_label/intro/3_Managing%20Change%20in%20Time%20of%20Crisis.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-managing-change-in-time-of-crisis-lesson-3-how-to-support-your-employees-in-a-crisis';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2890/mod_label/intro/4_Managing%20Change%20in%20Time%20of%20Crisis.mp4">https://goalvow.com/upskilling/pluginfile.php/2890/mod_label/intro/4_Managing%20Change%20in%20Time%20of%20Crisis.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-managing-change-in-time-of-crisis-lesson-4-turning-a-crisis-into-an-opportunity-for-positive-change';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Find a motivating story.&nbsp;</strong>Keep a stressed team afloat by connecting to a shared or personal vision of the future. When it’s time to make tough decisions or the next step is unclear, return to the story to find meaning and purpose within the crisis.</li></ul><p></p><ul><li><strong>How can you foster your team’s resilience and adaptability together?&nbsp;</strong>Resilience, or the ability to cope with difficulty, is an important partner to adaptability. H ow would you rate your team’s resilience and adaptability now? Are they more skilled in one over the other? How can you promote both?</li></ul><p></p><ul><li><strong>Do your performance metrics make sense?</strong>&nbsp;As day-to-day work shifts and team members take on new tasks, chances are metrics need adjusting to reflect the rapidly changing situation. Find new ways to recognize and reward teams rising to the challenge.&nbsp;</li></ul><p><ul><li><strong>Change your mindset.&nbsp;</strong>Instead of viewing change as a “necessary evil,” help your team envision how change can accelerate growth and create a better future.</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-6-managing-change-in-time-of-crisis-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand</strong> the change management process</li><li><strong>Make </strong>the case for change</li><li><strong>Know-how</strong> to develop and communicate a vision for change</li><li><span>Have the </span><strong>capability</strong> to create a change action plan</li><li><strong>Assist </strong>employees facing change at work</li><li><strong>Know-how </strong>to measure effectiveness of change</li></ul><br><p></p></div>' WHERE slug = 'module-3-the-change-management-process-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2111/mod_resource/content/2/Change%20Mangmnt%20Process%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Change Mangmnt Process Course Material.pdf</a></p>' WHERE slug = 'module-3-the-change-management-process-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2876/mod_label/intro/1_The%20Change%20Management%20Process.mp4">https://goalvow.com/upskilling/pluginfile.php/2876/mod_label/intro/1_The%20Change%20Management%20Process.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-the-change-management-process-lesson-1-making-the-case-for-change';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2877/mod_label/intro/2_The%20Change%20Management%20Process.mp4">https://goalvow.com/upskilling/pluginfile.php/2877/mod_label/intro/2_The%20Change%20Management%20Process.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-the-change-management-process-lesson-2-how-to-develop-and-communicate-a-vision-for-change';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2878/mod_label/intro/3_The%20Change%20Management%20Process.mp4">https://goalvow.com/upskilling/pluginfile.php/2878/mod_label/intro/3_The%20Change%20Management%20Process.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-the-change-management-process-lesson-3-creating-a-change-action-plan';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2879/mod_label/intro/4_The%20Change%20Management%20Process.mp4">https://goalvow.com/upskilling/pluginfile.php/2879/mod_label/intro/4_The%20Change%20Management%20Process.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-the-change-management-process-lesson-4-tips-for-employees-facing-change-at-work';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2880/mod_label/intro/5_The%20Change%20Management%20Process.mp4">https://goalvow.com/upskilling/pluginfile.php/2880/mod_label/intro/5_The%20Change%20Management%20Process.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-the-change-management-process-lesson-5-how-to-measure-the-effectiveness-of-change';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Foster trust with transparency.&nbsp;</strong>Open the books and let employees or stakeholders see the data that informed your proposition for change. Let them see for themselves why change is urgent and necessary.</li></ul><p></p><ul><li><strong>Stay on track with frequent gut checks.</strong>&nbsp;Ask employees for feedback by asking,&nbsp;<em>“How do you think we’re doing?”</em>&nbsp;and,&nbsp;<em>“What could we do better to reach our vision?”</em>&nbsp;Take their opinions to heart, and show them that you’re listening by promptly responding and implementing what’s feasible.</li></ul><p></p><ul><li><strong>Where are opportunities hiding?&nbsp;</strong>Think of the change from multiple perspectives to uncover skill-building, innovation, and efficiency possibilities. You might be surprised by what you find from another point of view!</li></ul><p></p><ul><li><strong>Stay positive, regardless of the outcome.</strong>&nbsp;Not all changes will be successful. Sometimes, leadership makes mistakes. They may even have to revise their plan. &nbsp;But even if your skepticism is validated, it shouldn’t change your attitude toward change. Your strategy should remain consistent regardless of whether you disagree with the change. A focused, optimistic approach puts your company in a position to succeed, now and in the future.&nbsp;</li></ul><p><ul><li>The old saying<strong>,&nbsp;<em>“A stitch in time saves nine,”</em>&nbsp;</strong>means that if you address issues quickly, you’ll save yourself from a bigger headache down the road. Apply what you learn from metrics swiftly to get the most benefit and keep the change process moving smoothly.</li></ul></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-3-the-change-management-process-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>common workplace issues and how to handle them</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to work with different communication styles</li><li><strong>Create strategies </strong>for dealing with difficult coworkers</li><li><strong>Create strategies</strong> for dealing with difficult boss</li><li><strong>Know-when</strong>&nbsp;and how to escalate issues to your boss</li><li><strong>Know-when </strong>and how to involve HR</li><li><strong>Know-when </strong>to overcome fear of confrontation and conflict</li><li><strong>Know-how </strong>to have difficult conversation</li></ul><br><br><p></p></div>' WHERE slug = 'module-8-communicating-in-difficult-situations-learning-outcome';
