UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/849/mod_label/intro/4_Empathy.mp4?time=1709882566779">https://goalvow.com/upskilling/pluginfile.php/849/mod_label/intro/4_Empathy.mp4?time=1709882566779</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-empathy-lesson-4-overcoming-empathy-roadblocks';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/850/mod_label/intro/5_Empathy.mp4?time=1709882626406">https://goalvow.com/upskilling/pluginfile.php/850/mod_label/intro/5_Empathy.mp4?time=1709882626406</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-empathy-lesson-5-strategies-for-building-empathy';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Are you empathetic or sympathetic?&nbsp;</strong>If you’re unsure whether you’re empathetic or sympathetic, ask yourself:&nbsp;<em>Am I relating personally to this emotion or experience? Do I understand the feeling?&nbsp;</em>If you can step into the other person’s shoes and experience the moment along with them, then you’re showing empathy.</li></ul><p></p><ul><li><strong>Empathy builds understanding.&nbsp;</strong>Empathy doesn’t mean that you need to always agree with or please others. Rather, it’s about understanding. By thoughtfully considering how others feel and view things, you’ll be a more effective coworker or leader.</li></ul><p></p><ul><li><strong>Empathy isn’t always about fixing.&nbsp;</strong>When communicating empathy, it’s tempting to try to fix the problem. But sometimes, a person just wants to feel understood. They want to feel less alone. Before offering advice, ask the person if they want it:<em>&nbsp;“I hear you, and I’m sorry this is happening to you. Would you like help?”</em></li></ul><p></p><p></p><ul><li><strong>Overcome snap judgements.&nbsp;</strong>The next time you find yourself making a snap judgment about another person, try to override those assumptions. Ask questions, get more details, and look for ways you can empathize with them. Before forming an opinion, try to gain a deeper understanding.&nbsp;</li></ul><p><ul><li><strong>Exercise your empathy.&nbsp;</strong>Empathy is like a muscle. When you exercise the muscle, it gets stronger. Keep practicing and challenging yourself. Put in the work and don’t give up. You’ll then help those around you feel heard, seen, and understood.</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-2-empathy-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Know-what </strong>is<strong>&nbsp;</strong>communication and why it fails sometimes</li><li><strong>Know-why </strong>communication skills matter to your professional success</li><li><strong>Know-how&nbsp;</strong>to use verbal, nonverbal and written communication</li><li><strong>Know-how&nbsp;</strong>to remove common communication barriers</li><li><strong>Choose </strong>the right communication medium</li></ul><br><br><p></p></div>' WHERE slug = 'module-1-communication-fundamentals-learning-outcome';
