UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/855/mod_label/intro/5_Communiation%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/855/mod_label/intro/5_Communiation%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-communication-fundamentals-lesson-5-choosing-the-right-communication-medium';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Sender tip.&nbsp;</strong>The next time you send a message, try placing yourself in the receiver’s shoes. If you were receiving this message (instead of sending it), how would you answer the following two questions: “Is the message clear and straightforward?” and “What’s my overall interpretation of this message?”</li></ul><p></p><ul><li><strong>Build relationships from conflict.&nbsp;</strong>Conflicts can be nerve-wracking, but they’re also a chance for growth! The next time you experience conflict, take a step back and seek to understand the other person’s perspective. Once you fully understand where they’re coming from, let them know you do. They’ll feel more valued, increasing the chances you’ll have a productive dialogue and resolution.</li></ul><p></p><ul><li><strong>Nonverbal communication: practice makes perfect.&nbsp;</strong>Even when we’re silent, our nonverbal cues can speak volumes. If you have an important presentation or conversation coming up, try practicing in front of a mirror or recording yourself. That can help you become more aware of your nonverbal communication.</li></ul><p></p><ul><li><strong>Just enough information.&nbsp;</strong>What’s the happy medium between too much and too little information? Try this: If you could put your entire message into only one sentence, what would you say? Now, give more details, but make sure you’re staying on target. Remember, all extra information should still relate back to that original sentence.</li></ul><p><ul><li><strong>Choose your medium based on the situation.&nbsp;</strong>Most people have a go-to medium they feel most comfortable using. When choosing your medium, make sure your preferences aren’t getting in the way. Remember, your communication will be most successful if you make your choice based on the&nbsp;<strong>situation</strong>&nbsp;and your&nbsp;<strong>message</strong>&nbsp;and not necessarily on what feels easiest.</li></ul></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-1-communication-fundamentals-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Conduct </strong>an effective meeting</li><li><strong>Set </strong>a meeting agenda</li><li><strong>Implement </strong>group facilitation techniques</li><li><strong>Build</strong> consensus in meetings</li><li><strong>Manage </strong>conflict in meetings</li><li><strong>Speak </strong>up in meetings</li></ul><br><br><p></p></div>' WHERE slug = 'module-4-meetings-learning-outcome';
