UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/860/mod_label/intro/5_Meetings.mp4?time=1709997429961">https://goalvow.com/upskilling/pluginfile.php/860/mod_label/intro/5_Meetings.mp4?time=1709997429961</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-meetings-lesson-5-managing-conflict-in-meetings';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/861/mod_label/intro/6_Meetings.mp4">https://goalvow.com/upskilling/pluginfile.php/861/mod_label/intro/6_Meetings.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-meetings-lesson-6-speaking-up-in-meetings';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Keep track of time.&nbsp;</strong>One of the biggest meeting challenges is ending on time. Navigate this challenge effectively by keeping a clock, stopwatch, or another form of countdown visible.</li></ul><p></p><ul><li><strong>Use a template.&nbsp;</strong>Agendas are typically designed as a list or outline and are ideally limited to a single page. However, it may be longer depending on the length and complexity of the meeting. You can save yourself time when developing future meeting agendas by designing a template to use again.</li></ul><p></p><p></p><ul><li><strong>Practice active listening.</strong>&nbsp;Develop your skills in active listening to better facilitate group meetings. Listen, make eye contact, and use encouraging body language to show that you are listening and engaged in what the speaker is saying. You might also paraphrase what the speaker says and repeat the speaker’s main points back to the group for deeper reflection.&nbsp;</li></ul><p></p><p></p><ul><li><strong>Delegate decisions to appropriate stakeholders.&nbsp;</strong>Consensus-based decision-making is ideal for meetings in which all participants play a relevant role in, or add a critical perspective to, the decision-making process. However, don’t hesitate to delegate decisions to smaller groups or appropriate stakeholders if everyone’s input isn’t needed.&nbsp;</li></ul><p></p><ul><li><strong>Adopt a zero-tolerance policy</strong>. While it’s okay to express concerns or disagree with colleagues, it’s not okay to insult or personally attack them. Adopt and communicate a zero-tolerance policy for personal attacks at meetings to protect a workplace environment that fosters trust, respect, and open communication.&nbsp;</li></ul><p><ul><li><strong>Just do it.&nbsp;</strong>Speaking up in meetings will get easier the more you practice. The best way to get better is to make a leap. Just do it, no matter how uncomfortable or unprepared you may feel.</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-4-meetings-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>the difference between negotiating and persuading</li><li><strong>Distinguish </strong>types of negotiations and use one that is appropriate&nbsp;</li><li><strong>Know-how&nbsp;</strong>to use negotiation tactics</li><li><strong>Know-how&nbsp;</strong>to use persuasion tactics</li><li><strong>Improve </strong>your negotiation and persuasion skills</li></ul><br><br><p></p></div>' WHERE slug = 'module-6-negotiation-and-persuasion-learning-outcome';
