UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/864/mod_label/intro/3_Negotiation%20and%20Persuasion.mp4?time=1709998168108">https://goalvow.com/upskilling/pluginfile.php/864/mod_label/intro/3_Negotiation%20and%20Persuasion.mp4?time=1709998168108</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-negotiation-and-persuasion-lesson-3-negotiation-tactics';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/865/mod_label/intro/4_Negotiation%20and%20Persuasion.mp4?time=1709998212573">https://goalvow.com/upskilling/pluginfile.php/865/mod_label/intro/4_Negotiation%20and%20Persuasion.mp4?time=1709998212573</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-negotiation-and-persuasion-lesson-4-persuasion-tactics';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/866/mod_label/intro/5_Negotiation%20and%20Persuasion.mp4?time=1709998258556">https://goalvow.com/upskilling/pluginfile.php/866/mod_label/intro/5_Negotiation%20and%20Persuasion.mp4?time=1709998258556</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-negotiation-and-persuasion-lesson-5-improving-your-negotiation-and-persuasion-skills';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Mix it up.</strong>&nbsp;Negotiation and persuasion are not mutually exclusive. You can use a persuasive argument to make your case during a negotiation. Or, if you find yourself unable to persuade the other party, you can always resort to negotiation. Don’t hesitate to use both practices if the situation calls for it.&nbsp;</li></ul><p></p><ul><li><strong>Do your homework.</strong>&nbsp;Before heading into any negotiation, research the other party to better understand their interests, context, and challenges. Try to prepare mutually beneficial alternatives that might exist in case your offer isn’t accepted.&nbsp;</li></ul><p></p><ul><li><strong>Make the first offer.</strong>&nbsp;Making the first offer in a negotiation sets an anchor for the discussion that follows. Take control of the range of the negotiation by making the first move.</li></ul><p></p><ul><li><strong>Brainstorm potential concerns.</strong>&nbsp;Before you try to persuade someone, consider all sides of the argument and create a list of potential concerns the other party may have. Not only should you be prepared to dispel these concerns, but you also might consider bringing them up yourself to show the other party that you have a plan. It’s better to address, rather than ignore, concerns off the bat.&nbsp;</li></ul><p><ul><li><strong>Remember that some human interests are universal.</strong>&nbsp;For example, we all want to be treated respectfully and fairly. We want to feel proud of our work. Always strive to meet these basic interests for the other party.&nbsp;</li></ul></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-6-negotiation-and-persuasion-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Define</strong>&nbsp;your presentation objective</li><li><strong>Know-how </strong>to structure your presentation</li><li><strong>Work</strong>&nbsp;with visual aids</li><li><strong>Implement </strong>your visual aid design</li><li><strong>Present </strong>your data for the audience</li><li><strong>Practice </strong>your presentation</li><li><strong>Cope </strong>with presentation nerves</li><li><strong>Deal </strong>with questions accordingly</li><li><strong>Improve </strong>your presentation skills</li><li><br></li></ul><br><br><p></p></div>' WHERE slug = 'module-5-presentations-learning-outcome';
