UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/882/mod_label/intro/7_Verbal%20Communication.mp4?time=1709997049203">https://goalvow.com/upskilling/pluginfile.php/882/mod_label/intro/7_Verbal%20Communication.mp4?time=1709997049203</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-verbal-communication-lesson-7-becoming-an-expert-verbal-communicator';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Practice makes perfect.&nbsp;</strong>Being a great verbal communicator is a skill, and like all skills, it can be learned. Improve your communication skills by finding opportunities to speak up. Pay close attention to what you say and how others interpret that message. Were you successful? Why, or why not? The more you practice your skills and observe your performance, the better you’ll get at it.</li></ul><p></p><ul><li><strong>Who’s your listener?&nbsp;</strong>When choosing a conversation starter, consider your listener. If you’re meeting your company’s founder, it’s not the best idea to start with,&nbsp;<em>“What’s your favorite food?”</em>&nbsp;Instead, a better approach is to start with a compliment such as,&nbsp;<em>“I’m so impressed with everything you’ve done. How did you get the idea to create such a unique brand?”</em>&nbsp;Remember: The best conversation starters cater to your listener.&nbsp;</li></ul><p></p><ul><li><strong>Keep your questions on topic.&nbsp;</strong>&nbsp;Often, our questions can lead a speaker in a direction they didn’t plan on taking. If you notice that has happened, take ownership and steer the discussion back in the right direction. You might say:&nbsp;<em>“Thanks for clarifying! Now, tell me more about …”</em></li></ul><p></p><ul><li><span><strong style="font-style: italic;">Keep open questions focused.&nbsp;</strong>Even when your question is open, it still needs parameters. Asking your boss,&nbsp;<span style="">“What’s your favorite quality in a person?”</span>&nbsp;won’t help your search for an ideal job candidate. You’ll have better luck asking,&nbsp;<span style="">“What’s your favorite quality in an employee?”&nbsp;</span>Whether your question is open or closed, it should still be specific.</span></li></ul><p></p><ul><li><em><strong>Stay calm.</strong>&nbsp;</em>If you make a communication mistake, stay calm. If you make a big deal out of the problem or appear agitated, you’ll likely blow it out of proportion. Take a few deep breaths, calmly address the situation, and move on.</li></ul><ul><li><span><strong style="font-style: italic;">Be honest. Give a real reason.&nbsp;</strong>Whatever your reason is for ending a conversation, make sure it’s honest. Whether you said you were going back to work, grabbing a drink, or making a phone call, you need to follow through with that activity. Otherwise, the other person will likely notice and feel hurt by your dishonesty.</span></li></ul><ul><li><span><strong style="font-style: italic;">Keep practicing.&nbsp;</strong>No one becomes an expert communicator overnight. It takes practice. Push yourself out of your comfort zone, strike up conversations, and apply these techniques. The more opportunities you have to communicate, the more natural these skills will become.</span></li></ul><p></p><p></p><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-3-verbal-communication-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Know-how </strong>to write with purpose</li><li><strong>Select </strong>the right medium for written communication</li><li><strong>Know-how&nbsp;</strong>to write for your audience</li><li><strong>Know-how&nbsp;</strong>to structure your writing</li><li><strong>Improve </strong>your grammar, spelling and punctuation</li><li><strong>Edit and proofread </strong>your work</li><li><strong>Improve </strong>your business writing skills</li></ul><br><br><p></p></div>' WHERE slug = 'module-7-writing-well-learning-outcome';
