UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/893/mod_label/intro/3_Crisis%20Management.mp4?time=1709316314124">https://goalvow.com/upskilling/pluginfile.php/893/mod_label/intro/3_Crisis%20Management.mp4?time=1709316314124</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-crisis-management-lesson-3-preventing-and-preparing-for-a-crisis';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/894/mod_label/intro/4_Crisis%20Management.mp4?time=1709316361400">https://goalvow.com/upskilling/pluginfile.php/894/mod_label/intro/4_Crisis%20Management.mp4?time=1709316361400</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-crisis-management-lesson-4-responding-to-a-crisis';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/895/mod_label/intro/5_Crisis%20Management.mp4?time=1709316403647">https://goalvow.com/upskilling/pluginfile.php/895/mod_label/intro/5_Crisis%20Management.mp4?time=1709316403647</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-crisis-management-lesson-5-recovery-after-a-crisis';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr"></p><ul><li><strong>Don’t be overconfident.</strong> It’s easy to assume that a crisis won’t happen to you—until it does. Don’t leave yourself and your company vulnerable. Make crisis management a priority. Put together a crisis team to get started on crisis prevention and preparation.</li></ul><p></p><ul><li><strong>What could go wrong?</strong> An effective strategy for assessing your biggest risk factors is to ask yourself and your crisis team this question: What could go wrong? While it sounds pessimistic, it’s a practical strategy for evaluating the real threats to your business and creating a more optimistic future for your company.</li></ul><p></p><ul><li><strong>Aim to review your plan and conduct crisis training annually.</strong> Companies change, just like their environments and risk factors change. You need to review your crisis management plan and conduct crisis training at least once a year to ensure that it’s relevant and your crisis team is adequately prepared.</li></ul><p></p><ul><li><strong>Withdraw advertising that’s inappropriate in light of the crisis.</strong> Your crisis team may want to consider if you have any advertisements that are no longer appropriate to run. For example, you may decide to withdraw a commercial that highlights an automobile’s safety features in light of a recent product recall.</li></ul><p></p><ul><li><strong>Don’t dwell on the crisis.</strong> While it’s essential to handle the residual effects of a crisis on your business, team, and the public, you should also feel comfortable regaining a sense of normalcy and taking steps forward from the incident.</li></ul><p></p><ul><li>For some types of crises, such as natural disasters, don’t forget to fi le the appropriate insurance claims. There may even be grants or tax cuts that your business can apply for to seek further financial support.</li></ul><p><ul><li><strong>Interview your crisis response team, document what happened, and create a timeline.</strong> A good starting point for your PIR is to interview your crisis response team members. Document everything that happened, as well as the thinking behind each decision. Create a timeline that maps out what happened, and when it happened, to get a better picture of your crisis response.</li></ul></p><p></p></div>' WHERE slug = 'module-4-crisis-management-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>what is Emotional Intelligence (EQ)</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to implement strategies that will boost your Self-regulation</li><li><strong>Know-how&nbsp;</strong>to improve your Self-awareness</li><li><strong>Know-how&nbsp;</strong>to increase your Self-Motivation and develop empathy</li><li><strong>Improve and Hence </strong>your Social Skills</li></ul><br><p></p></div>' WHERE slug = 'module-3-emotional-intelligence-learning-outcome';
