UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/901/mod_label/intro/6_Emotional%20Intelligence.mp4?time=1709315894986">https://goalvow.com/upskilling/pluginfile.php/901/mod_label/intro/6_Emotional%20Intelligence.mp4?time=1709315894986</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-emotional-intelligence-lesson-6-enhancing-your-social-skills';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><span><strong>EQ starts with you.</strong> Emotional intelligence involves several components, but they all start with you. By\r\nbuilding your self-awareness, you’ll begin to recognize similar emotions in others. By learning self motivation, you’ll develop strategies for motivating a team. So, start small. Start thinking about your\r\nown feelings and reactions, and soon, you’ll improve your ability to understand and influence others.</span></li></ul><p></p><ul><li><strong>Keep practicing.</strong> A onetime reflection or feedback session isn’t enough. To develop self-awareness, you\r\nmust make a conscious, everyday commitment to practice awareness. So, make a habit of regularly\r\nchecking in with your experiences, noticing your feelings, and using every moment as an opportunity\r\nto learn more about yourself and your emotions.</li></ul><p></p><ul><li><strong>Don’t play the blame game.</strong> It’s easy to blame our situations for our reactions: “I’m angry because my\r\nstaff doesn’t get it!” But remember, you can choose how you react. So, the next time you feel a strong\r\nemotion, remember that you’re in control of your emotions, and it’s up to you to determine what\r\nhappens next.</li></ul><p></p><ul><li><strong>Motivation comes and goes.</strong> Don’t be dissuaded if you feel like your motivation is flatlining. Some days,\r\nyou’ll feel better than others. What’s important is not to feel defeated. If you’re feeling down on yourself,\r\npractice the tips covered in this lesson, know that everyone goes through ups and downs, and set your\r\nsights on getting back on your feet.</li></ul><p></p><ul><li><strong>Have deeper conversations.</strong> To understand where another person is coming from, you need to have\r\nconversations beyond the casual, “How are you?” or “Great weather today, huh?” Empathy requires asking\r\nyour staff real questions about their personal feelings, challenges, and motivations. So, don’t shy away\r\nfrom those deeper conversations—they’re the key to understanding what your employees are thinking\r\nand feeling.</li></ul><p><ul><li><strong>A long-term project.</strong> Social skills cover a lot of ground, and it’s not a competency that you can improve\r\novernight. So, don’t get frustrated if you’re struggling. Social skills are best thought of as a long-term\r\nproject. But that doesn’t mean you can’t start making small improvements every day. Continue to seek\r\nopportunities to connect with others and practice the skills covered in this lesson, and you’ll soon\r\nbecome an expert in this vital emotional competency.</li></ul></p><p><br></p><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-3-emotional-intelligence-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>what makes a good leader</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to engage and motivate employees as a leader</li><li><strong>Know-how&nbsp;</strong>to lead your team with a vision</li><li><strong>Know-how </strong>to become a better leader</li></ul><br><br><p></p></div>' WHERE slug = 'module-1-leadership-fundamentals-learning-outcome';
