UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/904/mod_label/intro/3_Leadership%20Fundamentals.mp4?time=1709313805421">https://goalvow.com/upskilling/pluginfile.php/904/mod_label/intro/3_Leadership%20Fundamentals.mp4?time=1709313805421</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-leadership-fundamentals-lesson-3-leading-with-vision';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/905/mod_label/intro/4_Leadership%20Fundamentals.mp4?time=1709313848548">https://goalvow.com/upskilling/pluginfile.php/905/mod_label/intro/4_Leadership%20Fundamentals.mp4?time=1709313848548</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-leadership-fundamentals-lesson-4-six-practices-to-become-a-better-leader';
UPDATE lessons SET content = '<div class="no-overflow"><p><strong>Summary</strong></p><ul><li><strong>Invest in yourself.</strong>&nbsp;Effective leadership skills take time and effort to develop. Invest in accelerating your growth. Find a mentor. Seek out in-person workshops or live seminar trainings. Join a professional group, or, build your library of leadership development books.</li></ul><ul><li><strong>Encourage employees to be themselves.</strong>&nbsp;Leaders may unknowingly create tension and resentment when they expect employees to act the way they do or be motivated by the same factors. Recognize employees for their individuality. Pay less attention to the things that they aren’t doing and more to the things that they’re naturally attracted to, skilled in, or that complement their personality and interests. Encourage employees to be their authentic selves, and then call on their natural strengths to achieve desired outcomes.</li></ul><p></p><ul><li><strong>Be relentless in the pursuit of your vision. </strong>Your job isn’t over once you’ve developed your vision statement. It’s just begun. Create a strategy and action plan for realizing it. Communicate your vision often enough that employees know it by heart. Also, make sure that your actions and organizational decisions support and align with your vision.</li></ul><p><ul><li><strong>Never stop improving.</strong> Approach leadership development as a continuous process. Seek continuous feedback on how you can improve as a leader or create a better workplace. See what works, find out what doesn’t, and keep adjusting and honing your skills.</li></ul></p></div>' WHERE slug = 'module-1-leadership-fundamentals-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>different types of leadership styles that can boost performance.</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to implement different leadership styles</li><li><strong>Know-when </strong>to use each leadership style</li><li><strong>Know-how </strong>to use each leadership style</li></ul><br><p></p></div>' WHERE slug = 'module-2-leadership-styles-learning-outcome';
