UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/910/mod_label/intro/5_Leadership%20Style.mp4?time=1709315431821">https://goalvow.com/upskilling/pluginfile.php/910/mod_label/intro/5_Leadership%20Style.mp4?time=1709315431821</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-leadership-styles-lesson-5-what-is-transactional-leadership';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/911/mod_label/intro/6_Leadership%20Style.mp4?time=1709315478120">https://goalvow.com/upskilling/pluginfile.php/911/mod_label/intro/6_Leadership%20Style.mp4?time=1709315478120</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-leadership-styles-lesson-6-what-is-transformational-leadership';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p><strong>Summary</strong></p><ul><li><strong>Listen to your team.</strong> Pay attention to your team. Stay receptive to their personalities and needs.\r\nRemember, great leadership is not only about what works for you, but what works for the group as a\r\nwhole.</li></ul><p></p><ul><li><strong>Be available.</strong> Even though the laissez-faire style is a hands-off approach, it doesn’t mean you can ignore\r\nyour staff. You must continue to monitor your employees, look out for signs of distress, and remain\r\navailable. Continue to offer support from a distance and never leave the group stranded without a life\r\nvest.</li></ul><p></p><ul><li><strong>Don’t ignore the benefits.</strong> Autocratic leadership can feel like a negative and unpopular approach. But in\r\nthe right situation, it might be your best option. If your team is highly disorganized, if your projects are\r\ngetting out of hand, or if you’re in a crisis, don’t shy away from an autocratic style. It might be the very\r\nthing that saves your company—and remember, it doesn’t need to be forever.</li></ul><p></p><ul><li><strong>Create an inclusive environment.</strong> Inclusivity extends past the decision-making stage. To be a successful\r\ndemocratic leader, you must create a space where equality is part of your company makeup. You can’t\r\nturn inclusion on and off. Rather, you must create an environment where group members are eager to\r\nshare their knowledge—both inside and outside the meeting room.</li></ul><p></p><ul><li><strong>Improve your communication skills.</strong> As a transactional leader, you set the goals, procedures, and\r\nexpectations. However, if your team doesn’t understand those rules, the style falls apart. So, always\r\ncommunicate goals clearly, give guidance, offer feedback, and give your staff ample time to ask\r\nquestions. That communication can make the difference between achievement and failure.</li></ul><p></p><ul><li><strong>Change is ongoing.</strong> Transformational change is ongoing. And to be successful in applying this style, you\r\nmust avoid getting caught up in outdated ideas that no longer work. Make a habit of doing regular self checks by asking the following questions: How can we make things better? Can we streamline any\r\nsystems? Is anything no longer working?</li></ul><p></p><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-2-leadership-styles-module-summary';
