UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/914/mod_label/intro/3_Building%20Career%20Resilience.mp4?time=1710072990791">https://goalvow.com/upskilling/pluginfile.php/914/mod_label/intro/3_Building%20Career%20Resilience.mp4?time=1710072990791</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-building-career-resilience-lesson-3-taking-ownership-of-your-career';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Begin by looking inward.&nbsp;</strong>Developing a lifelong-learner mindset requires introspection. Start by reflecting on your strengths and weaknesses, and let your self-evaluation inspire you. Ask yourself:&nbsp;<em>What do I want to know more about? What skills could use some updating? How can I master this subject further?</em></li></ul><p></p><ul><li><span><strong style="">Always respect boundaries.&nbsp;</strong>What may build rapport with one person may not work with another. And keep in mind that different organizations have different cultures. When in doubt, err on the side of being professional.</span></li></ul><p></p><ul><li><strong>It’s OK to progress as an individual contributor.&nbsp;</strong>Many mistakenly believe the only way to advance professionally is to become a people manager. If a supervisory role doesn’t appeal to you, it’s OK to focus on maximizing your individual contributions instead. There will be opportunities no matter your goals; the key is to know what you’re looking for and seize it when you can.</li></ul><p><br></p><p><br></p><p></p><p></p><p></p></div>' WHERE slug = 'module-2-building-career-resilience-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li>Have the&nbsp;<strong>capability</strong>&nbsp;to boost resilience through self-awareness<br></li><li><strong>Know-how&nbsp;</strong>to increase your mental agility</li><li><strong>Know-how&nbsp;</strong>to boost your emotional self-regulation and resilience</li><li><strong>Develop </strong>a healthy optimism</li><li><strong>Maintain </strong>physical resilience</li></ul><br><p></p></div>' WHERE slug = 'module-4-emotional-and-physical-resilience-learning-outcome';
