UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/919/mod_label/intro/5_Emotional%20and%20Physical%20Resilience.mp4">https://goalvow.com/upskilling/pluginfile.php/919/mod_label/intro/5_Emotional%20and%20Physical%20Resilience.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-emotional-and-physical-resilience-lesson-5-tips-for-maintaining-physical-resilience';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Practice being present.&nbsp;</strong>While thinking about the past can be helpful, it may also cause you to stay stuck in negative thinking. When a negative thought arises, notice and learn from it, and avoid rumination.</li></ul><p></p><ul><li><strong>Try setting focus time.&nbsp;</strong>Distractions, even when they’re passed off as “multi-tasking,\'\' can drain mental resources. Get an extra agility boost by blocking time to focus on your creative problem-solving efforts.</li></ul><ul><li><strong>Reach out for help.</strong>&nbsp;It’s normal to feel overwhelmed by emotions. But if you’re struggling to cope with persistent complicated feelings, a therapist or professional counselor can provide deeper guidance and support.</li></ul><p></p><ul><li>Your&nbsp;<strong>outlook</strong>&nbsp;is powerful armor that can shield you against life’s demands and disappointments—and advance you toward goals.</li></ul><p><ul><li><strong>Change the narrative.</strong>&nbsp;The stories we tell ourselves have power. If we focus on faults and weaknesses, we reinforce negative pathways in the brain. Rewrite your story to concentrate on your compassion, resilience, and adaptability instead.</li></ul></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-4-emotional-and-physical-resilience-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li>Have the&nbsp;<strong>capability</strong>&nbsp;to implement strategies to become a resilient leader<br></li><li><span>Have the </span><strong>capability </strong>to lead through a challenge</li><li><strong>Know-how&nbsp;</strong>to build a resilient team</li></ul><br><br><p></p></div>' WHERE slug = 'module-3-leadership-and-resilience-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2083/mod_resource/content/2/Leadership%20and%20Resilience%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Leadership and Resilience Course Material.pdf</a></p>' WHERE slug = 'module-3-leadership-and-resilience-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp; &nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/920/mod_label/intro/1_Leadership%20and%20Resilience.mp4?time=1710073098220">https://goalvow.com/upskilling/pluginfile.php/920/mod_label/intro/1_Leadership%20and%20Resilience.mp4?time=1710073098220</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-leadership-and-resilience-lesson-1-strategies-to-become-a-resilient-leader';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/921/mod_label/intro/2_Leadership%20and%20Resilience.mp4?time=1710073138586">https://goalvow.com/upskilling/pluginfile.php/921/mod_label/intro/2_Leadership%20and%20Resilience.mp4?time=1710073138586</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-leadership-and-resilience-lesson-2-leading-through-a-challenge';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/922/mod_label/intro/3_Leadership%20and%20Resilience.mp4?time=1710073183275">https://goalvow.com/upskilling/pluginfile.php/922/mod_label/intro/3_Leadership%20and%20Resilience.mp4?time=1710073183275</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-leadership-and-resilience-lesson-3-building-a-resilient-team';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Building resilience takes time.&nbsp;</strong>Nothing important happens overnight. Instead of expecting instant results, look for ways to train yourself, practice your skills, and reflect on your progress. Small steps every day can make a big impact on your resilient leadership skills.</li></ul><p></p><ul><li><strong>Stay positive.&nbsp;</strong>The attitude you approach a challenge with is contagious. You can inspire your team by focusing on your organization’s core values and the positive impact you make on clients, customers, and employees.</li></ul><p><ul><li><strong>No one can predict what will happen in the future. </strong>That’s why building team resilience is worth the investment. No matter what happens, resilient teams can handle the obstacles that come their way.</li></ul></p><p></p><p></p></div>' WHERE slug = 'module-3-leadership-and-resilience-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>employee resilience</li><li><strong>Know-how&nbsp;</strong>to build a resilient team&nbsp;<br></li><li><strong>Build </strong>five pillars of personal resilience</li></ul><br></div>' WHERE slug = 'module-1-resilience-fundamentals-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2081/mod_resource/content/2/Resilience%20Fundamentals%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Resilience Fundamentals Course Material.pdf</a></p>' WHERE slug = 'module-1-resilience-fundamentals-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2742/mod_label/intro/1_Resilience%20Fundamentals.mp4?time=1710072663591">https://goalvow.com/upskilling/pluginfile.php/2742/mod_label/intro/1_Resilience%20Fundamentals.mp4?time=1710072663591</video>&nbsp;</div>' WHERE slug = 'module-1-resilience-fundamentals-lesson-1-what-is-employee-resilience';
UPDATE lessons SET content = '<div class="no-overflow">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/924/mod_label/intro/2_Resilience%20Fundamentals.mp4?time=1710072710289">https://goalvow.com/upskilling/pluginfile.php/924/mod_label/intro/2_Resilience%20Fundamentals.mp4?time=1710072710289</video>&nbsp;</div>' WHERE slug = 'module-1-resilience-fundamentals-lesson-2-how-to-build-a-resilient-team';
UPDATE lessons SET content = '<div class="no-overflow">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/925/mod_label/intro/3_Resilience%20Fundamentals.mp4?time=1710072748848">https://goalvow.com/upskilling/pluginfile.php/925/mod_label/intro/3_Resilience%20Fundamentals.mp4?time=1710072748848</video>&nbsp;</div>' WHERE slug = 'module-1-resilience-fundamentals-lesson-3-the-5-pillars-of-personal-resilience';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong><strong>Summary</strong></strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong><strong>Resilience is a moving target.&nbsp;</strong></strong>Your resilience may dip from one day to the next, depending on many factors. Moods, sleep, health, relationships, and even the weather can impact your resilience. Beating yourself up won’t help. Instead, focus on recognizing the factors that keep it in flux. &nbsp;</li></ul><p></p><ul><li><strong>Give yourself options.&nbsp;</strong>There are many tools in the resilience toolkit: one-on-one or peer-to-peer coaching, facilitated group discussion, online or in-person classes, apps, and assessments. Some techniques utilize professionals, and others are “do-it-yourself.” Try various methods to identify what works best for you and your team. &nbsp;</li></ul><p><ul><li><strong>Gain a leg up with planning.&nbsp;</strong>Setting small goals is a helpful complementary tactic to overcome general stress or a specific problem at hand. Keeping these goals realistic and grounded in your values will help maintain a positive outlook.&nbsp;</li></ul></p><p></p><p></p></div>' WHERE slug = 'module-1-resilience-fundamentals-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>how to cope with challenges</li><li><strong>Manage </strong>your response to workplace conflict</li><li><strong>Know-how </strong>rest makes you more resilient</li><li><strong>Adapt </strong>and become resilient</li><li><strong>Step </strong>outside your comfort zone</li><li><strong>Use </strong>criticism and rejection to your advantage and grow</li><li><strong>Make Strategies </strong>for turning challenges into opportunities</li></ul><br><p></p></div>' WHERE slug = 'module-5-thriving-through-challenges-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2085/mod_resource/content/2/Thriving%20Through%20Challenges%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Thriving Through Challenges Course Material.pdf</a></p>' WHERE slug = 'module-5-thriving-through-challenges-module-reading-material';
