UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/931/mod_label/intro/6_Thriving%20Through%20Challenges.mp4?time=1710073880378">https://goalvow.com/upskilling/pluginfile.php/931/mod_label/intro/6_Thriving%20Through%20Challenges.mp4?time=1710073880378</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-thriving-through-challenges-lesson-6-using-criticism-and-rejection-to-grow';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/932/mod_label/intro/7_Thriving%20Through%20Challenges.mp4?time=1710073921735">https://goalvow.com/upskilling/pluginfile.php/932/mod_label/intro/7_Thriving%20Through%20Challenges.mp4?time=1710073921735</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-thriving-through-challenges-lesson-7-strategies-for-turning-challenges-into-opportunities';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><b>Summary</b></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Try a new view.&nbsp;</strong>Reframe tough challenges as a chance to grow. A positive outlook can make what seems impossible into an exciting opportunity.</li></ul><p></p><ul><li><strong>Know your company’s culture.&nbsp;</strong>Note how your company prefers to handle conflict and how they’ve approached past conflicts to help shape your strategy. That way, you can integrate the tips you’ve learned the next time a conflict arises while staying true to company values.&nbsp;</li></ul><p></p><ul><li><strong>Know your values.&nbsp;</strong>Overcoming an obstacle doesn’t always have to result in major changes, especially if those changes don’t align with your company’s values. When a challenge arises, don’t compromise your principles for short-term progress. The temptation to take shortcuts or bend the rules increases as you struggle to stay relevant. A strong moral and ethical compass points you to the best path forward.</li></ul><p></p><ul><li><strong>Remember—rejection doesn’t have to define you.&nbsp;</strong>When criticism knocks you down, reconnect to your purpose and goals, then get up and try again.</li></ul><p><ul><li><strong>Focusing on solutions doesn’t mean minimizing your feelings.&nbsp;</strong>When bad things happen, it’s OK to have negative emotions. Minimizing these feelings can lead to toxic positivity—or the belief that a positive attitude must be maintained at all costs. Turning challenges into opportunities isn’t about ignoring the bad—it’s about understanding that good things can sometimes come from bad situations.</li></ul></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-5-thriving-through-challenges-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>the fundamentals of problem solving</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to manage complicated problems</li><li><strong>Form </strong>a team of top skills and implement strategies for effective problem solving</li><li><strong>Know-how&nbsp;</strong>to overcome barriers for effective problem solving</li><li><strong>Know-how </strong>to grow your problem solving skills</li></ul><br><br><p></p></div>' WHERE slug = 'module-1-problem-solving-fundamentals-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2115/mod_resource/content/2/Problem%20Solving%20Fund%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Problem Solving Fund Course Material.pdf</a></p>' WHERE slug = 'module-1-problem-solving-fundamentals-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2954/mod_label/intro/1_Problem%20Solving%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2954/mod_label/intro/1_Problem%20Solving%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-problem-solving-fundamentals-lesson-1-introduction-to-problem-solving';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2955/mod_label/intro/2_Problem%20Solving%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2955/mod_label/intro/2_Problem%20Solving%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-problem-solving-fundamentals-lesson-2-managing-complicated-vs-complex-problems';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2956/mod_label/intro/3_Problem%20Solving%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2956/mod_label/intro/3_Problem%20Solving%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-problem-solving-fundamentals-lesson-3-top-skills-and-strategies-for-effective-problem-solving';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2957/mod_label/intro/4_Problem%20Solving%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2957/mod_label/intro/4_Problem%20Solving%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-problem-solving-fundamentals-lesson-4-overcoming-barriers-to-effective-problem-solving';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2958/mod_label/intro/5_Problem%20Solving%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2958/mod_label/intro/5_Problem%20Solving%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-problem-solving-fundamentals-lesson-5-how-to-grow-your-problem-solving-skills';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>I’m going to sleep on it.</strong>&nbsp;Ever heard someone say,<em>&nbsp;“I’m going to sleep on it”</em>? There’s merit to giving your brain an extended, overnight break from a problem. Sleep allows your brain to make deeper connections between unrelated ideas, meaning you may wake up not only feeling rested but also with the perfect solution to your problem.</li></ul><p></p><ul><li><strong>Try, learn, and adapt.</strong>&nbsp;Use a “try, learn, and adapt” approach when working on complex problems.&nbsp;<em>Try</em>&nbsp;out various strategies,&nbsp;<em>learn</em>&nbsp;from them, and then&nbsp;<em>adapt</em>&nbsp;your next steps appropriately. In this way, you can manage complex problems rather than trying to achieve a straight-line solution.</li></ul><p></p><ul><li><strong>Overcome silos when problem-solving.</strong>&nbsp;In the workplace, a silo is a team or group of individuals hoarding information and resources for their own benefit. When problems arise, teams may be unwilling to work cross-departmentally to solve them. Even if silos exist at your company, strive to be a team player. For example, you can offer to join in on brainstorming sessions when other teams face challenges or share useful data your team has compiled.</li></ul><p></p><ul><li><strong>Use trial and error to overcome barriers.&nbsp;</strong>You might not overcome a problem-solving barrier the first time. In fact, you’ll probably need to attempt it multiple times before you achieve success. If you have a limited number of strategies in mind when facing an obstacle, a trial-and-error approach can be useful. First, narrow down your strategies to the ones you think will be most successful. Then, implement each one, ruling out those that don’t work, until you overcome the obstacle.</li></ul><p><ul><li><strong>Learn from effective problem-solvers.&nbsp;</strong>One of the best ways to grow your problem-solving skills is to watch what the pros do. Effective leaders are often great problem-solvers. They have all the skills needed to achieve successful outcomes, such as professionalism, positivity, communication, creativity, and commitment. If there are any effective leaders in your workplace, consider asking them to mentor you through your problem-solving journey. You’ll likely witness them putting the strategies we covered into practice.</li></ul></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-1-problem-solving-fundamentals-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Know-how </strong>to define a problem and identify its root cause</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to brainstorm solutions to a problem</li><li><strong>Know-how&nbsp;</strong>to research and evaluate possible solutions to problems</li><li><strong>Implement</strong> the best solution to problem</li><li><strong>Know-how </strong>to evaluate your results for your solutions to problems</li></ul><br><br><p></p></div>' WHERE slug = 'module-3-steps-to-problem-solving-learning-outcome';
