UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2966/mod_label/intro/3_Steps%20to%20Problem%20Solving.mp4">https://goalvow.com/upskilling/pluginfile.php/2966/mod_label/intro/3_Steps%20to%20Problem%20Solving.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-steps-to-problem-solving-lesson-3-researching-and-evaluating-possible-solutions-when-problem-solving';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2967/mod_label/intro/4_Steps%20to%20Problem%20Solving.mp4">https://goalvow.com/upskilling/pluginfile.php/2967/mod_label/intro/4_Steps%20to%20Problem%20Solving.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-steps-to-problem-solving-lesson-4-implementing-the-best-solution-to-a-problem';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2968/mod_label/intro/5_Steps%20to%20Problem%20Solving.mp4">https://goalvow.com/upskilling/pluginfile.php/2968/mod_label/intro/5_Steps%20to%20Problem%20Solving.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-steps-to-problem-solving-lesson-5-evaluating-your-results-when-problem-solving';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Better understand your successes, too.</strong>&nbsp;Root cause analysis isn’t only for analyzing the cause of a problem. You can use it to understand your successes better, as well. The next time your team experiences a “win,” use root cause analysis to find the root cause of that win. What is the source? What caused your team to achieve this success? This process can be a positive experience for your team, and it also can help you translate your success to different areas of your business.</li></ul><p></p><ul><li><strong>Brainstorm bad ideas first.&nbsp;</strong>There’s a lot of pressure during a brainstorming meeting to come up with the most creative ideas. To help your team relax, start your session by having everyone throw out the worst ideas they can think of. That will help get the creative juices flowing as well as make clear that all ideas are welcome.</li></ul><p></p><ul><li><strong>Nix impossible solutions.&nbsp;</strong>If a potential solution clearly won’t work, don’t waste time and resources continuing to research it. For example, if you have a solution that you discover would take two months to implement, but you only have one month, you should eliminate it. That way, you can free up your team to explore other options more thoroughly.</li></ul><p></p><ul><li><strong>Keep the lines of communication open.&nbsp;</strong>People affected by your problem should be kept apprised of how it’s being solved. For example, if you operate a local food delivery service and your truck breaks down, you need to communicate the issue to your customers along with the steps you’re taking to fulfill their orders and fix the problem. By keeping your stakeholders in the know, you can build trust, develop support for your solution, and minimize potential public relations disasters. Social media is a great tool for not only quickly reaching your audience with information but also giving them a platform to be heard. Other options include notifying an email list, holding a press conference, or calling a company meeting.</li></ul><p><ul><li><strong>Measure what really matters.</strong>&nbsp;When it comes to KPIs, more is not better. Incorporating too many KPIs when problem-solving can easily become overwhelming. Remember that&nbsp;<em>key</em>&nbsp;refers to&nbsp;<em>most important</em>. To focus on the KPIs with the highest priority, limit yourself to three per goal.</li></ul></p><p><br></p><p><br></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-3-steps-to-problem-solving-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Lead </strong>problem solving that will bring effective solutions</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to cultivate a culture that fosters creative problem solving</li><li><strong>Know-how&nbsp;</strong>to solve problems as a team</li><li><strong>Know-how&nbsp;</strong>to prioritize workplace problems</li></ul><br><br><p></p></div>' WHERE slug = 'module-2-problem-solving-in-the-workplace-learning-outcome';
