UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2960/mod_label/intro/2_Problem%20Solving%20in%20the%20Workplace.mp4">https://goalvow.com/upskilling/pluginfile.php/2960/mod_label/intro/2_Problem%20Solving%20in%20the%20Workplace.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-problem-solving-in-the-workplace-lesson-2-cultivating-a-culture-that-fosters-creative-problem-solving';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2961/mod_label/intro/3_Problem%20Solving%20in%20the%20Workplace.mp4">https://goalvow.com/upskilling/pluginfile.php/2961/mod_label/intro/3_Problem%20Solving%20in%20the%20Workplace.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-problem-solving-in-the-workplace-lesson-3-solving-problems-as-a-team';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2962/mod_label/intro/4_Problem%20Solving%20in%20the%20Workplace.mp4">https://goalvow.com/upskilling/pluginfile.php/2962/mod_label/intro/4_Problem%20Solving%20in%20the%20Workplace.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-problem-solving-in-the-workplace-lesson-4-prioritizing-workplace-problems';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Seek a mentor.&nbsp;</strong>Do you know any effective leaders at your workplace? Consider asking them to mentor or coach you when you’re facing problems. Most people are happy to assist, and you may even strengthen your professional relationships in the process.</li></ul><p></p><ul><li><strong>Set aside time for team-building activities.</strong>&nbsp;If you’ve ever participated in an “ice breaker” exercise during a meeting, you know its value. By the end of the ice breaker, there’s usually a greater sense of trust and relaxation among the group. Why? Because participants formed a connection with each other, even if just a slight one. If a simple ice breaker can have that kind of impact, imagine the result of regular team-building activities. A close-knit team is much more likely to be transparent and open to others’ ideas than a disconnected one.</li></ul><p></p><ul><li><strong>Create opportunities for success from the outset.</strong>&nbsp;There’s a saying that “success breeds success.” When you achieve something, you generally feel confident that you’ll be able to accomplish it again. The same is true for collaborative problem-solving. When a problem-solving team is first starting out, create opportunities for the group to be successful—perhaps, by assigning them a minor problem to tackle first or providing extra support when needed.</li></ul><p><ul><li><strong>Delegate busywork.&nbsp;</strong>Sometimes, “busywork”—or mundane and low-value tasks—is unavoidable. You just have to do it to keep things running smoothly. However, when possible (and if appropriate to your job role), delegate the busywork to someone else. Focus on the tasks that carry the greatest value for yourself and your company. You’ll not only feel more fulfilled by doing so, but you’ll also position yourself as a valuable asset to your company.</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-2-problem-solving-in-the-workplace-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>the divergent and convergent thinking</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to mitigate the risk of heuristics in problem solving</li><li><strong>Know-how&nbsp;</strong>to reframe problems for innovative solutions</li><li><strong>Implement </strong>design thinking compared to traditional problem solving</li></ul><br><p></p></div>' WHERE slug = 'module-4-advanced-problem-solving-learning-outcome';
