UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2970/mod_label/intro/2_Advance%20Problem%20Solving.mp4">https://goalvow.com/upskilling/pluginfile.php/2970/mod_label/intro/2_Advance%20Problem%20Solving.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-advanced-problem-solving-lesson-2-the-risk-of-heuristics-in-problem-solving';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2971/mod_label/intro/3_Advance%20Problem%20Solving.mp4">https://goalvow.com/upskilling/pluginfile.php/2971/mod_label/intro/3_Advance%20Problem%20Solving.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-advanced-problem-solving-lesson-3-reframing-problems-for-innovative-solutions';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2972/mod_label/intro/4_Advance%20Problem%20Solving.mp4">https://goalvow.com/upskilling/pluginfile.php/2972/mod_label/intro/4_Advance%20Problem%20Solving.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-advanced-problem-solving-lesson-4-design-thinking-vs-traditional-problem-solving';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Write out your ideas.&nbsp;</strong>Regardless of whether you’re a creative thinker or an analytical one, getting your thoughts down on paper or a computer screen can help you visualize and organize them. You could use a mind map, journal entry, pros-and-cons list, or something similar. Jotting down ideas during both modes of thought also helps ensure that you dedicate time to each part of the problem-solving process.</li></ul><p></p><ul><li><strong>Get a second opinion.</strong>&nbsp;Because we use heuristics unintentionally, bias and error can creep into our thought processes under the radar. To guard against this, talk through your perspective and possible solutions with a coworker, friend, or family member. Get their opinions and thoughts about the situation. By doing so, you can uncover holes in your thinking, and you may even discover a more effective way to solve an issue you’re facing.</li></ul><p></p><ul><li><strong>Make an honest assessment of your mindset.&nbsp;</strong>If you find that you’re generally married to your solutions and resistant to others’ ideas, you likely need to use reframing when problem-solving. No one is always right. Be honest with yourself about your need to consider other perspectives. You can take steps in that direction by intentionally asking a coworker or friend for feedback about your grasp of an issue. Then, seriously consider what they have to say, and adjust your strategy as needed.</li></ul><p><ul><li><strong>Start small when implementing design thinking.&nbsp;</strong>Initially, your team or coworkers might be resistant to using design thinking—especially if the traditional approach to problem-solving is their go-to. To ease them into the design thinking mindset, start small. Use design thinking to tackle a low-risk issue or challenge, such as planning a team party. That way, you’ll be more likely to achieve success and demonstrate the benefits of this method.</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-4-advanced-problem-solving-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Create </strong>a distraction-free and productive work environment</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to adopt healthy habits to stay focused</li><li><strong>Know-why </strong>and <strong>how </strong>to stop multitasking</li><li><strong>Know-how&nbsp;</strong>to manage your energy and not your time</li></ul><br><br><p></p></div>' WHERE slug = 'module-5-concentration-learning-outcome';
