UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/990/mod_label/intro/5_Concentration%20for%20Time%20Management.mp4">https://goalvow.com/upskilling/pluginfile.php/990/mod_label/intro/5_Concentration%20for%20Time%20Management.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-concentration-lesson-5-how-to-manage-your-energy-not-your-time';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Talk to your manager.&nbsp;</strong>If you’re struggling to be productive in your work environment, consider checking in with your manager. Too often, managers aren’t aware of the workspace challenges their employees face each day. At your next one-on-one, share a list of the issues you’re facing and solutions you’d like to implement.</li></ul><p></p><ul><li><strong>Listen to music.&nbsp;</strong>It can be challenging to focus on your work when you can hear coworkers talking—phones ringing—or the copy machine running in the background. Listening to music is one way that you can mask background noise and avoid distractions. Consider classical music, nature sounds, or ambient music without lyrics. Choose music that’s soft and subtle enough that it doesn’t become a distraction in and of itself.</li></ul><p></p><ul><li><strong>Establish routines to reduce decision-making.</strong>&nbsp;Decision fatigue is a real thing. To reduce the number of decisions you make in a day, try creating routines. For example, plan your meals at the beginning of every week. Or, set regular times to work on recurring tasks. Even small decisions add up, and routines can make small decisions feel automatic.</li></ul><p></p><ul><li><strong>Use your transition times wisely.&nbsp;</strong>Use the transition times between tasks to take a break and recharge before starting something new. By taking a break in-between tasks, you’ll have more energy to finish the job–instead of stopping or switching tasks halfway through.</li></ul><p><ul><li><strong>Experiment to discover what works for&nbsp;<em>you</em>.&nbsp;</strong>Not everyone feels energized or depleted by the same things. Experiment with different ways to energize yourself—and keep modifying or adapting your approach until you find what works best for&nbsp;<em>you</em>.</li></ul></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-5-concentration-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Know-what </strong>time management</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to filter symptoms of poor time management</li><li><strong>Manage </strong>your time effectively at work</li><li><strong>Track and analyze </strong>your time usage</li></ul><br><p></p></div>' WHERE slug = 'module-1-time-management-fundamentals-learning-outcome';
