UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/944/mod_label/intro/3_Time%20Management%20Fundamentals.mp4?time=1709880322338">https://goalvow.com/upskilling/pluginfile.php/944/mod_label/intro/3_Time%20Management%20Fundamentals.mp4?time=1709880322338</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-time-management-fundamentals-lesson-3-seven-tips-for-effective-time-management-at-work';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/945/mod_label/intro/4_Time%20Management%20Fundamentals.mp4?time=1709880441450">https://goalvow.com/upskilling/pluginfile.php/945/mod_label/intro/4_Time%20Management%20Fundamentals.mp4?time=1709880441450</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-time-management-fundamentals-lesson-4-tracking-and-analyzing-how-you-use-your-time';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><b>Summary</b></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Start small.&nbsp;</strong>Getting organized with your time can feel overwhelming at first. If you’re feeling overwhelmed, then start small. Try focusing on changing one habit that’s wasting time. Or brainstorm how you might use just&nbsp;<em>30 minutes</em>&nbsp;of your workday more productively. Small changes can deliver big rewards.</li></ul><p></p><ul><li><strong>Time management is a learned skill.&nbsp;</strong>Keep practicing, and remind yourself that you can develop your skills with effort and time.</li></ul><p></p><ul><li><strong>Put your waiting time to work.&nbsp;</strong>Most of us waste a decent amount of time waiting in lines, commuting, or sitting in waiting rooms. Why not put that time to work? Check emails on your phone while you’re sitting in a waiting room. Think about a complex work problem when you’re standing in line or waiting for the coffee to brew. Or, bring some work with you while you’re commuting on the bus or train.</li></ul><p></p><ul><li><strong>Monitor your progress.&nbsp;</strong>Always monitor your progress after implementing changes from time tracking. After a month or two have passed, track your time again, and see how you’re doing. What’s working well? What&nbsp;<em>isn’t</em>&nbsp;working well? Continue to make adjustments and fine-tune how you manage your time.</li></ul><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-1-time-management-fundamentals-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Know-how </strong>to prioritize tasks by urgency and importance</li><li><strong>Know-how&nbsp;</strong>to avoid the top six time-wasters in the workplace&nbsp;</li><li><strong>Understand</strong> and manage procrastination</li></ul><br><br><p></p></div>' WHERE slug = 'module-4-prioritization-learning-outcome';
