UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/937/mod_label/intro/1_Prioritization.mp4?time=1709881341020">https://goalvow.com/upskilling/pluginfile.php/937/mod_label/intro/1_Prioritization.mp4?time=1709881341020</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-prioritization-lesson-1-how-to-prioritize-tasks-by-urgency-and-importance';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/938/mod_label/intro/2_Prioritization.mp4?time=1709881481563">https://goalvow.com/upskilling/pluginfile.php/938/mod_label/intro/2_Prioritization.mp4?time=1709881481563</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-prioritization-lesson-2-how-to-avoid-the-top-six-time-wasters-in-the-workplace';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/939/mod_label/intro/3_Prioritization.mp4?time=1709881520291">https://goalvow.com/upskilling/pluginfile.php/939/mod_label/intro/3_Prioritization.mp4?time=1709881520291</video>&nbsp;<br></p></div>' WHERE slug = 'module-4-prioritization-lesson-3-understanding-and-managing-procrastination';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li>If you’re having trouble assessing the urgency and importance of a task, try asking yourself this question:&nbsp;<em>“What are the consequences if this task does&nbsp;<strong>not</strong>&nbsp;get done?”</em></li></ul><p></p><ul><li><strong style="">Label and organize your files.&nbsp;</strong>A final tip is to stop wasting time looking for (or losing!) those elusive financial reports or new-hire interview questions. Create clear labels for your files and organize them in an easy-to-navigate folder system so that you can always find what you need when you need it.&nbsp;</li></ul><p></p><ul><li><strong style="">Set deadlines for yourself and verbalize your commitments to others.&nbsp;</strong>You can increase your accountability—and make it more difficult for yourself to procrastinate—by setting deadlines and verbalizing your commitments to others. For example, you might tell your boss,&nbsp;“I’ll have X done by the end of today.”&nbsp;Even if the task isn’t due until the end of the week, you’ll be more likely to tackle it the same day if that’s what you promised someone else.</li></ul><p></p><p></p><p></p></div>' WHERE slug = 'module-4-prioritization-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>the importance of scheduling and how to schedule your time</li><li><strong>Know-how&nbsp;</strong>to estimate the time needed to complete tasks<br></li><li><strong>Use </strong>best good practice for time management scheduling&nbsp;</li></ul><br><br><p></p></div>' WHERE slug = 'module-3-scheduling-learning-outcome';
