UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/940/mod_label/intro/1_Scheduling.mp4?time=1709881116632">https://goalvow.com/upskilling/pluginfile.php/940/mod_label/intro/1_Scheduling.mp4?time=1709881116632</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-scheduling-lesson-1-the-importance-of-scheduling-and-how-to-schedule-your-time';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/941/mod_label/intro/2_Scheduling.mp4?time=1709881152561">https://goalvow.com/upskilling/pluginfile.php/941/mod_label/intro/2_Scheduling.mp4?time=1709881152561</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-scheduling-lesson-2-how-to-estimate-the-time-needed-to-complete-tasks';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/942/mod_label/intro/3_Scheduling.mp4?time=1709881187888">https://goalvow.com/upskilling/pluginfile.php/942/mod_label/intro/3_Scheduling.mp4?time=1709881187888</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-scheduling-lesson-3-five-scheduling-tips-for-time-management';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Set aside regular time for scheduling.&nbsp;</strong>For example, set aside time to create a new schedule at the beginning of each day, week, or month. Scheduling is an ongoing process, not a one-time event.</li></ul><p></p><ul><li><strong>Be realistic.&nbsp;</strong>Avoid estimating how long a task will take you to complete in an “ideal scenario” or a situation that’s devoid of interruptions, setbacks, or delays. Ideal estimates rarely hold up in practice. Instead, embrace the reality of your situation and limitations.</li></ul><p><ul><li><strong>Change the default meeting time to 15 minutes.&nbsp;</strong>Many online calendars have the default meeting or duration of appointment time set to 30 minutes. So, people schedule 30-minute meetings without thinking about whether they actually need the full 30 minutes. Lower the default to 15 minutes to encourage more concise meetings and to make yourself and others think critically about how long a meeting needs to be.</li></ul></p><p></p><p></p></div>' WHERE slug = 'module-3-scheduling-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Know-how </strong>to avoid taking on too much at work</li><li><strong>Manage </strong>distractions effectively</li><li><strong>Know-how&nbsp;</strong>to end the cycle of lateness</li><li><strong>Know-how </strong>and <strong>why </strong>to cut back on meetings</li><li><strong>Take </strong>control of your inbox</li><li><strong>Adopt </strong>healthy habits to help you stay focused</li></ul><br><br><p></p></div>' WHERE slug = 'module-6-overcoming-time-challenges-learning-outcome';
