UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/949/mod_label/intro/3_Overcoming%20Challenges.mp4">https://goalvow.com/upskilling/pluginfile.php/949/mod_label/intro/3_Overcoming%20Challenges.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-overcoming-time-challenges-lesson-3-how-to-end-the-cycle-of-lateness';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/950/mod_label/intro/4_Overcoming%20Challenges.mp4">https://goalvow.com/upskilling/pluginfile.php/950/mod_label/intro/4_Overcoming%20Challenges.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-overcoming-time-challenges-lesson-4-how-and-why-to-cut-back-on-meetings';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/951/mod_label/intro/5_Overcoming%20Challenges.mp4">https://goalvow.com/upskilling/pluginfile.php/951/mod_label/intro/5_Overcoming%20Challenges.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-overcoming-time-challenges-lesson-5-five-tips-to-take-control-of-your-inbox';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Cut yourself some slack.&nbsp;</strong>When you’re unable to avoid a packed schedule, don’t be too hard on yourself—it happens. Just remember that to do your best work, you need to take care of yourself, too. That means limiting long days at the office, using personal days when needed, and having honest conversations with your manager about your schedule and workload limitations.</li></ul><p></p><ul><li><strong>If you need a break, opt for a “useful” distraction.&nbsp;</strong>Distractions get a bad rap in the workplace—but they aren’t always a negative thing. For example, when you need to think creatively but feel stuck, giving in to a distraction can help you get out of a mental rut. Not all distractions are equal, however. Be sure you’re choosing useful distractions rather than ones with no return. For instance, chatting with a coworker is better than losing 10 minutes to scrolling aimlessly on social media.</li></ul><p></p><ul><li><strong>Get comfortable with arriving early.&nbsp;</strong>Some people avoid arriving at places early. They don’t want to feel uncomfortable or waste time sitting around—“<em>What will I do while I wait?”&nbsp;</em>As a result, they cut it close and often arrive late. If this sounds like you, make the wait easier by having something productive to do. For example, respond to emails, read an e-book, or catch up on the latest news on your phone.</li></ul><p></p><p></p><ul><li><strong>Use out-of-the-box strategies when a meeting is unavoidable.&nbsp;</strong>You won’t be able to cut meetings completely from your schedule. So, for necessary ones, use creative strategies to keep them engaging and brief. For example, try a “learning meeting”—a meeting that focuses on problem-solving instead of reporting. This approach can generate dialogue and energy.</li></ul><p></p><p></p><ul><li><strong>Create email templates.&nbsp;</strong>Why repeat the same things over and over? Unfortunately, it often happens in the email world. Save yourself time by creating templates for your recurring messages. For example, “<em>Thanks for your project request. I’ll review your information and get back to you within 24 hours.”&nbsp;</em>Creating email templates may take time initially, but you’ll have a library of canned responses at the ready.</li></ul><p><ul><li><strong>Listen to music.&nbsp;</strong>It can be challenging to focus on your work when you can hear coworkers talking—phones ringing—or the copy machine running in the background. Listening to music is one way that you can mask background noise and avoid distractions. Consider classical music, nature sounds, or ambient music without lyrics. Choose music that’s soft and subtle enough that it doesn’t become a distraction in and of itself.</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-6-overcoming-time-challenges-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><ul><li><strong>Know-what </strong>is goal setting and why is it important</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to set goals that actually work</li><li><strong>Know-how&nbsp;</strong>to stick to your goals</li><li><strong>Measure </strong>and <strong>Track </strong>goal progress</li></ul><br><p></p></div>' WHERE slug = 'module-2-goal-setting-learning-outcome';
