UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/957/mod_label/intro/2_Goal%20Setting.mp4?time=1709880733618">https://goalvow.com/upskilling/pluginfile.php/957/mod_label/intro/2_Goal%20Setting.mp4?time=1709880733618</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-goal-setting-lesson-2-setting-goals-that-actually-work';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/958/mod_label/intro/3_Goal%20Setting.mp4?time=1709880777898">https://goalvow.com/upskilling/pluginfile.php/958/mod_label/intro/3_Goal%20Setting.mp4?time=1709880777898</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-goal-setting-lesson-3-how-to-stick-to-your-goals';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/959/mod_label/intro/4_Goal%20Setting.mp4?time=1709880840890">https://goalvow.com/upskilling/pluginfile.php/959/mod_label/intro/4_Goal%20Setting.mp4?time=1709880840890</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-goal-setting-lesson-4-measuring-and-tracking-goal-progress';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Remember the value.&nbsp;</strong>If you have an aspiration, don’t just commit to&nbsp;<em>“getting around to it eventually.”&nbsp;</em>Instead, remember the value of setting goals, and take the time to think about how you can create your own system. Take the first step, and the others will soon follow.</li></ul><p></p><ul><li><strong>Break down your goals.</strong>&nbsp;If you feel like your goal is too big to accomplish, continue to break it down into smaller and smaller steps. Remember, everyone has to start somewhere. So, map out all the milestones on the way to your objective until you arrive at the target that’s closest to where you are right now. Start small and work your way up, and eventually, those impossible goals won’t seem so out of reach.</li></ul><p></p><ul><li><strong>Get back on track.&nbsp;</strong>The next time you fall off track, remember that everyone encounters obstacles. What matters is not how you fall down, but how you get back up. Small hiccups don’t make you a failure. Instead, focus on aligning your identity, environment, and habits with your goal, and soon, you’ll be pushing forward and making positive strides toward achieving your objective.</li></ul><p></p><ul><li><strong>Re-measure often.&nbsp;</strong>Measuring your goals is an ongoing process—not a one-off occurrence. And if you’re working toward an objective, you should be tracking your progress and re-measuring often. After all, the more frequently you measure, the more likely you are to spot setbacks in their early stages. And the sooner you have that information, the sooner you can change course.</li></ul><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-2-goal-setting-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>the importance of delegating</li><li><strong>Know-why </strong>people don\'t delegate</li><li><strong>Know-what </strong>and <strong>how </strong>to delegate</li><li><strong>Delegate </strong>the right tasks to the right people</li><li><span>Have the </span><strong>capability</strong> to keep control of employees without micromanaging</li></ul><br><br><p></p></div>' WHERE slug = 'module-5-delegating-tasks-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2127/mod_resource/content/2/Delegating%20Task%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Delegating Task Course Material.pdf</a></p>' WHERE slug = 'module-5-delegating-tasks-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2913/mod_label/intro/1_Delegating%20Tasks.mp4">https://goalvow.com/upskilling/pluginfile.php/2913/mod_label/intro/1_Delegating%20Tasks.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-delegating-tasks-lesson-1-the-importance-of-delegation';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2914/mod_label/intro/2_Delegating%20Tasks.mp4">https://goalvow.com/upskilling/pluginfile.php/2914/mod_label/intro/2_Delegating%20Tasks.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-delegating-tasks-lesson-2-why-people-don-t-delegate';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2915/mod_label/intro/3_Delegating%20Tasks.mp4">https://goalvow.com/upskilling/pluginfile.php/2915/mod_label/intro/3_Delegating%20Tasks.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-delegating-tasks-lesson-3-what-and-how-to-delegate';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2916/mod_label/intro/4_Delegating%20Tasks.mp4">https://goalvow.com/upskilling/pluginfile.php/2916/mod_label/intro/4_Delegating%20Tasks.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-delegating-tasks-lesson-4-delegating-the-right-tasks-to-the-right-people';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2917/mod_label/intro/5_Delegating%20Tasks.mp4">https://goalvow.com/upskilling/pluginfile.php/2917/mod_label/intro/5_Delegating%20Tasks.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-5-delegating-tasks-lesson-5-keeping-control-without-micromanaging';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Avoid the urge to tell employees how to do tasks.&nbsp;</strong>Instead, focus on what needs to be accomplished and why, and give them the opportunity to work out how to achieve that on their own. Provide a framework, not the solution.</li></ul><p></p><ul><li><strong>Focus on your team, not yourself.&nbsp;</strong>Notice how many of the reasons people don’t delegate involve an “I” statement or otherwise revolve around the team manager’s perceptions and feelings? When you shift the focus away from how you’re feeling, and concentrate on what’s best for your team instead, you may find it easier to let go and start delegating.</li></ul><p></p><ul><li><strong>Adopt a positive attitude toward delegating</strong>, and get into the habit of reviewing your tasks and asking yourself these questions:&nbsp;<em>“Who else could do this? Who might benefit from learning this? Who would be interested in trying this?"</em></li></ul><p></p><ul><li><span><strong style="font-style: italic;">Ask if your team members are up for more challenging tasks.&nbsp;</strong>If you’re delegating an especially challenging task, explain to the other person why you think they’re the best fit and express your confidence in their abilities. Then ask them,<span style="">&nbsp;“Are you up for the challenge?”&nbsp;</span>Or, “<span style="">Do you feel good about handling this?”</span>&nbsp;Get their verbal commitment.</span></li></ul><p></p><ul><li><strong>Prioritize your project involvement.&nbsp;</strong>Having your hand in every project can quickly spread your time and energy thin. Ask yourself,&nbsp;<em>“Which projects are a high priority? Which projects involve a high level of decision-making or risk? Which projects are unlike anything that my team has done before?”</em>&nbsp;Monitor these projects more closely, and give your team more control over low-priority or low-risk projects.</li></ul><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-5-delegating-tasks-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>a manager\'s role in career development</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to implement team development in stages</li><li><strong>Know-how&nbsp;</strong>to conduct a gap analysis</li><li><strong>Know-how&nbsp;</strong>to choose the right training methods</li><li><strong>Know-how </strong>to conduct effective one-on-ones</li><li><strong>Develop </strong>your team through coaching</li><li><strong>Get </strong>to know employees strength, interest and what they value</li></ul><br><br><p></p></div>' WHERE slug = 'module-3-developing-your-team-learning-outcome';
