UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2904/mod_label/intro/6_Developing%20your%20Team.mp4">https://goalvow.com/upskilling/pluginfile.php/2904/mod_label/intro/6_Developing%20your%20Team.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-developing-your-team-lesson-5-how-to-conduct-effective-one-on-ones';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2905/mod_label/intro/5_Developing%20your%20Team.mp4">https://goalvow.com/upskilling/pluginfile.php/2905/mod_label/intro/5_Developing%20your%20Team.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-developing-your-team-lesson-6-developing-your-team-through-coaching';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2906/mod_label/intro/7_Developing%20your%20Team.mp4">https://goalvow.com/upskilling/pluginfile.php/2906/mod_label/intro/7_Developing%20your%20Team.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-developing-your-team-lesson-7-getting-to-know-employees-strength-interests-and-values';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>You don’t need to do everything.</strong>&nbsp;If you’re feeling overwhelmed, remember that career development is largely an employee’s responsibility. You don’t need to do everything. Instead, just focus on getting to know your staff, offering your input, and looking out for opportunities. After that, it’s up to your team members to drive the journey.</li></ul><p></p><ul><li><strong>Where is your team?&nbsp;</strong>Review the four stages of team development to identify which stage resonates with your team. Which stage are they in? And how can you help them move forward?</li></ul><p></p><ul><li><strong>Use spreadsheets.&nbsp;</strong>Spreadsheets are a simple tool for conducting gap analyses that involve numbers or metrics. You can write your desired numbers in one column and your present numbers in another. Set up a third column to calculate the difference between the two columns automatically, and quickly see where the gaps are. However, remember that you’ll need to do some detective work and ask why there is a discrepancy in identifying the underlying cause of the gap.</li></ul><p></p><ul><li><strong>Make training engaging and relevant.&nbsp;</strong>The best training engages employees and is directly relevant or applicable to their day-to-day tasks. Consider how you can make training content more engaging through case studies or videos, or more relevant through real-world examples. Get creative!</li></ul><p></p><ul><li><strong>Limit project updates to five minutes of your meeting.&nbsp;</strong>Talking about where an employee is at on a particular project or task is an easy discussion topic, but it’s not the most valuable way to spend your time together in a one-on-one. Limit the update to five minutes, then move on to more employee-specific topics.</li></ul><p></p><ul><li><strong>Call out interesting behaviors, thoughts, or language patterns.</strong>&nbsp;Pay attention to any behaviors, thoughts, or language patterns that stand out to you. Have you noticed that a team member often competes with or compares themselves to their colleagues? Or, have you noticed that there’s a discrepancy between a team member’s self-perception and their objective performance? Call out your observations; they can be powerful points for reflection.</li></ul><p><ul><li><strong>Be direct.&nbsp;</strong>People like to talk about what they’re good at, what they’re passionate about, or what’s important to them. If you have any doubts or questions about a person’s strengths, interests, or values—just ask.</li></ul></p><p></p><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-3-developing-your-team-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>the fundamentals of team management</li><li><strong>Know-what </strong>makes a team effective</li><li><strong>Know-how </strong>to communicate with your team effectively</li><li><strong>Implement </strong>team management techniques</li><li><strong>Know-how </strong>to avoid common team problems</li></ul><br><p></p></div>' WHERE slug = 'module-1-team-management-fundamentals-learning-outcome';
