UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2893/mod_label/intro/3_Team%20Management%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2893/mod_label/intro/3_Team%20Management%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-team-management-fundamentals-lesson-3-communicating-with-your-team';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2894/mod_label/intro/4_Team%20Management%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2894/mod_label/intro/4_Team%20Management%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-team-management-fundamentals-lesson-4-team-management-tips-and-techniques';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2895/mod_label/intro/5_Team%20Management%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2895/mod_label/intro/5_Team%20Management%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-team-management-fundamentals-lesson-5-common-team-problems-and-how-to-resolve-them';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Take responsibility for your team’s success.&nbsp;</strong>It’s easy to blame others or external factors when things go wrong. As a team manager, you need to take full responsibility for your team’s success or failure. Be accountable for guiding your team and helping them succeed in their individual roles. &nbsp;</li></ul><p></p><ul><li><strong>Embrace humor.&nbsp;</strong>All work and no play can make for a less-effective team. Embrace your team’s sense of humor, curiosity, and playfulness to bring a positive attitude to your team.</li></ul><p></p><ul><li><strong>Take advantage of communication tools.&nbsp;</strong>It doesn’t matter if your team is big or small, remote or local, or working in healthcare or construction—there are tons of tools available to make team communication easier and more effective. Explore everything from messaging apps and video conference software to tools for taking notes, organizing information, sending updates, and reviewing others’ work.</li></ul><p></p><ul><li><strong>Add a teamwork section to performance reviews.&nbsp;</strong>Use performance reviews not only to evaluate individual performance, but also to assess how well individuals collaborate and where they add value to the team. It will give team members a better understanding of their strengths within the team, and a sense of how they can better help their team. It will also show them that teamwork is highly valued.</li></ul><p><ul><li><strong>Focus on&nbsp;<em>long-term</em>&nbsp;solutions.&nbsp;</strong>Sometimes, team managers panic when they perceive a crisis within their teams. They launch into action mode and try to do whatever they can to resolve the problem as quickly as possible. However, remember that short-term solutions may not hold up in the long run. Avoid the easy fix, and think about which solutions are more sustainable in the long term.</li></ul></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-1-team-management-fundamentals-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>good reasons for letting an employee go</li><li><strong>Implement</strong> steps to take before letting an employee go</li><li><strong>Know-how&nbsp;</strong>to tell an employee they\'re fired</li><li><strong>Know-how&nbsp;</strong>to mitigate legal risks when letting an employee go</li><li><strong>Reassure </strong>your team after someone is let go</li></ul><br><br><p></p></div>' WHERE slug = 'module-11-letting-an-employee-go-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2133/mod_resource/content/2/Letting%20an%20Employee%20Go%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Letting an Employee Go Course Material.pdf</a></p>' WHERE slug = 'module-11-letting-an-employee-go-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2949/mod_label/intro/1_Letting%20an%20Employee%20Go.mp4">https://goalvow.com/upskilling/pluginfile.php/2949/mod_label/intro/1_Letting%20an%20Employee%20Go.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-11-letting-an-employee-go-lesson-1-good-reasons-for-letting-an-employee-go';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2950/mod_label/intro/2_Letting%20an%20Employee%20Go.mp4">https://goalvow.com/upskilling/pluginfile.php/2950/mod_label/intro/2_Letting%20an%20Employee%20Go.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-11-letting-an-employee-go-lesson-2-steps-to-take-before-letting-an-employee-go';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2951/mod_label/intro/3_Letting%20an%20Employee%20Go.mp4">https://goalvow.com/upskilling/pluginfile.php/2951/mod_label/intro/3_Letting%20an%20Employee%20Go.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-11-letting-an-employee-go-lesson-3-how-to-tell-an-employee-they-re-fired';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2952/mod_label/intro/4_Letting%20an%20Employee%20Go.mp4">https://goalvow.com/upskilling/pluginfile.php/2952/mod_label/intro/4_Letting%20an%20Employee%20Go.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-11-letting-an-employee-go-lesson-4-mitigating-legal-risks-when-letting-an-employee-go';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2953/mod_label/intro/5_Letting%20an%20Employee%20Go.mp4">https://goalvow.com/upskilling/pluginfile.php/2953/mod_label/intro/5_Letting%20an%20Employee%20Go.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-11-letting-an-employee-go-lesson-5-reassuring-your-team-after-someone-is-let-go';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Review your employee handbook and talk to human resources (HR)</strong>. Always review your employee handbook and talk to HR before terminating an employee. What does company policy say about employee conduct, time off, and consequences for violating workplace rules and policies? You might also try reviewing the employee’s contract and the original job description. What job responsibilities and performance standards were outlined?</li></ul><p></p><ul><li><strong>Prepare what you’re going to say.&nbsp;</strong>Prepare what you’re going to say when you fire an employee so that you can deliver the news in a way that’s professional and direct—while also being respectful and preserving the terminated employee’s dignity.</li></ul><p></p><ul><li><strong>How would you want to be treated?&nbsp;</strong>When in doubt about how you should act or what you should say to a terminated employee, try asking yourself,&nbsp;<em>“How would you like to be treated?</em>” Put yourself in the employee’s shoes, and imagine how you’d want your manager to break the news to you.</li></ul><p></p><ul><li><strong>Seek legal counsel.&nbsp;</strong>The content in this lesson is meant to be used for general guidance—not to replace legal advice. Seek legal counsel to ensure your company’s adherence to the law and protection from wrongful termination lawsuits.</li></ul><p></p><ul><li><strong>Always speak respectfully and professionally about a terminated employee.&nbsp;</strong>Never bash or badmouth an employee who was let go. Badmouthing former employees will hurt your reputation and credibility as a manager—and set a bad example for the rest of your team.</li></ul><p></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-11-letting-an-employee-go-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Know-how </strong>to hire exceptional remote talent</li><li><strong>Implement best practices for managing remote teams</strong></li><li><strong>Know-how&nbsp;</strong>to communicate with remote teams</li><li><strong>Increase</strong> accountability to your remote teams</li><li><strong>Know-how </strong>to keep remote workers connected</li></ul><br><p></p></div>' WHERE slug = 'module-7-managing-remote-teams-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2129/mod_resource/content/2/Managing%20Remote%20Teams%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Managing Remote Teams Course Material.pdf</a></p>' WHERE slug = 'module-7-managing-remote-teams-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2923/mod_label/intro/1_Manging%20Remote%20Teams.mp4">https://goalvow.com/upskilling/pluginfile.php/2923/mod_label/intro/1_Manging%20Remote%20Teams.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-managing-remote-teams-lesson-1-hiring-exceptional-remote-talent';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2924/mod_label/intro/2_Manging%20Remote%20Teams.mp4">https://goalvow.com/upskilling/pluginfile.php/2924/mod_label/intro/2_Manging%20Remote%20Teams.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-managing-remote-teams-lesson-2-best-practices-for-managing-remote-teams';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2925/mod_label/intro/3_Managing%20Remote%20Teams.mp4">https://goalvow.com/upskilling/pluginfile.php/2925/mod_label/intro/3_Managing%20Remote%20Teams.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-managing-remote-teams-lesson-3-communicating-with-remote-teams';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2926/mod_label/intro/4_Managing%20Remote%20Teams.mp4">https://goalvow.com/upskilling/pluginfile.php/2926/mod_label/intro/4_Managing%20Remote%20Teams.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-managing-remote-teams-lesson-4-increasing-accountability-on-remote-teams';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2927/mod_label/intro/5_Manging%20Remote%20Teams.mp4">https://goalvow.com/upskilling/pluginfile.php/2927/mod_label/intro/5_Manging%20Remote%20Teams.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-7-managing-remote-teams-lesson-5-keeping-remote-workers-connected';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Write “<em>remote</em>” in your job posting.&nbsp;</strong>When posting remote positions on job boards or career sites, make sure to indicate that it’s a remote position. For example, you might be able to write remote as the location of the job. Or, find other areas to add the term remote to the job title or job description. You want candidates who are looking for remote work to be able to find you, and you don’t want job boards to filter your job posting out based on the location.&nbsp;</li></ul><p></p><ul><li><strong>Lean on one-on-ones.</strong>&nbsp;One-on-one meetings are an essential tool to touch base with remote employees in a distributed work environment. Try to conduct one-on-ones monthly—or even biweekly—to see how team members are doing, set goals and track progress, and give or receive feedback.&nbsp;</li></ul><p></p><p></p><ul><li><strong>Minimize interruptions.&nbsp;</strong>Remote workers—more than anyone—understand when your neighbor’s dog is barking, or your kids break into your office during a Skype meeting or a conference call. However, these kinds of interruptions can be distracting and disruptive. Do what you can to minimize interruptions during remote team meetings or collaborative working sessions.</li></ul><p></p><ul><li><strong>Create shared, standardized systems.&nbsp;</strong>Take some cognitive load off your team members’ plates by establishing shared and standardized systems for managing projects, sharing information, or solving problems. By having shared systems and processes in place, your team has less to figure out, and fewer obstacles to completing their work.</li></ul><p></p><p></p><ul><li><strong>Pay attention to the little things.&nbsp;</strong>You can also help remote team members feel more connected by paying attention to the little things. For example, you might send a birthday treat or work anniversary card in the mail as a way to help remote workers celebrate and feel like they are part of an in-person team.</li></ul><p></p><p></p><p></p></div>' WHERE slug = 'module-7-managing-remote-teams-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>factors that influence motivation</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to improve employees job satisfaction to increase motivation</li><li><strong>Implement</strong> strategies to motivate employee<span>&nbsp;</span></li></ul><br><br><p></p></div>' WHERE slug = 'module-6-motivating-your-team-learning-outcome';
