UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2921/mod_label/intro/4_Motivating%20your%20Team.mp4">https://goalvow.com/upskilling/pluginfile.php/2921/mod_label/intro/4_Motivating%20your%20Team.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-motivating-your-team-lesson-4-six-strategies-to-motivate-employees';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2922/mod_label/intro/5_Motivating%20your%20Team.mp4">https://goalvow.com/upskilling/pluginfile.php/2922/mod_label/intro/5_Motivating%20your%20Team.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-6-motivating-your-team-lesson-5-celebrating-wins';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Add and subtract.&nbsp;</strong>A simple way to approach motivation is to identify which factors add to—or take away from—employee satisfaction. For example, you might find that factors like a high level of autonomy and equity increase employee satisfaction, whereas a high level of uncertainty and bureaucracy decreases employee satisfaction. Then, try to increase the factors that add to satisfaction, and eliminate those that take away from it.&nbsp;</li></ul><p></p><ul><li><strong>Ask employees about motivation in team surveys or one-on-ones.&nbsp;</strong>You can always ask employees how motivated they feel, or what motivates them as an individual, in one-on-one meetings or anonymous team surveys. Ask what factors are currently hurting motivation as well as what you could do to improve motivation.</li></ul><p></p><p></p><ul><li><strong>Start small.&nbsp;</strong>You likely can’t overhaul an employee’s job entirely or give it more variety, autonomy, etc., overnight. So, start small. Ask yourself: “What’s one thing I can do?” For example, it could be as simple as asking for your employee’s input on a team decision that you would have typically made yourself.</li></ul><p></p><ul><li><strong>Discover what inspires and motivates you.&nbsp;</strong>Motivation can be contagious. When you’re inspired, your team will draw off your energy and inspiration.</li></ul><p></p><p></p><ul><li><strong>Tailor your celebrations to your team and company culture.&nbsp;</strong>Choose how you celebrate based on the person you’re celebrating as well as your company culture. What would the team member like best? Also, how might you bring your company values into your celebrations? For example, a company that values social responsibility might donate to a nonprofit of the team member’s choosing as a reward.</li></ul><p></p><p></p></div>' WHERE slug = 'module-6-motivating-your-team-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Transition </strong>from employee to manager position</li><li><strong>Avoid </strong>new manager mistake</li><li><strong>Know-how&nbsp;</strong>to transition from peer to boss</li><li><strong>Know-how&nbsp;</strong>to manage people with more experience than you</li></ul><br><p></p></div>' WHERE slug = 'module-2-new-manager-learning-outcome';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/2124/mod_resource/content/2/New%20Manager%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">New Manager Course Material.pdf</a></p>' WHERE slug = 'module-2-new-manager-module-reading-material';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2896/mod_label/intro/1_New%20Manager.mp4">https://goalvow.com/upskilling/pluginfile.php/2896/mod_label/intro/1_New%20Manager.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-new-manager-lesson-1-transitioning-from-employee-to-manager';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2897/mod_label/intro/2_New%20Manager.mp4">https://goalvow.com/upskilling/pluginfile.php/2897/mod_label/intro/2_New%20Manager.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-new-manager-lesson-2-seven-new-manager-mistakes-to-avoid';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2898/mod_label/intro/3_New%20Manager.mp4">https://goalvow.com/upskilling/pluginfile.php/2898/mod_label/intro/3_New%20Manager.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-new-manager-lesson-3-how-to-transition-from-peer-to-boss';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2899/mod_label/intro/4_New%20Manager.mp4">https://goalvow.com/upskilling/pluginfile.php/2899/mod_label/intro/4_New%20Manager.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-new-manager-lesson-4-managing-people-with-more-experience-than-you';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Be patient with yourself.&nbsp;</strong>Managing people is a skill that must be refined and learned. Don’t be too hard on yourself if you aren’t where you want to be overnight. It will take some time to discover your management style, see what works, and practice and perfect your skills.</li></ul><p></p><ul><li><strong>Don’t make big changes too quickly.&nbsp;</strong>New managers should avoid making big changes too quickly. Instead, spend time getting to know employees, learning more about their work, and understanding current systems and processes. Do your research before proposing ideas. Better yet—ask your team for ideas on what they’d like to see change.</li></ul><p></p><ul><li><strong>Address negativity swiftly and effectively.</strong>&nbsp;If former peers are expressing pessimism, don’t let their bad attitude spread to the rest of the team. Instead, nip it in the bud. Have a private conversation and explain to them that you know the transition is difficult, but the success of the team depends on everyone adopting a positive attitude and an open mind.</li></ul><p><ul><li><strong>When in doubt, write a list of your skills and achievements.&nbsp;</strong>Writing down your achievements and strengths as a manager can help you stave off self-doubt and remember why you’re uniquely qualified to lead a talented and experienced team.</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-2-new-manager-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>performance management</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to improve poor performance</li><li><strong>Know-how&nbsp;</strong>to develop a performance improvement plan</li><li><strong>Know-how&nbsp;</strong>to manage high performers</li><li><strong>Conduct </strong>effective performance reviews</li><li><strong>Give </strong>effective employee feedback</li><li><strong>Handle </strong>difficult reactions to feedback</li><li><strong>Know-how </strong>to effectively manage managers</li><li><strong>Implement </strong>continuous performance management</li></ul><br><br><p></p></div>' WHERE slug = 'module-9-performance-management-learning-outcome';
