UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2938/mod_label/intro/5_Performance%20Management.mp4">https://goalvow.com/upskilling/pluginfile.php/2938/mod_label/intro/5_Performance%20Management.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-9-performance-management-lesson-5-conducting-effective-performance-reviews';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2939/mod_label/intro/6_Performance%20Management.mp4">https://goalvow.com/upskilling/pluginfile.php/2939/mod_label/intro/6_Performance%20Management.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-9-performance-management-lesson-6-giving-effective-employee-feedback';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2940/mod_label/intro/7_Performance%20Management.mp4">https://goalvow.com/upskilling/pluginfile.php/2940/mod_label/intro/7_Performance%20Management.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-9-performance-management-lesson-7-handling-difficult-reactions-to-feedback';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2941/mod_label/intro/8_Performance%20Management.mp4">https://goalvow.com/upskilling/pluginfile.php/2941/mod_label/intro/8_Performance%20Management.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-9-performance-management-lesson-8-how-to-effectively-manage-managers';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2942/mod_label/intro/9_Performance%20Management.mp4">https://goalvow.com/upskilling/pluginfile.php/2942/mod_label/intro/9_Performance%20Management.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-9-performance-management-lesson-9-continuous-performance-management';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>A year-round activity.</strong>&nbsp;Life gets busy, and it’s easy to place your performance management system on hold—delaying or canceling meetings and saying: “We’ll chat soon.” But to achieve long-term results, ongoing check-ins and coaching sessions are necessary. So, keep that cycle consistent and stay in touch with your staff, regardless of what else is happening.</li></ul><p></p><ul><li><strong>Don’t delay confrontation.&nbsp;</strong>Performance meetings can be daunting. But don’t delay these conversations, as that will only inflate the issues further. Instead, keep these conversations regular and speak up at the first sign of underperformance. That way, you can prevent problems from escalating and keep these talks pain-free.</li></ul><p></p><p></p><ul><li><strong>Review your PIP for bias.&nbsp;</strong>Managers should try to reduce bias from their performance improvement plans and discussions by using neutral and descriptive language—not negative or insulting language. The plan should focus on behavior—not character. Goals should be attainable and tied to the employee’s direct job responsibilities. Finally, there should be evidence or documentation of an issue. Don’t let your frustration with an employee cloud your judgment about their performance.</li></ul><p></p><p></p><ul><li><strong>Ask high performers what they need to stay at the company for the long term.&nbsp;</strong>You don’t have to guess if a high performer feels satisfied and challenged in their role. Ask them directly in a one-on-one or performance evaluation. You might ask them,&nbsp;<em>“What would you need to stay at the company for the next X years?”</em></li></ul><p></p><p></p><ul><li><strong>Get a signature.&nbsp;</strong>Have the team member sign your performance review at the end of the meeting to confirm that they received it. If you ever need to discipline or fire a team member, then the signed performance review may help to prove that the person was given notice of a performance issue and an opportunity to improve it.</li></ul><p></p><ul><li><strong>Keep feedback regular.&nbsp;</strong>When feedback is continuous, the process becomes less of an ordeal, and it’s more effective. It allows you to prevent issues from escalating and to cultivate a culture of continual improvement. So, keep feedback regular, grab opportunities as they present themselves, and make a commitment to schedule routine catch-ups with your staff.</li></ul><p></p><ul><li><strong>Don’t give up.&nbsp;</strong>It may take some practice navigating difficult feedback conversations, but don’t give up or avoid confrontation. Remind yourself that giving feedback is instrumental to employees’ development and growth.</li></ul><p></p><ul><li><strong>Don’t criticize managers in front of their teams.</strong>&nbsp;Instead, help managers boost their credibility with direct reports by giving constructive feedback privately and looking for opportunities to compliment them or show confidence in their work and ideas publicly.</li></ul><p><ul><li><strong>Balance positive and constructive feedback.&nbsp;</strong>Continuous performance management isn’t limited to giving on-the-spot constructive feedback. Don’t forget to give on-the-spot praise and recognition, too! Reinforce positive behaviors, regularly.</li></ul></p><p><br></p><p></p><p></p><p><br></p><p></p><p></p><p></p></div>' WHERE slug = 'module-9-performance-management-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>common causes of conflict in the workplace</li><li><strong>Know-how </strong>people deal with conflict</li><li><span>Have the </span><strong>capability</strong> to implement steps to mediate conflict between employees</li><li><strong>Implement</strong> conflict resolution techniques</li><li><strong>Know-how </strong>to deal with frustrated or angry employees</li><li><strong>Know-how </strong>to deal with abusive behavior&nbsp;&nbsp;</li></ul><br><br><p></p></div>' WHERE slug = 'module-10-resolving-conflict-learning-outcome';
