UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2944/mod_label/intro/2_Resolving%20Conflict.mp4">https://goalvow.com/upskilling/pluginfile.php/2944/mod_label/intro/2_Resolving%20Conflict.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-10-resolving-conflict-lesson-2-understanding-how-people-deal-with-conflict';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2945/mod_label/intro/3_Resolving%20Conflict.mp4">https://goalvow.com/upskilling/pluginfile.php/2945/mod_label/intro/3_Resolving%20Conflict.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-10-resolving-conflict-lesson-3-six-steps-to-mediate-conflict-between-employees';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2946/mod_label/intro/4_Resolving%20Conflict.mp4">https://goalvow.com/upskilling/pluginfile.php/2946/mod_label/intro/4_Resolving%20Conflict.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-10-resolving-conflict-lesson-4-conflict-resolution-tips-and-techniques';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2947/mod_label/intro/5_Resolving%20Conflict.mp4">https://goalvow.com/upskilling/pluginfile.php/2947/mod_label/intro/5_Resolving%20Conflict.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-10-resolving-conflict-lesson-5-dealing-with-frustrated-or-angry-employees';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2948/mod_label/intro/6_Resolving%20Conflict.mp4">https://goalvow.com/upskilling/pluginfile.php/2948/mod_label/intro/6_Resolving%20Conflict.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-10-resolving-conflict-lesson-6-a-manager-s-guide-to-dealing-with-abusive-behavior';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Don’t ignore conflict or allow it to fester.</strong>&nbsp;Instead, address conflict promptly and directly. Encourage your team to confront conflict and develop strategies to deal with it effectively. Allow people to express issues if they have them.</li></ul><p></p><ul><li><strong>Listen and observe.&nbsp;</strong>While people can change their approach to the situation, there are often one or two approaches that we naturally gravitate to. Listen to and observe how your team members react to disagreements, stress, or tension on the team. Keep this in mind so you can better tailor your conflict management strategy to the parties involved.</li></ul><p></p><ul><li><strong>Be prepared to break.&nbsp;</strong>If discussions get too heated, be ready to break and let both parties cool off before reconvening. You can also try changing the environment to encourage a fresh start when you return to mediation.</li></ul><p></p><ul><li><strong>Ask why.&nbsp;</strong>A simple tip to facilitate understanding of people’s needs and motivations is to keep asking,<em>&nbsp;“Why?”&nbsp;</em>For example,&nbsp;<em>“Why do you feel that way? Why do you want that? Why did you do that?”</em>&nbsp;Or, “<em>Why do you think that?"</em></li></ul><p></p><p></p><ul><li><strong>Follow up.&nbsp;</strong>Schedule a time to check in with the employee after a solution has been implemented or a set amount of time has passed. How is the employee feeling? Has the situation improved, worsened, or stayed the same? Are there any other frustrations they would like to talk about (and that you can prevent from escalating further)? Following up is a great way to build trust and keep communication lines open.</li></ul><p></p><ul><li><strong>&nbsp;Have and communicate an open-door policy.&nbsp;</strong>Even with a reporting system in place, employees may hesitate to come to you with problems if you come across as unapproachable. Have an open-door policy, and regularly ask employees to come to you if they have questions, want to talk, or need help.</li></ul><p></p><p></p><p><br></p><p></p><p></p><p></p></div>' WHERE slug = 'module-10-resolving-conflict-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module</strong><strong>, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>team culture and why it matters</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to assess your team culture</li><li><strong>Know-how&nbsp;</strong>to create a strengths-based culture</li><li><strong>Know-how&nbsp;</strong>to build a positive team culture</li><li><strong>Transform</strong> a negative team culture&nbsp;</li></ul><br><br><p></p></div>' WHERE slug = 'module-4-team-culture-learning-outcome';
