UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2933/mod_label/intro/6_Team%20Dynamics.mp4">https://goalvow.com/upskilling/pluginfile.php/2933/mod_label/intro/6_Team%20Dynamics.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-8-team-dynamics-lesson-6-managing-the-multigenerational-workplace';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Communicate.</strong>&nbsp;If you’re unsure how to examine the dynamics of your team and improve them, start a conversation about it. Engage your team to ask what’s working, what’s not, and where people feel like they’re getting stuck. Acknowledge individual strengths and styles, and brainstorm how best to put them to use. Encouraging people to share—and listen—will help break down barriers and open communication channels. Then, you can identify the invisible forces at work on your team and help move your project toward success.</li></ul><p></p><ul><li><strong>Disclaimer!&nbsp;</strong>Remember that team roles describe patterns of behaviors and interpersonal styles. While people tend to adopt a particular team role, that role can change depending on the situation and the other team members. Use these roles as a flexible guide—not to conform others to rigid boxes.</li></ul><p></p><ul><li><strong>The characteristics are interrelated.&nbsp;</strong>If your team is missing one characteristic, it’s likely missing others. For example, employees cannot share ownership without sharing a purpose. The characteristics are interrelated. So, be mindful of the gaps. If needed, focus on one trait at a time, and soon, all the pieces will fall into place.</li></ul><p></p><ul><li><strong>Be patient: Improvement takes time.&nbsp;</strong>Team dynamics are about relationships and, like all relationships, they take time to develop. So, be patient. If your team is struggling, don’t give up. Continue following the five strategies covered in this lesson and remember that improvement takes time.</li></ul><p></p><p></p><ul><li><strong>Adopt a custom approach.&nbsp;</strong>People are complicated, and some team members may border between styles. For example, maybe there’s a Prioritizer on your team who also values relationships. In these cases, adopt a custom approach—mixing strategies so that you can appeal to the individual behind the style.</li></ul><p></p><ul><li><strong>Don’t dwell on the differences.</strong>&nbsp;It’s easy to get caught up in what makes people different. But there are similarities across all groups. So, rather than dwelling on the differences, turn your attention to what connects your employees. Help your team members understand and relate to one another, and you’ll create a more united workforce.</li></ul><p></p><p><br></p><p></p><p></p><p></p></div>' WHERE slug = 'module-8-team-dynamics-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Know-how </strong>to identify reliable information</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to distinguish between facts and opinion</li><li><strong>Know-how&nbsp;</strong>to identify satire and fake news&nbsp;</li></ul><br><p></p></div>' WHERE slug = 'module-3-critical-thinking-and-information-literacy-learning-outcome';
