UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2752/mod_label/intro/1_Critical%20Thinking%20and%20Information%20Literacy.mp4">https://goalvow.com/upskilling/pluginfile.php/2752/mod_label/intro/1_Critical%20Thinking%20and%20Information%20Literacy.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-critical-thinking-and-information-literacy-lesson-1-how-to-identify-reliable-information';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2753/mod_label/intro/2_Critical%20Thinking%20and%20Information%20Literacy.mp4">https://goalvow.com/upskilling/pluginfile.php/2753/mod_label/intro/2_Critical%20Thinking%20and%20Information%20Literacy.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-critical-thinking-and-information-literacy-lesson-2-distinguishing-between-fact-and-opinion';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2754/mod_label/intro/3_Critical%20Thinking%20and%20Information%20Literacy.mp4">https://goalvow.com/upskilling/pluginfile.php/2754/mod_label/intro/3_Critical%20Thinking%20and%20Information%20Literacy.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-3-critical-thinking-and-information-literacy-lesson-3-how-to-identify-satire-and-fake-news';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Stay actively engaged.&nbsp;</strong>When evaluating the reliability of information, notice how the source presents and backs up details with supporting evidence. Reflect on your overall impression of the content’s quality and identify if it’s clear, concise, and something you can easily understand and communicate with others.</li></ul><p></p><ul><li><strong>Always look for clues.&nbsp;</strong>Even experts have opinions, so don’t assume that someone in a position of authority or with extensive knowledge is sharing a fact. Look for clues to determine whether what they’re saying is factual or a well-informed opinion.</li></ul><p><ul><li><strong>When in doubt, throw it out.&nbsp;</strong>If you’re unsure whether a story is real, fake, or satirical, err on the side of caution and refrain from sharing it. At worst, you’ll miss out on a good laugh with friends. But sharing false information only adds to the internet’s most dangerous trends. Take solace in the fact that there will be more opportunities to share fun and entertaining stories online.&nbsp;</li></ul></p><p></p><p></p></div>' WHERE slug = 'module-3-critical-thinking-and-information-literacy-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Understand </strong>the fundamentals of critical thinking and its process</li><li><strong>Know-how </strong>to ask better questions for critical thinking</li><li><strong>Know-when </strong>to use inductive or deductive reasoning</li><li><strong>Know-how&nbsp;</strong>to identify cognitive bias</li></ul><br><br><p></p></div>' WHERE slug = 'module-1-critical-thinking-fundamentals-learning-outcome';
