UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2744/mod_label/intro/2_Critical%20Thinking%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2744/mod_label/intro/2_Critical%20Thinking%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-critical-thinking-fundamentals-lesson-2-the-critical-thinking-process';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2745/mod_label/intro/3_Critical%20Thinking%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2745/mod_label/intro/3_Critical%20Thinking%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-critical-thinking-fundamentals-lesson-3-how-to-ask-better-questions-for-critical-thinking';
UPDATE lessons SET content = '<div class="no-overflow">&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2746/mod_label/intro/4_Critical%20Thinking%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2746/mod_label/intro/4_Critical%20Thinking%20Fundamentals.mp4</video>&nbsp;</div>' WHERE slug = 'module-1-critical-thinking-fundamentals-lesson-4-inductive-vs-deductive-reasoning';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2747/mod_label/intro/5_Critical%20Thinking%20Fundamentals.mp4">https://goalvow.com/upskilling/pluginfile.php/2747/mod_label/intro/5_Critical%20Thinking%20Fundamentals.mp4</video>&nbsp;<br></p></div>' WHERE slug = 'module-1-critical-thinking-fundamentals-lesson-5-how-to-identify-cognitive-bias';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Critical thinking promotes creativity.&nbsp;</strong>As you grow your critical thinking skills, you might discover that your creativity is flourishing, too. Critical thinking and creativity are closely connected—and both are highly desired attributes in potential employees and leaders.</li></ul><p></p><ul><li><strong>Most problems have more than one “right” solution.</strong>&nbsp;Individuals using the same critical thinking process may come up with different solutions. The value of the critical thinking process is not in reaching the same conclusion as others. Instead, it ensures that the conclusion you come to is rooted in evidence, logic, and reason and free from personal bias.</li></ul><p></p><ul><li><strong>Practice makes habits.&nbsp;</strong>Asking questions may not come naturally to you initially. Practice brainstorming and asking questions anyway to exercise your brain’s curiosity and critical thinking skills. &nbsp;</li></ul><p></p><ul><li><strong>Explore other types of logical thinking.&nbsp;</strong>Inductive and deductive reasoning are just two of the many ways you can approach a challenge. Examples to examine further include abductive reasoning, analogical reasoning, and de-compositional reasoning. Studying these different methods can strengthen your critical thinking skills.</li></ul><p><ul><li><strong>Be curious.&nbsp;</strong>Asking questions and investigating our thinking can help combat cognitive bias. Take time to explore other perspectives, information, or approaches.</li></ul></p><p></p><p></p><p></p><p></p></div>' WHERE slug = 'module-1-critical-thinking-fundamentals-module-summary';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"></p><p dir="ltr"><strong>After completing this module, you will be able to:</strong></p><p dir="ltr"></p><ul><li><strong>Know-how </strong>to strengthen your critical thinking skills</li><li>Have the&nbsp;<strong>capability</strong>&nbsp;to build and strengthen workplace arguments</li><li><strong>Help to develop </strong>other employees critical thinking skills</li><li><strong>Know-how&nbsp;</strong>to avoid workplace fallacies</li></ul><br><br><p></p></div>' WHERE slug = 'module-2-thinking-in-the-workplace-learning-outcome';
