UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2750/mod_label/intro/3_Critical%20Thinking%20in%20the%20Workplace.mp4?time=1710074275995">https://goalvow.com/upskilling/pluginfile.php/2750/mod_label/intro/3_Critical%20Thinking%20in%20the%20Workplace.mp4?time=1710074275995</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-thinking-in-the-workplace-lesson-3-developing-employees-critical-thinking-skills';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;">&nbsp;&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/2751/mod_label/intro/4_Critical%20Thinking%20in%20the%20Workplace.mp4?time=1710074313831">https://goalvow.com/upskilling/pluginfile.php/2751/mod_label/intro/4_Critical%20Thinking%20in%20the%20Workplace.mp4?time=1710074313831</video>&nbsp;<br></p></div>' WHERE slug = 'module-2-thinking-in-the-workplace-lesson-4-seven-workplace-fallacies-to-watch-out-for';
UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><strong>Summary</strong></p><p dir="ltr" style="text-align: left;"></p><ul><li><strong>Find what works for you.&nbsp;</strong>As you’ve seen, there are a variety of ways to engage in critical thinking every day. Find the ones that you enjoy and look forward to—they’ll be easier to incorporate into your routine.</li></ul><p></p><ul><li><strong>Don’t be too rigid.&nbsp;</strong>Be willing to concede when your audience makes good points or raises legitimate objections. It builds trust and demonstrates flexibility. If you automatically reject opposing viewpoints or react negatively to criticism, you create an adversarial dynamic. Meet them halfway, and you’ll go much farther working together.&nbsp;</li></ul><p></p><ul><li><strong>Critical thinking skills are like muscles.</strong>&nbsp;Don’t expect to develop them overnight or from a single workout. Instead, strengthen your team’s critical thinking skills through regular exercise and gradually increasing the complexity of problems you assign them.</li></ul><p><ul><li><strong>Explore other types of fallacies.&nbsp;</strong>The fallacies we covered in this lesson are just a small sample of the hundreds identified. Research other fallacies to broaden your view of critical thinking in the workplace.</li></ul></p><p></p><p></p><p></p></div>' WHERE slug = 'module-2-thinking-in-the-workplace-module-summary';
