UPDATE lessons SET content = '<div class="no-overflow"><p dir="ltr" style="text-align: left;"><b><u>Topic 1: Modify the Quick Access Toolbar</u></b></p><p dir="ltr" style="text-align: left;"><b><u>&nbsp;<video controls="true"><source src="https://goalvow.com/upskilling/pluginfile.php/3199/mod_label/intro/1_Word%20Basic_Lesson%202.mp4">https://goalvow.com/upskilling/pluginfile.php/3199/mod_label/intro/1_Word%20Basic_Lesson%202.mp4</video>&nbsp;<br></u></b></p></div>\n\n<div class="no-overflow"><p dir="ltr" style="text-align: left;"><u><strong>Topic 2: Modify the Status Bar</strong></u></p></div>\n\n<div class="no-overflow"><p dir="ltr" style="text-align: left;"><u><strong>Topic 3: Find Commands by Using the Tell Me Feature</strong></u></p></div>' WHERE slug = 'managing-word-documents-and-options-lesson-2-customizing-toolbars';
UPDATE lessons SET content = '<div class="no-overflow"><h5><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-font-kerning: 18.0pt; mso-fareast-language: EN-ZA;">COURSE INTRODUCTION </span></strong></h5>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Welcome to the <strong>Career Management Strategies Course</strong> — a practical, empowering, and forward-looking program designed to help you navigate your professional journey with confidence. Whether you are entering the workplace for the first time, exploring new opportunities, or seeking growth in your current career path, this course equips you with the essential skills, insights, and strategies to actively manage and shape your future.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Throughout this learning experience, you will discover how to identify your strengths, build a compelling professional identity, develop meaningful workplace relationships, and confidently pursue new opportunities. With real-world examples, interactive exercises, and guidance aligned to modern workplace expectations, you will learn how to take charge of your career and position yourself for success in any industry.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">By the end of this course, you will not only understand what it takes to build a strong and sustainable career you will be ready to take action.</span></p>\r\n<h5><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-font-kerning: 18.0pt; mso-fareast-language: EN-ZA;">COURSE PURPOSE </span></strong></h5>\r\n<p data-start="189" data-end="837">The purpose of the <strong data-start="208" data-end="247">Career Management Strategies Course</strong> is to empower learners with the practical tools, self-awareness, and confidence needed to navigate the modern workplace and build a sustainable, fulfilling career. This course equips individuals to take ownership of their professional journey — from understanding their strengths and setting career goals, to networking, improving workplace relationships, and adapting to challenges. By blending real-world scenarios with proven career development techniques, this course prepares learners to make informed decisions, pursue meaningful opportunities, and thrive in any working environment.</p>\r\n<h5><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-font-kerning: 18.0pt; mso-fareast-language: EN-ZA;">COURSE OBJECTIVES</span></strong></h5>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">By completing this course, you will be able to:</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 13.5pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">1. Understand and shape your career direction: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Gain clarity on your career purpose, goals, and long-term professional aspirations.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 13.5pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">2. Assess and develop your strengths and skills: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Identify what you’re good at, understand areas for improvement, and learn how to present your strengths effectively to employers.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 13.5pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">3. Apply strategic job-seeking techniques: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Learn how to find new job opportunities, prepare strong applications, and perform effectively in interviews.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 13.5pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">4. Transition confidently into professional environments: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Develop the mindset and expectations needed to thrive as a new professional in today’s dynamic workplaces.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 13.5pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">5. Build and grow professional networks: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Understand the power of networking and learn how to build connections that support your career growth.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 13.5pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">6. Benefit from workplace mentoring: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Recognize the role of mentors and learn how to both seek mentorship and engage in professional guidance relationships.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 13.5pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;"><span style="mso-spacerun: yes;"> </span>7. Demonstrate professionalism in the workplace: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Apply proper etiquette, ethical behavior, and communication skills that reflect a strong professional image.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 13.5pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">8. Build strong working relationships: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Enhance your ability to collaborate, resolve conflict, communicate respectfully, and work effectively with diverse teams.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 13.5pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">9. Overcome workplace challenges with confidence: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Develop resilience, problem-solving strategies, and adaptability to manage obstacles throughout your career.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 13.5pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">10. Prepare for and succeed in your final career assessment: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Review and integrate key concepts to demonstrate mastery in the Final Exam and earn your Career Management Certificate.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"></p>\r\n<p data-start="189" data-end="837"></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"></p></div>' WHERE slug = 'career-management-strategies-course-introduction-purpose-and-objectives';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to Driving your Career Module</strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT) that can be used to enrol on more courses.</p>\r\n<p dir="ltr">This module is <strong>one of nine modules</strong> from the Career Management<strong> </strong>course and after completing all nine modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Career Management<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Career Management </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p>\r\n<p dir="ltr"></p>\r\n<p><br><br></p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3338/mod_resource/content/3/Driving%20your%20Career%20Course%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Driving your Career Course Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Understand </strong>career development and how to drive your career successfully</li>\r\n<li><strong>Know-how </strong>to create a career development plan</li>\r\n<li><strong>Know-how </strong>to use your One-on-One meeting with your manager to support your development</li>\r\n<li><strong>Know-how </strong>to increase your value at work</li>\r\n<li><strong>Know-how</strong> to ask for a raise</li>\r\n<li>Have the <strong>capability </strong>to take control of your personal brand at work</li>\r\n<li><strong>Prepare </strong>for your performance review</li>\r\n<li><strong>Know-how </strong>to transfer jobs with your company</li>\r\n<li><strong>Choose </strong>which career track is best for you between individual contributor or manager</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3340/mod_resource/content/1/Driving%20your%20Career%20Module%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Driving your Career Module Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3341/mod_resource/content/1/Module%201%20Summary.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Module 1 Summary.pdf</a></p>' WHERE slug = 'career-management-strategies-module-1-driving-your-career-to-success';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to</strong><strong> Assessing your Strengths and Skills </strong><strong>Module </strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards Token (VRT)</strong> that can be used to enrol on more modules.</p>\r\n<p dir="ltr">This module is <strong>one of nine modules</strong> from the Career Management<strong> </strong>course and after completing all nine modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Career Management<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Career Management </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3345/mod_resource/content/1/Assessing%20your%20Strength%20%20Skills%20Course%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Assessing your Strength  Skills Course Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Understand and Leverage </strong>you strengths</li>\r\n<li>Have the <strong>capability</strong> to match your career to your interests</li>\r\n<li><strong>Know-how </strong>to define your goals</li>\r\n<li><strong>Know-how </strong>to seek and receive feedback</li>\r\n<li><strong>Develop </strong>a growth mindset</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3349/mod_resource/content/1/Assessing%20your%20Strength%20%20Skills%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Assessing your Strength  Skills Course Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3356/mod_resource/content/1/Assessing%20your%20Strength%20%20Skills%20Module%202%20Summary.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Assessing your Strength  Skills Module 2 Summary.pdf</a></p>' WHERE slug = 'career-management-strategies-module-2-assessing-your-strengths-and-skills';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to Finding a New Job Module</strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT) that can be used to enrol on more courses.</p>\r\n<p dir="ltr">This module is <strong>one of nine modules</strong> from the Career Management<strong> </strong>course and after completing all nine modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Career Management<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Career Management </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p>\r\n<p dir="ltr"></p>\r\n<p><br><br></p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3360/mod_resource/content/1/Finding%20a%20New%20Job%20Course%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Finding a New Job Course Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr" style="text-align: left;">Learning Outcome</h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Make sense </strong>of the signs that its time to find a new job</li>\r\n<li>Have the <strong>capability</strong> to create a resume</li>\r\n<li><strong>Write </strong>a cover letter</li>\r\n<li><strong>Prepare </strong>for a job interview</li>\r\n<li><strong>Know-how </strong>to respond to common interview questions</li>\r\n<li><strong>Decide </strong>if remote work will work for you</li>\r\n<li><strong>Know-how </strong>to look for a new job </li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3362/mod_resource/content/1/Finding%20a%20New%20Job%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Finding a New Job Course Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3372/mod_resource/content/1/Finding%20a%20New%20Job.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Finding a New Job.pdf</a></p>' WHERE slug = 'career-management-strategies-module-3-finding-a-new-job';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3373/mod_resource/content/1/New%20Professional%20Course%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">New Professional Course Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li>Have the <strong>capability</strong> to create a 30/60/90 day plan</li>\r\n<li><strong>Adopt a successful work attitude</strong></li>\r\n<li><strong>Know-how </strong>to be an effective teammate</li>\r\n<li><strong>Know-how </strong>to connect with coworkers</li>\r\n<li><strong>Ask </strong>for help at work when you need it</li>\r\n<li><strong>Know-how </strong>to build your confidence as a new professional</li>\r\n<li><strong>Implement </strong>practices of successful new professionals</li>\r\n<li>Have the capability to t<strong>rain </strong>new coworkers</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3375/mod_resource/content/1/New%20Professional%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">New Professional Course Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3387/mod_resource/content/1/New%20Professional.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">New Professional.pdf</a></p>' WHERE slug = 'career-management-strategies-module-4-new-professional';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3388/mod_resource/content/1/Networking.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Networking.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Know-what </strong>is networking and <strong>why </strong>it is important</li>\r\n<li><strong>Navigate </strong>a business networking event</li>\r\n<li><strong>Develop</strong> a winning elevator pitch</li>\r\n<li><strong>Develop </strong>to develop a professional network</li>\r\n<li><strong>Maintain </strong>your professional network</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3390/mod_resource/content/1/Networking%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Networking Course Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3398/mod_resource/content/1/Networking%20Summary.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Networking Summary.pdf</a></p>' WHERE slug = 'career-management-strategies-module-5-networking';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3399/mod_resource/content/1/Mentoring%20in%20the%20Workplace%20Module%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Mentoring in the Workplace Module Material.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Understand </strong>the role of a mentor in your career development and how do find one</li>\r\n<li><strong>Know-how </strong>to be a model mentee</li>\r\n<li><strong>Guide </strong>others as a mentor</li>\r\n<li><strong>Overcome </strong>common mentoring challenges</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3401/mod_resource/content/1/Mentoring%20in%20the%20Workplace%20Module%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Mentoring in the Workplace Module Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3408/mod_resource/content/1/Mentoring%20in%20the%20Workplace.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Mentoring in the Workplace.pdf</a></p>' WHERE slug = 'career-management-strategies-module-6-mentoring-in-the-workplace';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3409/mod_resource/content/1/Professional%20Etiquette%20Course%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Professional Etiquette Course Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Elevate </strong>your workplace professionalism</li>\r\n<li><strong>Know-how </strong>to write effective business emails</li>\r\n<li><strong>Adopt </strong>business phone etiquette</li>\r\n<li><strong>Know-when </strong>and how to use formal/informal communication</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3411/mod_resource/content/1/Professional%20Etiquette%20Module%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Professional Etiquette Module Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3416/mod_resource/content/1/Professional%20Etiquette.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Professional Etiquette.pdf</a></p>' WHERE slug = 'career-management-strategies-module-7-professional-etiquette';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3419/mod_resource/content/1/Working%20Relationship%20Course%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Working Relationship Course Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr" style="text-align: left;"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Build </strong>strong work relationships with your coworkers</li>\r\n<li><strong>Build </strong>strong work relationships with your boss </li>\r\n<li><strong>Repair </strong>broken work relationships</li>\r\n<li><strong>Work </strong>with people you don\'t like</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3421/mod_resource/content/1/Working%20Relationship%20Module%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Working Relationship Module Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3426/mod_resource/content/1/Working%20Relationship.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Working Relationship.pdf</a></p>' WHERE slug = 'career-management-strategies-module-8-working-relationships';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3429/mod_resource/content/1/Overcoming%20Challenges%20Course%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Overcoming Challenges Course Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr" style="text-align: left;"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Know-what </strong>to do and what <strong>not to do </strong>after losing your job</li>\r\n<li>Have the <strong>strength</strong> to come back from a big mistake</li>\r\n<li><strong>Know-what </strong>to do when you\'re feeling unmotivated</li>\r\n<li><strong>Cope </strong>with workplace challenges</li>\r\n<li><strong>Overcome </strong>imposter syndrome</li>\r\n<li><strong>Implement </strong>strategies for working remotely</li>\r\n<li><strong>Overcome </strong>the fear of failure</li>\r\n<li><strong>Get </strong><strong>noticed</strong> at work</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3431/mod_resource/content/1/Overcoming%20Challenges%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Overcoming Challenges Course Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3440/mod_resource/content/1/Overcoming%20Challenges.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Overcoming Challenges.pdf</a></p>' WHERE slug = 'career-management-strategies-module-9-overcoming-challenges';
UPDATE lessons SET content = '<div class="no-overflow"><h5><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-font-kerning: 18.0pt; mso-fareast-language: EN-ZA;">COURSE SUMMARY</span></strong></h5>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">The <strong>Career Management Strategies Course</strong> provides a complete foundation for developing and advancing your career with purpose. Through a structured series of modules, you will explore how to assess your strengths, set career goals, search for new opportunities, build strong professional relationships, and apply essential workplace etiquette. You will also learn how to overcome challenges, benefit from mentoring, and grow as a new professional. </span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Designed for students, job seekers, and working professionals at any stage, this course offers practical, actionable strategies to help you confidently shape your career path. By the end, you will be equipped with the clarity, skills, and direction needed to succeed — plus a certificate to showcase your career readiness.</span></p></div>' WHERE slug = 'career-management-strategies-course-summary-and-final-exam';
UPDATE lessons SET content = '<p><a href="https://virtual-reality-simulation.vercel.app/" target="_blank" rel="noopener noreferrer">Virtual Reality Skills Simulation</a></p>' WHERE slug = 'career-management-strategies-module-1-virtual-reality-skills-simulation';
UPDATE lessons SET content = '<div class="no-overflow"><h5><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-font-kerning: 18.0pt; mso-fareast-language: EN-ZA;">COURSE INTRODUCTION</span></strong></h5>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Welcome to the <strong>Human Resource Essentials Course</strong>, a practical and transformative learning experience designed to equip you with the foundational knowledge and core competencies required in today’s modern HR environment. Whether you are beginning your HR career, supporting HR functions in your role, or seeking to understand people management more deeply, this course provides a complete overview of the skills and responsibilities that drive effective workforce management.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Through real-world examples, interactive activities, and professional insights, you will explore the full employee lifecycle—from recruitment and onboarding, to workplace well-being, talent development, diversity, and ethical practices. The course helps you understand how HR contributes to organizational culture, employee engagement, and long-term business success.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">By the end of this course, you will have the confidence to apply HR principles professionally and responsibly in any workplace environment.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 1;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-font-kerning: 18.0pt; mso-fareast-language: EN-ZA;">COURSE PURPOSE</span></strong></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">The purpose of the <strong>Human Resource Essentials Course</strong> is to build a strong foundation in HR knowledge, enabling learners to understand, support, and contribute to the people-related functions of an organization. The course aims to enhance your ability to manage human capital effectively by teaching you essential HR practices—from interviewing and talent management to promoting inclusion, handling bias, ensuring workplace well-being, and supporting employees throughout their career journeys.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;"><span style="font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-ansi-language: EN-ZA; mso-fareast-language: EN-ZA; mso-bidi-language: AR-SA;">This course is designed to help both new and experienced professionals develop the competencies needed to foster healthy, productive, and compliant workplaces.</span></span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 1;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-font-kerning: 18.0pt; mso-fareast-language: EN-ZA;">COURSE OBJECTIVES</span></strong></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Upon completing this course, you will be able to:</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">1. Demonstrate understanding of HR fundamentals: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Understand the key functions of HR, including recruitment, onboarding, compliance, and workforce planning.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">2. Promote diversity, inclusion, and belonging: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Recognize the importance of diversity and inclusion and apply strategies to create equitable work environments.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">3. Conduct effective and fair interviews: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Learn structured interviewing techniques and best practices to identify the right talent while reducing bias.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">4. Identify and mitigate unconscious bias: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Understand how unconscious bias affects workplace decisions and learn methods to prevent, address, and reduce bias.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">5. Manage and develop talent strategically: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Apply talent management tools to support employee performance, growth, and retention.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">6. Enhance workplace well-being: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Promote mental, emotional, and physical well-being across the organization using evidence-based HR practices.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">7. Uphold anti-harassment and anti-discrimination standards: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Ensure workplace safety by understanding legal obligations and ethical responsibilities related to employee protection.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">8. Support employees through retirement planning: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Understand the principles of retirement planning and how to guide employees toward long-term financial well-being.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">9. Integrate HR knowledge into real HR scenarios: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Apply course concepts to practical HR challenges, case studies, and real-world decision-making situations.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"></p></div>' WHERE slug = 'human-resource-essentials-course-introduction-purpose-and-objectives';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to Human Resource Fundamentals Module</strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT) that can be used to enrol on more courses.</p>\r\n<p dir="ltr">This module is <strong>one of eight modules</strong> from the Human Resource Essentials<strong> </strong>course and after completing all eight modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Human Resource Essentials<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Human Resource Essentials </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p>\r\n<p dir="ltr"></p>\r\n<p><br><br></p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3481/mod_resource/content/1/HR%20Fundamentals%20Courses%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">HR Fundamentals Courses Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr" style="text-align: left;"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Understand </strong>the essentials of Human Resource.</li>\r\n<li>Have the <strong>capability</strong> to draw-up and implement recruiting process.</li>\r\n<li><strong>Know what </strong>to look for and how to review CVs quickly &amp; effectively. </li>\r\n<li><strong>Know-how </strong>to onboard and train new employees.</li>\r\n<li><strong>Implement</strong> processes for disciplinary actions.</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3483/mod_resource/content/1/Fundamentals%20of%20HR%20Course%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Fundamentals of HR Course Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3494/mod_resource/content/1/Human%20Resource%20Fundamentals%20Module%20Summary.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Human Resource Fundamentals Module Summary.pdf</a></p>' WHERE slug = 'human-resource-essentials-module-1-hr-fundamentals';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to Diversity, Inclusion and Belonging Module</strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT) that can be used to enrol on more courses.</p>\r\n<p dir="ltr">This module is <strong>one of eight modules</strong> from the Human Resource Essentials<strong> </strong>course and after completing all eight modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Human Resource Essentials<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Human Resource Essentials </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p>\r\n<p dir="ltr"></p>\r\n<p><br><br></p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3495/mod_resource/content/1/Diversity%20Iinclusion%20and%20Belonging%20Course%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Diversity Iinclusion and Belonging Course Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Understand</strong> the difference between Diversity, Inclusion and Belonging (DIBS).</li>\r\n<li>Have the <strong>capability</strong> to implement Diversity, Inclusion and Belonging in the Workplace.</li>\r\n<li><strong>Know-how</strong> to attract and hire diverse talent that can lead to higher company performance.</li>\r\n<li><strong>Know-how</strong> to retain diverse talent.</li>\r\n<li><strong>Implement</strong> tools that will quantify and measure Diversity, Inclusion and Belonging.</li>\r\n<li>Make <strong>strategic decisions</strong> that will make your company to be an Ally of Diversity, Inclusion and Belonging.</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3497/mod_resource/content/1/Course%20Material%20for%20Diversity%20Iinclusion%20and%20Belonging.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Course Material for Diversity Iinclusion and Belonging.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3504/mod_resource/content/1/Diversity%2C%20Inclusion%20and%20Belonging.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Diversity, Inclusion and Belonging.pdf</a></p>' WHERE slug = 'human-resource-essentials-module-2-diversity-inclusion-and-belonging';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to Interviewing Module</strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT) that can be used to enrol on more courses.</p>\r\n<p dir="ltr">This module is <strong>one of eight modules</strong> from the Human Resource Essentials<strong> </strong>course and after completing all eight modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Human Resource Essentials<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Human Resource Essentials </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3509/mod_resource/content/1/Interviewing%20Module%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Interviewing Module Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Prepare, plan and execute </strong>a successful job interview.</li>\r\n<li><strong>Understand </strong>which job interview type to implement.</li>\r\n<li><strong>Know-how</strong> to conduct an effective job interview.</li>\r\n<li><strong>Know-how</strong> to craft strong interview questions.</li>\r\n<li><strong>Implement</strong> a non-bias interview.</li>\r\n<li><strong>Implement </strong>a process to follow up after an interview.</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3511/mod_resource/content/1/Interviewing%20Module%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Interviewing Module Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3521/mod_resource/content/1/Interviewing.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Interviewing.pdf</a></p>' WHERE slug = 'human-resource-essentials-module-3-interviewing';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to Unconscious Bias</strong><strong style="font-size: 1.5rem; text-align: initial;"> Module</strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT) that can be used to enrol on more courses.</p>\r\n<p dir="ltr">This module is <strong>one of eight modules</strong> from the Human Resource Essentials<strong> </strong>course and after completing all eight modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Human Resource Essentials<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Human Resource Essentials </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3523/mod_resource/content/1/Unconscious%20Bias%20Module%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Unconscious Bias Module Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr" style="text-align: left;"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Know-the </strong>unconscious bias and what impact it does.</li>\r\n<li><strong>Understand</strong> different types of unconscious bias.</li>\r\n<li><strong>Capable</strong> of implementing strategies to help others overcome unconscious bias.</li>\r\n<li><strong>Implement</strong> processes to help avoid bias while recruiting and retaining talent.</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3525/mod_resource/content/1/Unconscious%20Bias%20Module%20Reading%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Unconscious Bias Module Reading Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3577/mod_resource/content/1/Module%204%20summary.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Module 4 summary.pdf</a></p>' WHERE slug = 'human-resource-essentials-module-4-unconscious-bias';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to Talent Management</strong><strong style="font-size: 1.5rem; text-align: initial;"> Module</strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT) that can be used to enrol on more courses.</p>\r\n<p dir="ltr">This module is <strong>one of eight modules</strong> from the Human Resource Essentials<strong> </strong>course and after completing all eight modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Human Resource Essentials<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Human Resource Essentials </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3530/mod_resource/content/1/Talent%20Management%20Module%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Talent Management Module Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr" style="text-align: left;"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li>Have the <strong>capability</strong> to build a talent management strategy</li>\r\n<li><strong>Understand</strong> how to attract and source top talent</li>\r\n<li><strong>Know-how </strong>to attract, retain, develop employees talent</li>\r\n<li><strong>Implement</strong> a process for employee transitioning to growth and new roles</li>\r\n<li><strong>Capable </strong>of implementing strategies for retaining talent and minimizing turnover</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3532/mod_resource/content/1/Talent%20Management%20Module%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Talent Management Module Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3578/mod_resource/content/1/Module%205%20Talent%20Management%20SUMMARY.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Module 5 Talent Management SUMMARY.pdf</a></p>' WHERE slug = 'human-resource-essentials-module-5-talent-management';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to Workplace Well-Being</strong><strong style="font-size: 1.5rem; text-align: initial;"> Module</strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT) that can be used to enrol on more courses.</p>\r\n<p dir="ltr">This module is <strong>one of eight modules</strong> from the Human Resource Essentials<strong> </strong>course and after completing all eight modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Human Resource Essentials<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Human Resource Essentials </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3538/mod_resource/content/1/Workplace%20Wellbeing%20Module%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Workplace Wellbeing Module Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr" style="text-align: left;"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Understand </strong>the benefits of health and well-being to businesses.</li>\r\n<li><strong>Develop </strong>and employee wellness program.</li>\r\n<li><strong>Capable </strong>of assessing employee interest on Wellness.</li>\r\n<li><strong>Implement</strong> a diversified wellness program.</li>\r\n<li><strong>Know-how</strong> to boost employee participation on wellness programs.</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3540/mod_resource/content/1/Workplace%20Wellbeing%20Module%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Workplace Wellbeing Module Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3579/mod_resource/content/1/Module%205%20Summary.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Module 5 Summary.pdf</a></p>' WHERE slug = 'human-resource-essentials-module-6-workplace-well-being';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to Anti-Harassment and Discrimination</strong><strong style="font-size: 1.5rem; text-align: initial;"> Module</strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT) that can be used to enrol on more courses.</p>\r\n<p dir="ltr">This module is <strong>one of eight modules</strong> from the Human Resource Essentials<strong> </strong>course and after completing all eight modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Human Resource Essentials<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Human Resource Essentials </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3547/mod_resource/content/1/Anti-Harassment%20and%20Discrimination%20Module%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Anti-Harassment and Discrimination Module Preview.pdf</a></p>\n\n<div class="no-overflow"><h4><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<p dir="ltr"></p>\r\n<ul>\r\n<li><strong>Understand </strong>the workplace Anti-Discrimination laws</li>\r\n<li>Have the <strong>capability</strong> to build a respectful workplace</li>\r\n<li><strong>Understand</strong> Harassment and Discrimination. </li>\r\n<li><strong>Know-how </strong>to differential to types of Sexual Harassment</li>\r\n<li><strong>Implement</strong> processes that will deal with Sexual Harassment.</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3549/mod_resource/content/1/Anti-Harassment%20and%20Discrimination%20Module%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Anti-Harassment and Discrimination Module Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3580/mod_resource/content/1/MODULE%207%20Anti-Harassment%20and%20Discrimination%20Summary.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">MODULE 7 Anti-Harassment and Discrimination Summary.pdf</a></p>' WHERE slug = 'human-resource-essentials-module-7-anti-harassment-and-discrimination';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to Retirement Planning</strong><strong style="font-size: 1.5rem; text-align: initial;"> Module</strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT) that can be used to enrol on more courses.</p>\r\n<p dir="ltr">This module is <strong>one of eight modules</strong> from the Human Resource Essentials<strong> </strong>course and after completing all eight modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Human Resource Essentials<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Human Resource Essentials </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3559/mod_resource/content/1/Retirement%20Planning%20Module%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Retirement Planning Module Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr" style="text-align: left;"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Understand </strong>retirement planning and why it is crucial</li>\r\n<li>Have the <strong>capability</strong> a retirement plan that will work for you</li>\r\n<li><strong>Know-how</strong> to avoid retirement planning mistakes.</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3561/mod_resource/content/1/Retirement%20Planning%20Module%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Retirement Planning Module Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3581/mod_resource/content/2/Module%208%20Retirement%20Planning%20Summary.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Module 8 Retirement Planning Summary.pdf</a></p>' WHERE slug = 'human-resource-essentials-module-8-retirement-planning';
UPDATE lessons SET content = '<div class="no-overflow"><p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 1;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-font-kerning: 18.0pt; mso-fareast-language: EN-ZA;">COURSE SUMMARY</span></strong></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">The <strong>Human Resource Essentials Course</strong> provides a comprehensive introduction to the core functions, values, and responsibilities within the HR profession. Throughout the course, you explored HR fundamentals, diversity and inclusion practices, interviewing techniques, unconscious bias, talent management strategies, workplace well-being, anti-harassment and discrimination policies, and retirement planning principles.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">You are now equipped with the foundational skills and mindset needed to support HR operations and contribute positively to the employee experience. As you complete your final assessment, reflect on how these concepts apply to your workplace and how you can continue growing as an HR professional.<br>Successfully completing this course demonstrates your readiness to handle essential HR duties and your commitment to creating fair, inclusive, and healthy workplaces.</span></p></div>' WHERE slug = 'human-resource-essentials-course-summary-and-final-exam';
UPDATE lessons SET content = '<div class="no-overflow"><p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 1;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-font-kerning: 18.0pt; mso-fareast-language: EN-ZA;">COURSE INTRODUCTION</span></strong></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Welcome to the <strong>Sales Techniques Course</strong>, an essential and practical program designed to build your confidence, sharpen your selling skills, and elevate your performance in today’s competitive sales environment. Whether you are new to sales, looking to improve your results, or aiming to excel as a sales professional, this course provides the tools, strategies, and mindset needed to succeed at every stage of the sales cycle.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Throughout this course, you will learn how to communicate value clearly, understand customer psychology, build lasting relationships, overcome objections, and close deals with confidence. You will also explore leadership approaches, ethical selling practices, and the real behaviors that differentiate top sales performers.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">By the end of this course, you will have the skills to engage customers effectively, present solutions persuasively, and drive sales outcomes that support your personal goals and your organization’s success.</span></p>\r\n<p class="MsoNormal" style="margin-bottom: .0001pt; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;"> </span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 1;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-font-kerning: 18.0pt; mso-fareast-language: EN-ZA;">COURSE PURPOSE</span></strong></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">The purpose of the <strong>Sales Techniques Course</strong> is to develop strong, practical sales capabilities that empower learners to excel in customer-facing roles. This course aims to equip you with proven sales frameworks, communication skills, and relationship-building techniques that can be applied immediately in real-world selling situations.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">By integrating modern sales psychology, customer engagement strategies, and professional selling behaviors, this course helps build the confidence, competence, and consistency required to become a high-performing sales professional.</span></p>\r\n<p class="MsoNormal" style="margin-bottom: .0001pt; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;"> </span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 1;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-font-kerning: 18.0pt; mso-fareast-language: EN-ZA;">COURSE OBJECTIVES</span></strong></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">By the end of this course, you will be able to:</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">1. Understand the fundamentals of professional selling: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Explain the sales process, buyer needs, and the principles of ethical and value-driven selling.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">2. Apply sales leadership and management skills: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Use leadership mindsets and motivational techniques to influence customers and guide sales interactions effectively.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">3. Utilize sales psychology to understand buyer behavior: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Recognize emotional triggers, decision patterns, and customer motivations to build persuasive sales conversations.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">4. Present solutions clearly and persuasively: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Communicate product or service value with structured, impactful presentations that address customer pain points.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">5. Build long-term customer relationships: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Develop credibility, trust, and rapport that lead to strong client retention and repeat business.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">6. Close deals with confidence and strategy: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Use closing techniques that align with customer readiness, objections, and decision-making timelines.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">7. Handle objections effectively: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Identify common objections and apply techniques to respond professionally, confidently, and constructively.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">8. Prospect and generate new leads: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Apply prospecting strategies—including outbound, inbound, and digital methods—to identify and attract new customers.</span></p></div>' WHERE slug = 'sales-techniques-course-introduction-purpose-and-objectives';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to Sales Fundamentals Module</strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT) that can be used to enrol on more courses.</p>\r\n<p dir="ltr">This module is <strong>one of eight modules</strong> from the Sales Techniques<strong> </strong>course and after completing all eight modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Sales Techniques<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Sales Techniques </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p>\r\n<p dir="ltr"></p>\r\n<p><br><br></p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3782/mod_resource/content/1/Sales%20Fundamentals%20Module%20%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Sales Fundamentals Module  Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr" style="text-align: left;"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr" style="text-align: left;"><strong>After completing this module you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Know-how </strong>to analyse your sales pipeline</li>\r\n<li>Be <strong>capable </strong>of using sales tools for more successful sales transactions</li>\r\n<li><strong>Integrate </strong>your sales and marketing efforts</li>\r\n<li><strong>Align </strong>the sales with the buyers journey</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3798/mod_resource/content/1/Sales%20Fundamentals%20Module%20Reading%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Sales Fundamentals Module Reading Material.pdf</a></p>' WHERE slug = 'sales-techniques-module-1-sales-fundamentals';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to Sales Leadership and Management Module</strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT) that can be used to enrol on more courses.</p>\r\n<p dir="ltr">This module is <strong>one of eight modules</strong> from the Sales Techniques<strong> </strong>course and after completing all eight modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Sales Techniques<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Sales Techniques </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p>\r\n<p dir="ltr"></p>\r\n<p><br><br></p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3783/mod_resource/content/1/Sales%20Leadership%20and%20Management%20Module%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Sales Leadership and Management Module Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr" style="text-align: left;"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li>Have the <strong>capability</strong> to transition from salesperson to sales manager</li>\r\n<li><strong>Know-how </strong>to manage a sales team effectively</li>\r\n<li><strong>Understand </strong>common sales methodologies and how they work </li>\r\n<li><strong>Understand</strong> sales best practices that can empower your sales team</li>\r\n<li><strong>Build</strong> and effective sales process for your team</li>\r\n<li><strong>Know-how </strong>to automate your sales process</li>\r\n<li><strong>Know-how </strong>to structure your sales team for better sales results</li>\r\n<li><strong>Track and Improve </strong>your sales team performance</li>\r\n<li><strong>Set </strong>realistic sales quotas for your team</li>\r\n<li><strong>Create </strong>battle cards to empower and enable your sales team</li>\r\n<li><strong>Understand </strong>the basics of creating a sales forecast</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3799/mod_resource/content/1/Sales%20Leadership%20and%20Management%20Module%20Reading%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Sales Leadership and Management Module Reading Material.pdf</a></p>' WHERE slug = 'sales-techniques-module-2-sales-leadership-and-management';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to Sales Psychology Module</strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT) that can be used to enrol on more courses.</p>\r\n<p dir="ltr">This module is <strong>one of eight modules</strong> from the Sales Techniques<strong> </strong>course and after completing all eight modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Sales Techniques<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Sales Techniques </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3784/mod_resource/content/1/Sales%20Psychology%20Module%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Sales Psychology Module Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr" style="text-align: left;"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr" style="text-align: left;"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Understand </strong>why people buy</li>\r\n<li><strong>Know-how </strong>to succeed in sales as an Introvert</li>\r\n<li><strong>Know-how </strong>to deal with rejection</li>\r\n<li><strong>Know-how </strong>to use body language to win more sales</li>\r\n<li><strong>Master</strong> the capability of selling to different personality types</li>\r\n<li><strong>Manage </strong>stress as a salesperson</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3800/mod_resource/content/1/Sales%20Psychology%20Module%20Reading%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Sales Psychology Module Reading Material.pdf</a></p>' WHERE slug = 'sales-techniques-module-3-sales-psychology';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to Presenting your Solution Module</strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT) that can be used to enrol on more courses.</p>\r\n<p dir="ltr">This module is <strong>one of eight modules</strong> from the Sales Techniques<strong> </strong>course and after completing all eight modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Sales Techniques<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Sales Techniques </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3785/mod_resource/content/1/Presenting%20your%20Solution%20Module%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Presenting your Solution Module Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr" style="text-align: left;"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr" style="text-align: left;"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Develop</strong> your proposal</li>\r\n<li><strong>Know-how </strong>to prepare for your a sales presentation</li>\r\n<li><strong>Tailor </strong>your presentation to an audience</li>\r\n<li><strong>Make </strong>the most of slide decks in sales presentation</li>\r\n<li><strong>Understand </strong>the winning sales techniques</li>\r\n<li><strong>Create </strong>your sales narrative</li>\r\n<li><strong>Understand </strong>the role of storytelling in sales</li>\r\n<li><strong>Translate </strong>features into benefits</li>\r\n<li><strong>Give </strong>an effective product demonstration</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3801/mod_resource/content/1/Presenting%20your%20Solution%20Module%20Reading%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Presenting your Solution Module Reading Material.pdf</a></p>' WHERE slug = 'sales-techniques-module-4-presenting-your-solution';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to Building Relationships Module</strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT) that can be used to enrol on more courses.</p>\r\n<p dir="ltr">This module is <strong>one of eight modules</strong> from the Sales Techniques<strong> </strong>course and after completing all eight modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Sales Techniques<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Sales Techniques </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3786/mod_resource/content/1/Building%20Customer%20Relationships%20Module%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Building Customer Relationships Module Preview.pdf</a></p>\n\n<div class="no-overflow"><h4><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr" style="text-align: left;"><strong>After completing this module, you will be able to: </strong></p>\r\n<ul>\r\n<li><strong>Know-how </strong>to qualify sales leads using BANT framework</li>\r\n<li><strong>Understand </strong>potential buyer\'s needs</li>\r\n<li><strong>Know-how </strong>to build trust with potential buyers</li>\r\n<li>Have the <strong>capability</strong> implement consultative selling</li>\r\n<li><strong>Leverage </strong>decision markers, influencers and gatekeepers</li>\r\n<li><strong>Develop</strong> emotional intelligence in sales</li>\r\n<li><strong>Implement </strong>transparency in building relationships and boost</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3802/mod_resource/content/1/Building%20Customer%20Relationships%20Module%20Reading%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Building Customer Relationships Module Reading Material.pdf</a></p>' WHERE slug = 'sales-techniques-module-5-building-relationships';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to Closing the Deal Module</strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT) that can be used to enrol on more courses.</p>\r\n<p dir="ltr">This module is <strong>one of eight modules</strong> from the Sales Techniques<strong> </strong>course and after completing all eight modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Sales Techniques<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Sales Techniques </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3787/mod_resource/content/1/Closing%20the%20Deal%20Module%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Closing the Deal Module Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr" style="text-align: left;"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr" style="text-align: left;"><strong>After completing this module</strong><strong>, you will be able to: </strong></p>\r\n<ul>\r\n<li><strong>Master</strong> sales negotiations</li>\r\n<li><strong>Understand </strong>essential techniques for negotiating a sale</li>\r\n<li><strong>Countering</strong> common buyer negotiation tactics</li>\r\n<li><strong>Know-how</strong> to close sales</li>\r\n<li><strong>Know-how </strong>to transition to customer success</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3803/mod_resource/content/1/Closing%20the%20Deal%20Module%20Reading%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Closing the Deal Module Reading Material.pdf</a></p>' WHERE slug = 'sales-techniques-module-6-closing-the-deal';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to Handling Objections Module</strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT) that can be used to enrol on more courses.</p>\r\n<p dir="ltr">This module is <strong>one of eight modules</strong> from the Sales Techniques<strong> </strong>course and after completing all eight modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Sales Techniques<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Sales Techniques </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3788/mod_resource/content/1/Handling%20Objections%20Module%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Handling Objections Module Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr" style="text-align: left;"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr" style="text-align: left;"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Know-how</strong> to handle sales objections</li>\r\n<li><strong>Overcome</strong> common sales objections</li>\r\n<li><strong>Implement</strong> winning techniques for handling sales objections</li>\r\n<li><strong>Understand </strong>common mistakes when handling sales objections</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3804/mod_resource/content/1/Handling%20Objections%20Module%20Reading%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Handling Objections Module Reading Material.pdf</a></p>' WHERE slug = 'sales-techniques-module-7-handling-objections';
UPDATE lessons SET content = '<div class="no-overflow"><h4 dir="ltr"><strong>Welcome to Prospecting Module</strong></h4>\r\n<p dir="ltr">After completing this module you will receive a <strong>C</strong><strong>ompletion Badge</strong> for social media sharing and <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT) that can be used to enrol on more courses.</p>\r\n<p dir="ltr">This module is <strong>one of eight modules</strong> from the Sales Techniques<strong> </strong>course and after completing all eight modules, you will receive a <strong>Certificate of Completion</strong>.</p>\r\n<p dir="ltr">Once you receive your Sales Techniques<strong> </strong>Certificate of Completion, you can apply to be a <strong>Vow Support</strong> <strong>Sales Techniques </strong><strong>Mentor</strong> for other Learners and earn more <strong>Vow Rewards</strong><strong> Tokens</strong> (VRT).</p></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3789/mod_resource/content/1/Prospecting%20Module%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Prospecting Module Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr" style="text-align: left;"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Understand</strong> the Fundamentals of Prospecting</li>\r\n<li><strong>Apply</strong> Effective Prospecting Techniques</li>\r\n<li><strong>Analyze and Differentiate</strong> from Competitors</li>\r\n<li><strong>Master</strong> Cold and Warm Calling</li>\r\n<li><strong>Leverage</strong> Social Selling for Prospecting</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3805/mod_resource/content/1/Prospecting%20Module%20Reading%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Prospecting Module Reading Material.pdf</a></p>' WHERE slug = 'sales-techniques-module-8-prospecting';
UPDATE lessons SET content = '<div class="no-overflow"><p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 1;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-font-kerning: 18.0pt; mso-fareast-language: EN-ZA;">COURSE SUMMARY </span></strong></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">The <strong>Sales Techniques Course</strong> has provided you with a complete, practical foundation for becoming a confident and effective sales professional. You explored essential skills such as sales fundamentals, sales psychology, leadership and management approaches, presenting solutions, building relationships, handling objections, closing deals, and prospecting for new opportunities.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Throughout the modules, you gained real-world strategies, communication techniques, and persuasive tools that allow you to connect with customers, understand their needs, and guide them toward decisions that create value for both sides. As you prepare for the final assessment, reflect on how these techniques can strengthen your performance in real selling environments.</span></p>\r\n<p><span style="font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-ansi-language: EN-ZA; mso-fareast-language: EN-ZA; mso-bidi-language: AR-SA;">Completing this course demonstrates your readiness to engage customers professionally, manage sales conversations effectively, and contribute meaningfully to sales outcomes within any organization.</span></p></div>' WHERE slug = 'sales-techniques-course-summary-and-final-exam';
UPDATE lessons SET content = '<div class="no-overflow"><p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 1;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-font-kerning: 18.0pt; mso-fareast-language: EN-ZA;">COURSE INTRODUCTION</span></strong></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Welcome to the <strong>Customer Service Excellence Course</strong>, a practical and transformative learning experience designed to build your confidence and capability in delivering exceptional customer experiences. In today’s service-driven world, customers expect empathy, clarity, efficiency, and professionalism every time they interact with a business. This course equips you with the skills, knowledge, and mindset required to meet and exceed those expectations.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Throughout the modules, you will explore the fundamentals of customer service, master communication techniques across multiple channels, understand cultural sensitivity, resolve difficult situations, and learn how to work effectively within customer-facing teams. Whether you are new to customer service or seeking to improve your performance, this course provides the essential tools to help you thrive in any service role.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">By the end of this course, you will be equipped to create positive, memorable, and professional customer experiences that build trust, loyalty, and long-term relationships.</span></p>\r\n<p class="MsoNormal" style="margin-bottom: .0001pt; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;"> </span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 1;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-font-kerning: 18.0pt; mso-fareast-language: EN-ZA;">COURSE PURPOSE</span></strong></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">The purpose of the <strong>Customer Service Excellence Course</strong> is to develop strong service professionals who understand how to communicate with empathy, solve customer problems effectively, and represent their organization with professionalism and respect. This course aims to build a foundation of customer-focused values and provide learners with the skills needed to deliver high-quality service across all customer touchpoints.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">By blending communication skills, cultural awareness, emotional intelligence, and service best practices, this course prepares learners to excel in customer-facing positions and contribute to a positive organizational reputation.</span></p>\r\n<p class="MsoNormal" style="margin-bottom: .0001pt; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;"> </span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 1;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-font-kerning: 18.0pt; mso-fareast-language: EN-ZA;">COURSE OBJECTIVES</span></strong></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">By the end of this course, you will be able to:</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">1. Understand customer service fundamentals: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Explain the principles of excellent service, customer expectations, professionalism, and service ethics.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">2. Demonstrate essential customer service skills: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Apply empathy, active listening, problem-solving, and effective communication to assist customers confidently.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">3. Master customer communication basics: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Use clear, respectful, and professional language when engaging customers in person, over the phone, or online.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">4. Use various communication channels effectively: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Engage customers through email, live chat, phone, social media, and face-to-face interactions with consistent quality.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">5. Manage and collaborate in service teams: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Understand team dynamics, leadership principles, and roles involved in delivering smooth, coordinated service.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">6. Apply cultural sensitivity in customer interactions: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Interact respectfully with customers from diverse cultural backgrounds using inclusive and culturally aware approaches.</span></p>\r\n<p class="MsoNormal" style="mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 3;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">7. Navigate difficult or complex customer situations: </span></strong><span style="font-size: 12.0pt; line-height: 115%; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-ansi-language: EN-ZA; mso-fareast-language: EN-ZA; mso-bidi-language: AR-SA;">Handle angry customers, misunderstandings, and service breakdowns with professionalism, calmness, and confidence.</span></p></div>' WHERE slug = 'customer-service-excellence-course-introduction-purpose-and-objectives';
UPDATE lessons SET content = '<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3977/mod_resource/content/1/Customer%20Service%20Fundamentals%20Module%20Preview.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Customer Service Fundamentals Module Preview.pdf</a></p>\n\n<div class="no-overflow"><h4 dir="ltr" style="text-align: left;"><strong>Learning Outcome</strong></h4>\r\n<p dir="ltr"><strong>After completing this module, you will be able to:</strong></p>\r\n<ul>\r\n<li><strong>Understand </strong>the fundamentals of customer service</li>\r\n<li>Have the <strong>capability</strong> to balance personal and professional customer service</li>\r\n<li><strong>Know-how </strong>to meet and exceed customer expectation</li>\r\n</ul></div>\n\n<p>📎 <a href="https://goalvow.com/upskilling/webservice/pluginfile.php/3985/mod_resource/content/1/Customer%20Service%20Fundamentals%20Module%20Reading%20Material.pdf?forcedownload=1?token=00536e412fb8d765b656ee064bf9ca2c" target="_blank" rel="noopener noreferrer">Customer Service Fundamentals Module Reading Material.pdf</a></p>' WHERE slug = 'customer-service-excellence-module-1-customer-service-fundamentals';
