UPDATE lessons SET content = '<div class="no-overflow"><p class="MsoNormal" style="line-height: 2; text-align: center;"><strong><span style="font-size: 24.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-font-kerning: 18.0pt; mso-fareast-language: EN-ZA;">Time Management &amp; Prioritization - Course Preview</span></strong></p>\r\n<p class="MsoNormal" style="line-height: 2;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Skill Pathway: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Time Management Skills</span></p>\r\n<p class="MsoNormal" style="line-height: 2; text-align: center;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;"><img class="img-fluid" src="https://goalvow.com/upskilling/pluginfile.php/5106/mod_label/intro/8_Time%20Management%20%20Prioritization%20Course%20Preview%20Thumbnail.png" alt="Time Management &amp; Prioritization Course Preview Thumbnail" width="750" height="500"></span></p>\r\n<p class="MsoNormal" style="line-height: 2; text-align: center;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;"><button class="btn btn-primary lambdacep" type="button"><a href="https://goalvow.com/upskilling/course/view.php?id=402">Watch Course Preview</a></button></span></p>\r\n<p class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Take control of your time with proven strategies for prioritizing and achieving your goals.</span></p>\r\n<ul>\r\n