UPDATE lessons SET content = '<div class="no-overflow"><p class="MsoNormal" style="line-height: 2; text-align: center;"><strong><span style="font-size: 24.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-font-kerning: 18.0pt; mso-fareast-language: EN-ZA;">Problem Solving Techniques - Course Preview</span></strong></p>\r\n<p class="MsoNormal" style="line-height: 2;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Skills Pathway: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Problem Solving Skills</span></p>\r\n<p class="MsoNormal" style="line-height: 2; text-align: center;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;"><img class="img-fluid" src="https://goalvow.com/upskilling/pluginfile.php/5107/mod_label/intro/9_Problem%20Solving%20Techniques.png" alt="Problem Solving Techniques" width="752" height="501"></span></p>\r\n<p class="MsoNormal" style="line-height: 2; text-align: center;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;"><button class="btn btn-primary lambdacep" type="button"><a href="https://goalvow.com/upskilling/course/view.php?id=403">Watch Course Preview</a></button></span></p>\r\n<p class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Sharpen your analytical thinking and creativity to solve workplace challenges effectively.</span></p>\r\n<ul>\r\n<li class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">🎯 <strong>Level:</strong> Beginner</span></li>\r\n<li class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">⏱ <strong>Duration:</strong> 4 weeks</span></li>\r\n<li class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">🎓 <strong>Certificate:</strong> GoalVow CPD Certificate of Completion</span></li>\r\n<li style="line-height: 2;">Course Rating: ⭐⭐⭐⭐</li>\r\n<li class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">👥 <strong>Enrolled Learners:</strong> 63+</span></li>\r\n<li style="line-height: 2;">💻 Format: Online, flexible learning</li>\r\n<li style="line-height: 2;">💰 Cost: Free</li>\r\n</ul>\r\n<p class="MsoNormal" style="line-height: 2; text-align: center;"><strong data-start="569" data-end="592"> <button class="btn btn-primary lambdacep" type="button"><a href="https://goalvow.com/upskilling/enrol/index.php?id=292">Enroll for Free</a></button></strong></p>\r\n<p class="MsoNormal" style="line-height: 2;"><strong><span style="font-size: 18.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Course Overview</span></strong></p>\r\n<p class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">The Problem Solving Techniques course is designed to strengthen your ability to analyze challenges, think critically, and apply structured methods to find effective solutions. In today’s fast-paced work environment, strong problem-solving skills are essential for making informed decisions and overcoming obstacles.</span></p>\r\n<p class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">This course introduces practical frameworks and tools that help you break down problems, evaluate options, and implement solutions with confidence. You will learn how to approach issues systematically while also applying creative thinking to develop innovative responses.</span></p>\r\n<p class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">By the end of this course, you will be equipped to handle workplace challenges with clarity, logic, and confidence.</span></p>\r\n<p class="MsoNormal" style="line-height: 2;"><strong><span style="font-size: 18.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Course Purpose</span></strong></p>\r\n<p class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">The purpose of the Problem Solving Techniques course is to empower learners with structured and creative approaches to identifying, analyzing, and resolving problems. This course builds confidence in decision-making and equips learners with transferable problem-solving skills that apply across industries and roles.</span></p>\r\n<p class="MsoNormal" style="line-height: 2;"><strong><span style="font-size: 18.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Learning Objectives</span></stron