UPDATE lessons SET content = '<div class="no-overflow"><p class="MsoNormal" style="line-height: 2; text-align: center;"><strong><span style="font-size: 24.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-font-kerning: 18.0pt; mso-fareast-language: EN-ZA;">Critical Thinking Strategies - Course Preview</span></strong></p>\r\n<p class="MsoNormal" style="line-height: 2;"><strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Skills Pathway: </span></strong><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Critical Thinking Skills</span></p>\r\n<p class="MsoNormal" style="line-height: 2; text-align: center;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;"><img class="img-fluid" src="https://goalvow.com/upskilling/pluginfile.php/5108/mod_label/intro/10_Critical%20Thinking%20Strategies%20Course%20Preview%20Thumbnail.png" alt="Critical Thinking Strategies Course Preview Thumbnail" width="750" height="500"></span></p>\r\n<p class="MsoNormal" style="line-height: 2; text-align: center;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;"><button class="btn btn-primary lambdacep" type="button"><a href="https://goalvow.com/upskilling/course/view.php?id=404">Watch Course Preview</a></button></span></p>\r\n<p class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Strengthen your critical thinking for making smarter decisions &amp; <a href="https://goalvow.com/upskilling/enrol/index.php?id=293">Enroll for Free</a> solving problems.</span></p>\r\n<ul>\r\n<li class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">🎯 <strong>Level:</strong> Beginner</span></li>\r\n<li class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">⏱ <strong>Duration:</strong> 3 weeks</span></li>\r\n<li class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">🎓 <strong>Certificate:</strong> GoalVow CPD Certificate of Completion</span></li>\r\n<li style="line-height: 2;">Course Rating: ⭐⭐⭐⭐</li>\r\n<li class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">👥 <strong>Enrolled Learners:</strong> 46+</span></li>\r\n<li style="line-height: 2;">💻 Format: Online, flexible learning</li>\r\n<li style="line-height: 2;">💰 Cost: Free</li>\r\n</ul>\r\n<p class="MsoNormal" style="line-height: 2; text-align: center;"><strong data-start="569" data-end="592"><button class="btn btn-primary lambdacep" type="button"><a href="https://goalvow.com/upskilling/enrol/index.php?id=293">Enroll for Free</a></button></strong></p>\r\n<p class="MsoNormal" style="line-height: 2;"><strong><span style="font-size: 18.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Course Overview</span></strong></p>\r\n<p class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">The Critical Thinking Strategies course is designed to help you think more clearly, analyze information effectively, and make better decisions in both professional and personal contexts. In a world of constant information and complex challenges, strong critical thinking skills are essential for success.</span></p>\r\n<p class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">This course equips you with practical tools to evaluate arguments, identify bias, assess evidence, and apply logical reasoning. You will learn how to approach problems thoughtfully and avoid common thinking errors that can impact judgment and performance.</span></p>\r\n<p class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">By the end of this course, you will be able to approach decisions with greater clarity, confidence, and analytical strength.</span></p>\r\n<p class="MsoNormal" style="line-height: 2;"><strong><span style="font-size: 18.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Course Purpose</span></strong></p>\r\n<p class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">The purpose of the Critical Thinking Strategies course is to develop learners’ ability to think independently, evaluate information critically, and apply logical reasoning to real-world situations. This course empowers learners to make informed decisions, solve problems effectively, and communicate ideas more clearly.</span></p>\r\n<p class="MsoNormal" style="line-height: 2;"><strong><span style="font-size: 18.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Learning Objectives</span></strong></p>\r\n<p class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">By completing this course, you will be able to:</span></p>\r\n<ul type="disc">\r\n<li class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Understand the foundations of critical thinking</span></li>\r\n<li class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Identify assumptions, biases, and logical fallacies</span></li>\r\n<li class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Evaluate information and sources more effectively</span></li>\r\n<li class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Apply logical reasoning to everyday decisions</span></li>\r\n<li class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Analyze arguments and evidence objectively</span></li>\r\n<li class="MsoNormal" style="line-height: 2;"><span style="font-size: 12.0pt; font-family: \'Times New Roman\',\'serif\'; mso-fareast-font-family: \'Times New Roman\'; mso-fareast-language: EN-ZA;">Strengthen workplace problem-solving abilities</span></li>\r\n<li class="MsoNorm