UPDATE lessons SET content = '<div class="no-overflow"><h5><span style="text-decoration: underline;"><strong>Welcome to Kitchenette Cleaner Course</strong></span></h5>\r\n<p>This course has three phases as part of GoalVow Ecosystem for learners:</p>\r\n<ul>\r\n<li>To <strong>Learn</strong> through <strong>Theory Knowledge Modules</strong></li>\r\n<li>To <strong>Develop</strong> through <strong>Practical Skills Training Modules</strong></li>\r\n<li>To <strong>Inspire</strong> through <strong>Workplace </strong><strong>Experience Modules</strong></li>\r\n</ul>\r\n<p></p>\r\n<h5><strong><span style="text-decoration: underline;">Course Entry Requirements</span></strong></h5>\r\n<p>The minimum entry requirement for this course is:</p>\r\n<ul>\r\n<li>Open Access, meaning anyone can enrol in this course.</li>\r\n</ul>\r\n<p></p>\r\n<h5><span style="text-decoration: underline;"><strong>Course Purpose</strong></span></h5>\r\n<p>The purpose of this course is to prepare the learner to function as a Commercial Kitchenette Cleaner in the workplace.</p>\r\n<p>A Commercial Kitchenette Cleaner, cleans and maintains a commercial kitchenette which is a workplace kitchen.</p>\r\n<p>In addition, learner attributes(including communication) will be integrated in the learning process.</p>\r\n<p>Learners will have to prove competence of the above knowledge, skills, attitudes, responsibilities, and tasks imbedded in the exit level outcomes of this course.</p>\r\n<p></p>\r\n<h5><span style="text-decoration: underline;"><strong>Course Learning Outcome</strong></span></h5>\r\n<p>After completing this course, a learner will be able to:</p>\r\n<ul>\r\n<li>Prepare equipment and tools, chemical and consumables to clean the kitchenette to specifications.</li>\r\n<li>Complete cleaning of the kitchenette to expected standard using cleaning principles and methods.</li>\r\n</ul>\r\n<p></p>\r\n<h5><span style="text-decoration: underline;"><strong>Course Overview</strong></span></h5>\r\n<p>This course is SAQA structured with NQF level 1, Credits 47 in total as shown below:</p>\r\n<p><strong>Knowledge Modules (KM):</strong></p>\r\n<ul>\r\n<li>811201-000-00-00-KM-01, Introduction to the world of work, NQF level 1, Credits 6</li>\r\n<li>811201-000-00-00-KM-04, Commercial cleaning equipment, chemicals and consumables, NQF level 1, Credits 5</li>\r\n<li>811201-000-00-00-KM-05, Basics of cleaning commercial kitchenette, NQF Level 1, Credits 5</li>\r\n</ul>\r\n<p><em>Total number of credits for Knowledge Modules: Credits16</em></p>\r\n<p><strong>Practical Skill Modules (PM):</strong></p>\r\n<ul>\r\n<li><span style="font-size: 1rem; text-align: initial;">811201-000-00-00-PM-01, Complete before shift duties, NQF Level 1, Credits 3</span></li>\r\n<li><span style="font-size: 1rem; text-align: initial;">811201-000-00-00-PM-03, Clean the commercial kitchenette, NQF Level 1, Credits 6</span></li>\r\n<li><span style="font-size: 1rem; text-align: initial;">811201-000-00-00-PM-07, Check and confirm completed tasks, NQF Level 1, Credits 5</span></li>\r\n</ul>\r\n<p><em>Total number of credits for Practical Skill Modules: Credits14</em></p>\r\n<p><strong>Work Experience Modules (WM):</strong></p>\r\n<ul>\r\n<li>811201-000-00-00-WM-01, Procedures for completing before shift duties, NQF Level 1, Credits 4</li>\r\n<li>811201-000-00-00-WM-03, Procedures for cleaning the commercial kitchenette, NQF Level 1, Credits 7</li>\r\n<li>811201-000-00-00-WM-07, Procedures for checking and confirming completed tasks, NQF Level 1, Credits 6</li>\r\n</ul>\r\n<p><em>Total number of credits for Work Experience Modules: Credits 17</em></p>\r\n<p></p>\r\n<p></p></div>' WHERE slug = 'commercial-kitchenette-cleaner-course-preview';
UPDATE lessons SET content = '<div class="no-overflow"><div class="section-heading">\r\n<div class="section-heading">\r\n<div class="section-heading">\r\n<div class="section-heading">\r\n<h4>Topic 1 (KT01) | Employment Contract</h4>\r\n</div>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n</div>\r\n</div>\r\n<p></p></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/338/mod_resource/content/4/1_KM%201_Intro%20to%20World%20of%20Work_Topic%201.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">1_KM 1_Intro to World of Work_Topic 1.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/339/mod_resource/content/4/1_KM%201_Intro%20to%20World%20of%20Work_Topic%201_Summary.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">1_KM 1_Intro to World of Work_Topic 1_Summary.pdf</a></p>\n\n<div class="no-overflow"><div class="section-heading">\r\n<div class="section-heading">\r\n<h4>Topic 2 (KT02) | Organizational Work</h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/806/mod_resource/content/1/1_KM%201_Intro%20to%20World%20of%20Work_Topic%202.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">1_KM 1_Intro to World of Work_Topic 2.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/807/mod_resource/content/2/1_KM%201_Intro%20to%20World%20of%20Work_Topic%202%20Summary.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">1_KM 1_Intro to World of Work_Topic 2 Summary.pdf</a></p>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Topic 3 (KT03) | Employer-Employee Relationships</h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n<p></p></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/808/mod_resource/content/1/Employee%20Employer%20Relationship.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Employee Employer Relationship.pdf</a></p>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Topic 4 (KT04) | Concepts related to the performance of work</h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n<p></p></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/809/mod_resource/content/2/Reading%20Material%20for%20Topic%204.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Reading Material for Topic 4.pdf</a></p>\n\n<div class="no-overflow"><h4>Topic 5 (KT05) | Ethics at Work</h4>\r\n<div class="section-heading">\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/810/mod_resource/content/1/Reading%20Material%20for%20Topic%205.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Reading Material for Topic 5.pdf</a></p>\n\n<div class="no-overflow"><p></p>\r\n<div class="section-heading">\r\n<h4>Topic 6 (KT06) | Current trends influencing work </h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n<p></p></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/811/mod_resource/content/1/Reading%20Material%20for%20Topic%206.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Reading Material for Topic 6.pdf</a></p>\n\n<div class="no-overflow"><p></p>\r\n<div class="section-heading">\r\n<h4>Topic 7 (KT07) | Basic Communication Skills</h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n<p></p></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/812/mod_resource/content/1/Reading%20Material%20for%20Topic%207.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Reading Material for Topic 7.pdf</a></p>\n\n<div class="no-overflow"><p></p>\r\n<div class="section-heading">\r\n<h4>Survey | Rate this Module</h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n<p></p></div>' WHERE slug = 'commercial-kitchenette-cleaner-theory-knowledge-module-1-introduction-to-the-world-of-work';
UPDATE lessons SET content = '<div class="no-overflow"><h5> </h5>\r\n<div class="info-box bg-info-light">\r\n<div class="icon-circle info"><span class="sr-only">info</span></div>\r\n<div class="info-body">\r\n<h5>Knowledge Module 2 (KM-02):</h5>\r\n<p class="m-0">The main focus of knowledge module 2 is to:</p>\r\n<ul>\r\n<li class="m-0">Build an understanding of the commercial cleaning equipment and chemicals.</li>\r\n<li class="m-0">The knowledge acquired will enable the learner to demonstrate an understanding of:\r\n<ul>\r\n<li class="m-0">KM-02-KT01: Types and functions of Cleaning Equipment (20%)</li>\r\n<li class="m-0">KM-02-KT02: Handling and caring for equipment (20%)</li>\r\n<li class="m-0">KM-02-KT03: Types, functions of consumables (20%)</li>\r\n<li class="m-0">KM-02-KT04: Categories of Chemicals (20%)</li>\r\n<li class="m-0">KM-02-KT05: Personal Protective Equipment (PPE) (20%)</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p><em>Time duration to complete this module, is at least 6.25 days</em></p>\r\n<p></p>\r\n</div>\r\n</div>\r\n<p><em>.</em></p></div>\n\n<div class="no-overflow"><h4> </h4>\r\n<div class="section-heading">\r\n<h4>Topic 1 (KT01) | Types and Functions of Cleaning Equipment</h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n<p></p></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/436/mod_resource/content/2/Reading%20Material%20Topic%201.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Reading Material Topic 1.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/441/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Topic 2 (KT02) | Handling and Caring for Equipment</h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n<p></p></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/443/mod_resource/content/2/Reading%20Material%20for%20Topic%202.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Reading Material for Topic 2.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/450/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Topic 3 (KT03) | Types, Functions of Consumables</h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n<p></p></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/444/mod_resource/content/2/Reading%20Material%20for%20Topic%203.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Reading Material for Topic 3.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/449/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Topic 4 (KT04) | Categories of Chemicals</h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n<p></p></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/445/mod_resource/content/2/Reading%20Material%20for%20Topic4.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Reading Material for Topic4.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/448/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Topic 5 (KT05) | Personal Protective Equipment (PPE)</h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n<p></p></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/446/mod_resource/content/2/Reading%20Material%20for%20Topic%205.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Reading Material for Topic 5.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/447/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>' WHERE slug = 'commercial-kitchenette-cleaner-theory-knowledge-module-2-commercial-cleaning-equipment-chemicals-and-consumable';
UPDATE lessons SET content = '<div class="no-overflow"><h5> </h5>\r\n<div class="info-box bg-info-light">\r\n<div class="info-body">\r\n<h5> </h5>\r\n<h5>Knowledge Module 3 (KM-03):</h5>\r\n<p class="m-0">The main focus of knowledge module 3 is to:</p>\r\n<ul>\r\n<li class="m-0">Build an understanding of the basics of cleaning a commercial kitchenette.</li>\r\n<li class="m-0">The knowledge acquired will enable the learner to demonstrate an understanding of:\r\n<ul>\r\n<li class="m-0">KM-03-KT01: Types and functions of kitchenette components (25%)</li>\r\n<li class="m-0">KM-03-KT02: Types and functions of kitchenette equipment (25%)</li>\r\n<li class="m-0">KM-03-KT03: Cutlery and crockery (25%)</li>\r\n<li class="m-0">KM-03-KT04: Cleaning procedures in the Kitchenette (25%)</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p><em>Time duration to complete this module, is at least 6.25 days</em></p>\r\n<p></p>\r\n</div>\r\n</div>\r\n<p></p></div>\n\n<div class="no-overflow"><h4> </h4>\r\n<div class="section-heading">\r\n<h4>Topic 1 (KT01) | Types and functions of kitchenette components</h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n<p></p></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/477/mod_resource/content/2/Reading%20Material%20for%20Topic%201.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Reading Material for Topic 1.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/475/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<div class="no-overflow"><h4> </h4>\r\n<div class="section-heading">\r\n<h4>Topic 2 (KT02) | Types and functions of kitchenette equipment</h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n<p></p></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/480/mod_resource/content/2/KM%203%20Topic%202.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">KM 3 Topic 2.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/482/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<div class="no-overflow"><h4> </h4>\r\n<div class="section-heading">\r\n<h4>Topic 3 (KT03) | Cutlery and crockery</h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n<p></p></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/479/mod_resource/content/2/KM3%20topic%203.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">KM3 topic 3.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/483/mod_resource/content/2/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<div class="no-overflow"><h4> </h4>\r\n<div class="section-heading">\r\n<h4>Topic 4 (KT04) | Cleaning procedures in the Kitchenette</h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n<p></p></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/478/mod_resource/content/2/KM3%20topic%204.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">KM3 topic 4.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/481/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>' WHERE slug = 'commercial-kitchenette-cleaner-theory-knowledge-module-3-basics-of-cleaning-commercial-kitchenette';
