UPDATE lessons SET content = '<div class="no-overflow"><div class="info-box bg-info-light">\r\n<div class="info-body">\r\n<h5>Practical Skills Module 1 (PM-01):</h5>\r\n<p class="m-0">The main focus of practical skills module 1 is to:</p>\r\n<ul>\r\n<li class="m-0">Provide the learner an opportunity to complete tasks before shift duties within a simulated or working environment</li>\r\n<li class="m-0">Learners will also be practicing skills related to:\r\n<ul>\r\n<li class="m-0">PM-01-PS01 Wear PPE</li>\r\n<li class="m-0">PM-01-PS02 Check tools and equipment for functionality</li>\r\n<li class="m-0">PM-01-PS03 Collect consumables and chemicals </li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p><em>Time duration to complete this module, is at least 7.5 days.</em></p>\r\n</div>\r\n</div></div>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Skill Topic 1 (PS01) | Wearing Kitchenette PPE</h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n<p></p></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/512/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/505/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Skill Topic 2 (PS02) | Check Kitchenette tools and equipment for functionality</h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n<p></p></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/513/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>