UPDATE lessons SET content = '<div class="no-overflow"><div class="info-box bg-info-light">\r\n<div class="info-body">\r\n<h5>Practical Skills Module 3 (PM-03):</h5>\r\n<p class="m-0">The main focus of practical skills module 3 is to:</p>\r\n<ul>\r\n<li class="m-0">Provide the learner an opportunity to check and confirm completed tasks within a simulated or working environment</li>\r\n<li class="m-0">Learners will also be practicing skills related to:\r\n<ul>\r\n<li class="m-0">PM-03-PS01 Clean and care for equipment and consumables</li>\r\n<li class="m-0">PM-03-PS02 Replenish and clean consumables/ chemicals within a commercial environment</li>\r\n<li class="m-0">PM-03-PS03 Remove PPE</li>\r\n<li class="m-0">PM-03-PS04 Report defects and maintenance requirement</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p><em>Time duration to complete this module, is at least 6.25 days..</em></p>\r\n</div>\r\n</div></div>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Skill Topic 1 (PS01) | Clean and care for equipment and consumables</h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/709/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/656/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/657/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/637/