UPDATE lessons SET content = '<div class="no-overflow"><div class="info-box bg-info-light">\r\n<div class="info-body">\r\n<h5>Work Experience Module 1 (WM-01):</h5>\r\n<p class="m-0">The main focus of Work Experience Module 1 is to:</p>\r\n<ul>\r\n<li class="m-0">Provide the learner an opportunity to gain real work exposure to complete before shift duties.</li>\r\n<li class="m-0">The learner will be required to successfully complete each work experience under supervision and independently at least five times within a period of five weeks.</li>\r\n<li class="m-0">Learners will be required to:\r\n<ul>\r\n<li class="m-0">WM-01-WE01 Wear PPE</li>\r\n<li class="m-0">WM-01-WE02 Check tools and equipment for functionality</li>\r\n<li class="m-0">WM-01-WE03 Collect consumables and chemicals</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p><em>Time duration to complete this module, is at least 5 days.</em></p>\r\n</div>\r\n</div></div>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Company Policy and Procedures</h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/650/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/710/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/711/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/712/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/713/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<div class="no-overflow"><div class="section-heading">\n<h4>Work Experience Topic 1 (WE01) | Wear PPE</h4>\n<div class="divider line-01"> </div>\n</div></div>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Work Experience Topic 2 (WE02) | Check tools and equipment for functionality</h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Work Experience Topic 3 (WE03) | Collect consumables and chemicals</h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>' WHERE slug = 'commercial-kitchenette-cleaner-workplace-experience-module-1-procedures-for-completing-before-shift-duties';
UPDATE lessons SET content = '<div class="no-overflow"><div class="info-box bg-info-light">\r\n<div class="info-body">\r\n<h5>Work Experience Module 2 (WM-02):</h5>\r\n<p class="m-0">The main focus of Work Experience Module 2 is to:</p>\r\n<ul>\r\n<li class="m-0">Provide the learner an opportunity to gain real work exposure cleaning the commercial kitchenette.</li>\r\n<li class="m-0">The learner will be required to successfully complete each work experience under supervision and independently at least five times within a period of five weeks.</li>\r\n<li class="m-0">Learners will be required to:\r\n<ul>\r\n<li class="m-0">WM-02-WE01 Clean kitchen floors</li>\r\n<li class="m-0">WM-02-WE02 Clean cupboards</li>\r\n<li class="m-0">WM-02-WE03 Clean kitchen appliances</li>\r\n<li>WM-02-WE04 Clean kitchenware</li>\r\n<li>WM-02-WE05 Refill and replenish kitchenette dispenser</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p><em>Time duration to complete this module, is at least 8.75 days.</em></p>\r\n</div>\r\n</div></div>\n\n<div class="no-overflow"><div class="section-heading">\n<h4>Company Policy and Procedures</h4>\n<div class="divider line-01"> </div>\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/718/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/765/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/766/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<p>📎 <a href="http