UPDATE lessons SET content = '<div class="no-overflow"><div class="info-box bg-info-light">\r\n<div class="info-body">\r\n<h5>Work Experience Module 3 (WM-03):</h5>\r\n<p class="m-0">The main focus of Work Experience Module 3 is to:</p>\r\n<ul>\r\n<li class="m-0">Provide the learner an opportunity to gain real work exposure checking and confirming completed tasks.</li>\r\n<li class="m-0">The learner will be required to successfully complete each work experience under supervision and independently at least five times within a period of five weeks.</li>\r\n<li class="m-0">Learners will be required to:\r\n<ul>\r\n<li class="m-0">WM-03-WE01 Clean and care for equipment and consumables</li>\r\n<li class="m-0">WM-03-WE02 Replenish and clean consumables/ chemicals within a commercial environment</li>\r\n<li class="m-0">WM-03-WE03 Remove PPE</li>\r\n<li>WM-03-WE04 Report defects and maintenance requirement</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p><em>Time duration to complete this module, is at least 7.5 days.</em></p>\r\n</div>\r\n</div></div>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Company Policy and Procedures</h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/771/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/796/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/797/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/798/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/799/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/800/mod_resource/content/1/DRAFT%20Reading%20Material.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">DRAFT Reading Material.pdf</a></p>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Work Experience Topic 1 (WE01) | Clean and care for equipment and consumables</h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Work Experience Topic 2 (WE02) | Replenish and clean consumables/ chemicals within a commercial environment</h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Work Experience Topic 3 (WE03) | Remove PPE</h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Work Experience Topic 4 (WE04) | Report defects and maintenance requirement</h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>' WHERE slug = 'commercial-kitchenette-cleaner-workplace-experience-module-3-procedures-for-checking-and-confirming-completed-t';
UPDATE lessons SET content = '<div class="no-overflow"><h5><span style="text-decoration: underline;"><strong>Purpose</strong></span></h5>\r\n<p>The purpose of this course is to prepare the learner to function as a Commercial Kitchenette Cleaner in the workplace.</p>\r\n<p>A Commercial Kitchenette Cleaner, cleans and maintains a commercial kitchenette which is a workplace kitchen.</p>\r\n<p>In addition, learner attributes(including communication) will be integrated in the learning process.</p>\r\n<p>Learners will have to prove competence of the above knowledge, skills, attitudes, responsibilities, and tasks imbedded in the exit level outcomes of this course.</p>\r\n<h5><span style="text-decoration: underline;"><strong>Learning Outcome</strong></span></h5>\r\n<p>After completing this course, a learner will be able to:</p>\r\n<ul>\r\n<li>Prepare equipment and tools, chemical and consumables to clean the kitchenette to specifications.</li>\r\n<li>Complete cleaning of the kitchenette to expected standard using cleaning principles and methods.</li>\r\n</ul></div>' WHERE slug = 'commercial-ablution-cleaner-purpose-and-learning-outcome';
UPDATE lessons SET content = '<div class="no-overflow"><h5><span style="text-decoration: underline;">Course Entry Requirements</span></h5>\r\n<p>The minimum entry requirement for this course is:</p>\r\n<ul>\r\n<li>Open Access, meaning anyone can enrol in this course.</li>\r\n</ul></div>' WHERE slug = 'commercial-ablution-cleaner-entry-requirements';
