UPDATE lessons SET content = '<div class="no-overflow"><p></p>\r\n<div class="shadow info-box bg-info-light">\r\n<div class="icon-circle info"><span class="sr-only">info</span></div>\r\n<div class="info-body">\r\n<h5>Knowledge Module 1 (KM-01):</h5>\r\n<p class="m-0">The main focus of knowledge module 1 is to:</p>\r\n<ul>\r\n<li class="m-0">Build an understanding of the world of work.</li>\r\n<li class="m-0">Enable the learner to demonstrate an understanding of various work related requirements like:\r\n<ul>\r\n<li class="m-0">KM-01-KT01: Employment Contract (20%)</li>\r\n<li class="m-0">KM-01-KT02: Organizational work (20%)</li>\r\n<li class="m-0">KM-01-KT03: Employer-Employee relationships (15%)</li>\r\n<li class="m-0">KM-01-KT04: Concepts related to the performance of work (15%)</li>\r\n<li class="m-0">KM-01-KT05: Ethics at work (10%)</li>\r\n<li class="m-0">KM-01-KT06: Current trends influencing work (10%)</li>\r\n<li class="m-0">KM-01-KT07: Basic Communication Skills (10%)</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p><em>Time duration to complete this module, is at least 7 days.</em></p>\r\n</div>\r\n</div></div>\n\n<div class="no-overflow"><div class="section-heading">\r\n<div class="section-heading">\r\n<div class="section-heading">\r\n<div class="section-heading">\r\n<h4>Topic 1 (KT01) | Employment Contract</h4>\r\n</div>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n</div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1095/mod_resource/content/1/1_KM%201_Intro%20to%20World%20of%20Work_Topic%201.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">1_KM 1_Intro to World of Work_Topic 1.pdf</a></p>\n\n<div class="no-overflow"><div class="section-heading">\r\n<div class="section-heading">\r\n<h4>Topic 2 (KT02) | Organizational Work</h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1116/mod_resource/content/1/1_KM%201_Intro%20to%20World%20of%20Work_Topic%202.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">1_KM 1_Intro to World of Work_Topic 2.pdf</a></p>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Topic 3 (KT03) | Employer-Employee Relationships</h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1138/mod_resource/content/1/Employee%20Employer%20Relationship.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Employee Employer Relationship.pdf</a></p>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Topic 4 (KT04) | Concepts related to the performance of work</h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1164/mod_resource/content/1/Reading%20Material%20for%20Topic%204.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Reading Material for Topic 4.pdf</a></p>\n\n<div class="no-overflow"><h4>Topic 5 (KT05) | Ethics at Work</h4>\r\n<div class="section-heading">\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1191/mod_resource/content/1/Reading%20Material%20for%20Topic%205.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Reading Material for Topic 5.pdf</a></p>\n\n<div class="no-overflow"><p></p>\r\n<div class="section-heading">\r\n<h4>Topic 6 (KT06) | Current trends influencing work </h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1220/mod_resource/content/1/Reading%20Material%20for%20Topic%206.pdf?forcedownload=1?token=6b5f00ce3889922a6