UPDATE lessons SET content = '<div class="no-overflow"><div class="info-box bg-info-light">\r\n<div class="info-body">\r\n<h5>Knowledge Module 3 (KM-03):</h5>\r\n<p class="m-0">The main focus of knowledge module 3 is to:</p>\r\n<ul>\r\n<li class="m-0">Build an understanding of the basics of Cleaning above the floor surfaces.</li>\r\n<li class="m-0">The knowledge acquired will enable the learner to demonstrate an understanding of:\r\n<ul>\r\n<li class="m-0">KM-08-KT01: Assess the area to be cleaned and plan the cleaning activities.(25%)</li>\r\n<li class="m-0">KM-08-KT02: Clean furniture, partitions and fittings( 50%)</li>\r\n<li class="m-0">KM-087-KT03: Check the quality of cleaning above the floor surfaces.(25%)</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p><em>Time duration to complete this module, is at least 5 days</em></p>\r\n<p></p>\r\n</div>\r\n</div></div>\n\n<div class="no-overflow"><h4> </h4>\r\n<div class="section-heading">\r\n<h4>Topic 1 (KT01) | Clean above the floor surfaces</h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1317/mod_resource/content/1/1_KM%201_Intro%20to%20World%20of%20Work_Topic%201.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">1_KM 1_Intro to World of Work_Topic 1.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1322/mod_resource/content/1/1_KM%201_Intro%20to%20World%20of%20Work_Topic%201.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">1_KM 1_Intro to World of Work_Topic 1.pdf</a></p>\n\n<div class="no-overflow"><h4> </h4>\r\n<div class="section-heading">\r\n<h4>Topic 2 (KT02) | Clean furniture, partitions and fittings</h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1325/mod_resource/content/1/1_KM%201_Intro%20to%20World%20of%20Work_Topic%201.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">1_KM 1_Intro to World of Work_Topic 1.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1329/mod_resource/content/1/1_KM%201_Intro%20to%20World%20of%20Work_Topic%201.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">1_KM 1_Intro to World of Work_Topic 1.pdf</a></p>\n\n<div class="no-overflow"><h4> </h4>\r\n<div class="section-heading">\r\n<h4>Topic 3 (KT03) | Check the quality of cleaning above the floor surfaces</h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1332/mod_resource/content/1/1_KM%201_Intro%20to%20World%20of%20Work_Topic%201.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">1_KM 1_Intro to World of Work_Topic 1.pdf</a></p>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1336/mod_resource/content/1/1_KM%201_Intro%20to%20World%20of%20Work_Topic%201.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">1_KM 1_Intro to World of Work_Topic 1.pdf</a></p>' WHERE slug = 'commercial-above-the-floor-surface-cleaner-knowledge-module-3-introduction-to-above-the-floor-surface';
UPDATE lessons SET content = '<div class="no-overflow"><h5><span style="text-decoration: underline;"><strong>Purpose</strong></span></h5>\r\n<p>The purpose of this course is to prepare the learner to function as a Commercial Kitchenette Cleaner in the workplace.</p>\r\n<p>A Commercial Kitchenette Cleaner, cleans and maintains a commercial kitchenette which is a workplace kitchen.</p>\r\n<p>In addition, learner attributes(including communication) will be integrated in the learning process.</p>\r\n<p>Learners will have to prove competence of the above knowledge, skills, attitudes, responsibilities, and tasks imbedded in the exit level outcomes of this course.</p>\r\n<h5><span style="text-decoration: underline;"><strong>Learning Outcome</strong></span></h5>\r\n<p>After completing this course, a learner will be able to:</p>\r\n<ul>\r\n<li>Prepare equipment and tools, chemical and consumables to clean the kitchenette to specifications.</li>\r\n<li>Complete cleaning of the kitchenette to expected standard using cleaning principles and methods.</li>\r\n</ul></div>' WHERE slug = 'commercial-floor-cleaner-purpose-and-learning-outcome';
UPDATE lessons SET content = '<div class="no-overflow"><h5><span style="text-decoration: underline;">Course Entry Requirements</span></h5>\r\n<p>The minimum entry requirement for this course is:</p>\r\n<ul>\r\n<li>Open Access, meaning anyone can enrol in this course.</li>\r\n</ul></div>' WHERE slug = 'commercial-floor-cleaner-entry-requirements';
UPDATE lessons SET content = '<div class="no-overflow"><p></p>\r\n<div class="shadow info-box bg-info-light">\r\n<div class="icon-circle info"><span class="sr-only">info</span></div>\r\n<div class="info-body">\r\n<h5>Knowledge Module 1 (KM-01):</h5>\r\n<p class="m-0">The main focus of knowledge module 1 is to:</p>\r\n<ul>\r\n<li class="m-0">Build an understanding of the world of work.</li>\r\n<li class="m-0">Enable the learner to demonstrate an understanding of various work related requirements like:\r\n<ul>\r\n<li class="m-0">KM-01-KT01: Employment Contract (20%)</li>\r\n<li class="m-0">KM-01-KT02: Organizational work (20%)</li>\r\n<li class="m-0">KM-01-KT03: Employer-Employee relationships (15%)</li>\r\n<li class="m-0">KM-01-KT04: Concepts related to the performance of work (15%)</li>\r\n<li class="m-0">KM-01-KT05: Ethics at work (10%)</li>\r\n<li class="m-0">KM-01-KT06: Current trends influencing work (10%)</li>\r\n<li class="m-0">KM-01-KT07: Basic Communication Skills (10%)</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p><em>Time duration to complete this module, is at least 7 days.</em></p>\r\n</div>\r\n</div></div>\n\n<div class="no-overflow"><div class="section-heading">\r\n<div class="section-heading">\r\n<div class="section-heading">\r\n<div class="section-heading">\r\n<h4>Topic 1 (KT01) | Employment Contract</h4>\r\n</div>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n</div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1094/mod_resource/content/1/1_KM%201_Intro%20to%20World%20of%20Work_Topic%201.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">1_KM 1_Intro to World of Work_Topic 1.pdf</a></p>\n\n<div class="no-overflow"><div class="section-heading">\r\n<div class="section-heading">\r\n<h4>Topic 2 (KT02) | Organizational Work</h4>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1115/mod_resource/content/1/1_KM%201_Intro%20to%20World%20of%20Work_Topic%202.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">1_KM 1_Intro to World of Work_Topic 2.pdf</a></p>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Topic 3 (KT03) | Employer-Employee Relationships</h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1139/mod_resource/content/1/Employee%20Employer%20Relationship.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Employee Employer Relationship.pdf</a></p>\n\n<div class="no-overflow"><div class="section-heading">\r\n<h4>Topic 4 (KT04) | Concepts related to the performance of work</h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1163/mod_resource/content/1/Reading%20Material%20for%20Topic%204.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Reading Material for Topic 4.pdf</a></p>\n\n<div class="no-overflow"><h4>Topic 5 (KT05) | Ethics at Work</h4>\r\n<div class="section-heading">\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1190/mod_resource/content/1/Reading%20Material%20for%20Topic%205.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Reading Material for Topic 5.pdf</a></p>\n\n<div class="no-overflow"><p></p>\r\n<div class="section-heading">\r\n<h4>Topic 6 (KT06) | Current trends influencing work </h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1219/mod_resource/content/1/Reading%20Material%20for%20Topic%206.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Reading Material for Topic 6.pdf</a></p>\n\n<div class="no-overflow"><p></p>\r\n<div class="section-heading">\r\n<h4>Topic 7 (KT07) | Basic Communication Skills</h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>\n\n<p>📎 <a href="https://goalvow.com/skills-training/webservice/pluginfile.php/1247/mod_resource/content/1/Reading%20Material%20for%20Topic%207.pdf?forcedownload=1?token=6b5f00ce3889922a6eb1df2b4a8c45aa" target="_blank" rel="noopener noreferrer">Reading Material for Topic 7.pdf</a></p>\n\n<div class="no-overflow"><p></p>\r\n<div class="section-heading">\r\n<h4>Survey | Rate this Module</h4>\r\n<div class="divider line-01"> </div>\r\n</div></div>' WHERE slug = 'commercial-floor-cleaner-knowledge-module-1-introduction-to-the-world-of-work';
