UPDATE lessons SET content = '<div class="no-overflow"><p></p>\r\n<div class="section-heading">\r\n<h2>Work Experience Module Section</h2>\r\n<div class="divider line-01"> </div>\r\n</div>\r\n<p></p></div>' WHERE slug = 'unitary-air-conditioning-installer-practical-skills-module-13-maintain-an-air-conditioning-system';

